-- Poems batch 308
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('40b3e402-f8dd-4730-8efa-31b0dd2860f8','對月','王令','宋','宋诗','song-poetry','','[]','柳梢地面絕微風，一片寒光萬里同。',64,'全唐诗/poet.song.39000.json','["柳梢地面絕微風，一片寒光萬里同。", "冰骨直疑潜裏換，塵心都覺坐來空。", "蚌胎有露珠成顆，蟾窟無雲玉作宫。", "莫怪幽人吟到曉，不知清興自無窮。"]'),
('364c48fe-5af8-4859-b935-a57e42640632','夜月','王令','宋','宋诗','song-poetry','','[]','可嗟落日志悠然，便有羣星出見天。',32,'全唐诗/poet.song.39000.json','["可嗟落日志悠然，便有羣星出見天。", "夜月自明人自愛，不妨人亦閉門眠。"]'),
('f0dea1d2-a216-423f-bcd1-95b91d26f0d3','孤雲','王令','宋','宋诗','song-poetry','','[]','一片孤雲逐吹飛，東西終日竟何依。',32,'全唐诗/poet.song.39000.json','["一片孤雲逐吹飛，東西終日竟何依。", "旁人莫道能爲雨，惟恨青山未得歸。"]'),
('99347f31-3a91-4609-b371-738720de29e2','晚晴寄滿子權','王令','宋','宋诗','song-poetry','','[]','常恐朝陰至夕曛，好風吹去信多勤。',64,'全唐诗/poet.song.39000.json','["常恐朝陰至夕曛，好風吹去信多勤。", "得逢白日忽開眼，可惜青天尚有雲。", "安得植梯懸碧落，共操長帚掃妖氛。", "恨無玉纊充天耳，垤鸛鳴鳩願不聞。"]'),
('32f174ec-e39b-47b8-94db-5eea9eb3aec3','晚虹','王令','宋','宋诗','song-poetry','','[]','晚虹随雨過山巔，誰插青雲倒掛懸。',64,'全唐诗/poet.song.39000.json','["晚虹随雨過山巔，誰插青雲倒掛懸。", "可惜兩垂空到海，不令一直徑冲天。", "不堪暮靄難相蔽，嘗到斜陽亦可憐。", "好使渇來能劇飲，且教溪壑减清淵。"]'),
('5bbd6637-0b55-49c6-a8ca-5ba91672333f','春城望湖','王令','宋','宋诗','song-poetry','','[]','春城綠野欝相望，閑客閑來興自長。',64,'全唐诗/poet.song.39000.json','["春城綠野欝相望，閑客閑來興自長。", "不見暮雲成宿雨，空看芳草到斜陽。", "花生惡土終成笑，蘭不逢人自信香。", "雖有塵纓無處濯，坐觀漁者滿滄浪。"]'),
('665f52d8-961f-4353-b178-91777459f52e','樓上望湖','王令','宋','宋诗','song-poetry','','[]','樓上人腸渴欲枯，樓前終日望平湖。',32,'全唐诗/poet.song.39000.json','["樓上人腸渴欲枯，樓前終日望平湖。", "無舟得往滄浪去，爲問漁人得意無。"]'),
('1d0b5299-c1bd-4dbb-a737-f872ff5eefd2','江上','王令','宋','宋诗','song-poetry','','[]','羃羃江城沒遠烟，暮雲歸族忽相連。',64,'全唐诗/poet.song.39000.json','["羃羃江城沒遠烟，暮雲歸族忽相連。", "春江流水出天外，晚渡歸舟下日邊。", "杏蕚春深翻淺纈，柳花風遠曳晴綿。", "無錢買得江頭樹，輸與漁人繫釣船。"]'),
('73b7b0f8-cf67-4e30-8a59-133dceba10e2','野外','王令','宋','宋诗','song-poetry','','[]','綠野愛平寛，偶來或永嘆。',48,'全唐诗/poet.song.39000.json','["綠野愛平寛，偶來或永嘆。", "村兒駭車馬，野犬吠衣冠。", "亂草無閑地，斜陽有去鞍。", "良田半蹊徑，始信直行難。"]'),
('914e46ec-4d0d-4d50-9aa8-3cded701d8c7','暮歸馬上口占','王令','宋','宋诗','song-poetry','','[]','林密村村暗，寒鴉處處啼。',48,'全唐诗/poet.song.39000.json','["林密村村暗，寒鴉處處啼。", "水光連野白，雪意逐雲低。", "風勁童呵指，泥深馬失蹄。", "客心兼暮色，歸去兩凄凄。"]'),
('61efa49c-edd2-4ef2-859a-842ae398b9e2','小酌','王令','宋','宋诗','song-poetry','','[]','平生從事漫徒勞，時以休閑近酒醪。',64,'全唐诗/poet.song.39000.json','["平生從事漫徒勞，時以休閑近酒醪。", "東海可從誰自重，南山如與客爭髙。", "老将日月來雙鬂，生委乾坤寄一毛。", "更展韋編探萬絕，懶從人世問滔滔。"]'),
('e40fa6bb-0e7f-4f55-ad06-6f9b141557d6','餘杭倦遊','王令','宋','宋诗','song-poetry','','[]','醉倚秋風笑自攻，偶來還去竟何蹤。',64,'全唐诗/poet.song.39000.json','["醉倚秋風笑自攻，偶來還去竟何蹤。", "已夫鳯鳥今不至，行矣鱣鯨非所容。", "且把心胸同伏虎，誰知頭角是真龍。", "歸乎伊畝殊難得，死爾西山尚有從。"]'),
('5e46bce6-a740-48a6-b92d-b75d2f7c0b3b','送和秘校','王令','宋','宋诗','song-poetry','','[]','野客從誰忽解顔，樂聞髙論厭樊間。',64,'全唐诗/poet.song.39000.json','["野客從誰忽解顔，樂聞髙論厭樊間。", "致身富貴時寧少，仕道功名古亦艱。", "好說青山從我老，當分白日與君閑。", "扁舟聞說明朝别，何日音書可到山。"]'),
('183b06fc-d55b-4d8a-8d8c-64a2cf709c24','送聱隅黄先生','王令','宋','宋诗','song-poetry','','[]','黄風吹土截天横，瘦馬着鞭驅不行。',64,'全唐诗/poet.song.39000.json','["黄風吹土截天横，瘦馬着鞭驅不行。", "尚說苦心酬直道，誰知白髪爲蒼生。", "平時夷虜恬忠藎，常日公卿足仰成。", "雖有英雄無用處，却令老去買牛耕。"]'),
('3a1fbcb3-7c58-4cc1-9813-0db4aae32605','送周器之歸潤再索','王令','宋','宋诗','song-poetry','','[]','何須别子始沾衣，久有江南去夢飛。',32,'全唐诗/poet.song.39000.json','["何須别子始沾衣，久有江南去夢飛。", "爲語青山幸相望，壮夫終不白頭歸。"]'),
('ccefc8bb-a96a-4348-a964-428614355792','送庭老罷尉金壇','王令','宋','宋诗','song-poetry','','[]','心無畦畛見天真，落落男兒七尺身。',64,'全唐诗/poet.song.39000.json','["心無畦畛見天真，落落男兒七尺身。", "莫嘆一官淹聖代，聊將三釡慰慈親。", "月明空照居民侣，風急随飄去馬塵。", "寂寞西軒人別後，海棠花好爲誰春。"]'),
('d7e325bb-7b15-4708-bd4e-612a1cb0b9bb','送李廷尉濠梁','王令','宋','宋诗','song-poetry','','[]','直道無適可，小官真漫論。',48,'全唐诗/poet.song.39000.json','["直道無適可，小官真漫論。", "夫君自行義，而我更何言。", "獨柱難爲力，横流不奈渾。", "此心持送子，飲泪當前樽。"]'),
('64c86906-b31c-4229-8402-d231f2f4437e','送束徽之入京','王令','宋','宋诗','song-poetry','','[]','出處身之道，窮通命有時。',48,'全唐诗/poet.song.39000.json','["出處身之道，窮通命有時。", "九門無直謁，千里去何爲。", "南畝春耕近，西風去馬羸。", "白雲况多恨，歸計莫令遲。"]'),
('168a45ea-ef55-4e85-a398-01550e593a5f','別陳藥院','王令','宋','宋诗','song-poetry','','[]','客居平日有誰親，一别三年百病身。',32,'全唐诗/poet.song.39000.json','["客居平日有誰親，一别三年百病身。", "爲道難言輕感慨，羡君無病更醫人。"]'),
('a4b2353c-5482-4b20-b5ce-5329e977e055','寄介甫','王令','宋','宋诗','song-poetry','','[]','天門廉陛鬰巍巍，勢利寧無淡泊譏。',64,'全唐诗/poet.song.39000.json','["天門廉陛鬰巍巍，勢利寧無淡泊譏。", "誰與跖徒爭有道，好思吾黨共言歸。", "古人踽踽今何取，天下滔滔昔已非。", "終見乘桴去滄海，好留餘地許相依。"]'),
('43bd8639-33e9-4ace-b6d3-3e1c840ee63d','奉寄黄任道','王令','宋','宋诗','song-poetry','','[]','蒿萊日日沒幽居，時得新詩亦自娛。',64,'全唐诗/poet.song.39000.json','["蒿萊日日沒幽居，時得新詩亦自娛。", "爲有遠懷希稷卨，或時飛夢見唐虞。", "久諳末俗難謀道，益厭庸兒妄問儒。", "絕筆斷絃無意寄，笑將遠目睨清虛。"]'),
('8f0538ea-631b-4c63-858f-4d5b39534fdd','奉寄朱昌叔','王令','宋','宋诗','song-poetry','','[]','勞勞忽忽欲誰從，要有田園去自終。',64,'全唐诗/poet.song.39000.json','["勞勞忽忽欲誰從，要有田園去自終。", "衰俗未知誰得失，古風期與子窮通。", "三年客興看秋葉，萬里歸心寄斷蓬。", "知有世嘲無意解，自慚疏懶甚揚雄。"]'),
('8f3b07ae-b2ab-4f45-934b-d0f27bf17525','到潤望竹林寺憶朱昌叔','王令','宋','宋诗','song-poetry','','[]','常與幽人過竹林，重來無地豁煩襟。',64,'全唐诗/poet.song.39000.json','["常與幽人過竹林，重來無地豁煩襟。", "青山欲去誰堪語，薄俗相期不到心。", "何計江湖終隐釣，去随魚鳥共飛沉。", "塵埃聞說難爲客，早晚歸來憶舊吟。"]'),
('c1aa6ba4-ce71-4154-bebb-66c40e4df736','奉寄伯兄泰伯','王令','宋','宋诗','song-poetry','','[]','心迹牽覊逐勢分，一生襟抱向誰論。',64,'全唐诗/poet.song.39000.json','["心迹牽覊逐勢分，一生襟抱向誰論。", "十年漂泊迷南北，千里憂思厭夢魂。", "書託遠懷期日月，眼和衰淚望乾坤。", "何時得就歸來賦，老守桑麻聚一門。"]'),
('30064179-cf23-4f5e-9d54-f73983716a1a','奉寄崔伯易','王令','宋','宋诗','song-poetry','','[]','功業嘗聞亦有時，可能天命出依違。',64,'全唐诗/poet.song.39000.json','["功業嘗聞亦有時，可能天命出依違。", "終看世態真何道，不得吾心自合歸。", "廊廟得逢應有義，草茅雖老尚知非。", "秋來客况無他異，時向西風誦式微。"]'),
('94aee9b1-f2cf-42d4-80a3-336f6d875554','寄滿子權二首  其一','王令','宋','宋诗','song-poetry','','[]','窗前午枕夢忘還，門外清風晝掩關。',64,'全唐诗/poet.song.39000.json','["窗前午枕夢忘還，門外清風晝掩關。", "天下誰當千古後，床頭自笑六經閑。", "能將道繫窮通裏，安用身居進退間。", "自愧公心猶有蔽，清時無日不思山。"]'),
('bb2d2132-5c61-4ac0-a29d-e9c76732fe58','寄滿子權二首  其二','王令','宋','宋诗','song-poetry','','[]','終年謀食亦何得，浪取窮愁只自侵。',64,'全唐诗/poet.song.39000.json','["終年謀食亦何得，浪取窮愁只自侵。", "餓死有時非正命，勞生幾不愧常心。", "百年此去塵埃在，萬古從來意思深。", "莫說山林是輕往，窮來無計得山林。"]'),
('277f8557-ae41-4f14-bb60-5b4f8323b9c9','寄李君厚','王令','宋','宋诗','song-poetry','','[]','一笑東風去十年，重來稚子已差肩。',64,'全唐诗/poet.song.39000.json','["一笑東風去十年，重來稚子已差肩。", "脱衣呼客家聲舊，把酒論心士氣全。", "病驥遠思牽直道，老鷹秋夢入青天。", "自言出處身無累，一把窮通寄自然。"]'),
('7a1c0359-b195-4604-a42a-876f9df5990e','寄滿粹翁','王令','宋','宋诗','song-poetry','','[]','滿子吾逢久，皇皇未見閑。',48,'全唐诗/poet.song.39000.json','["滿子吾逢久，皇皇未見閑。", "老成終到孔，窮死亦爲顔。", "學術思無際，誠明去一間。", "吾雖有心者，力苦未能攀。"]'),
('5ede1185-ddc8-4af7-9800-bf70c9cd5cd5','強顔寄任道子權','王令','宋','宋诗','song-poetry','','[]','強顔求世亦何從，甔石時時得復空。',64,'全唐诗/poet.song.39000.json','["強顔求世亦何從，甔石時時得復空。", "何日能無寒餓役，此身得與聖賢終。", "人生汲汲須髙致，世態渾渾未易窮。", "安得相逢共相語，荒城回首又春風。"]'),
('a9cec9e0-524b-406b-b678-01a148214282','招夏和叔','王令','宋','宋诗','song-poetry','','[]','矻矻雕鐫役俗兒，六經塵土有誰吹。',64,'全唐诗/poet.song.39000.json','["矻矻雕鐫役俗兒，六經塵土有誰吹。", "我追往聖思前躅，子苟安行即後時。", "大遇定爲當世福，不逢猶作後來師。", "思量最是男兒事，此外吾曹不足期。"]'),
('45c09575-1ff9-4638-a586-2c062515a2f3','贈崔伯易','王令','宋','宋诗','song-poetry','','[]','巉巖惡面插蒼鬚，中道時時自笑呼。',64,'全唐诗/poet.song.39000.json','["巉巖惡面插蒼鬚，中道時時自笑呼。", "但怪佯狂輕去俗，果聞髙論足開余。", "惡看富貴庸男子，喜見徜徉隐丈夫。", "我是自髙無許可，今朝爲子一長吁。"]'),
('981a51f4-1dd4-4956-8ae1-82e2b3e443fc','贈裴仲卿','王令','宋','宋诗','song-poetry','','[]','匣劍光芒射斗牛，持携天下洗人仇。',64,'全唐诗/poet.song.39000.json','["匣劍光芒射斗牛，持携天下洗人仇。", "英雄心胆老猶壯，道路風塵行未休。", "名重更須完小節，義高何必論閑愁。", "濛濛細雨陵陽市，折取重梅上酒樓。"]'),
('0e43fc0d-cd8e-497a-a5ba-8dd41d012834','寄都下二三子失舉二首  其一','王令','宋','宋诗','song-poetry','','[]','翹翹數子拔羣倫，落筆文章妙有神。',64,'全唐诗/poet.song.39000.json','["翹翹數子拔羣倫，落筆文章妙有神。", "清世暫時藏琬琰，紅塵終不卧麒麟。", "淹留京國三年客，牢落江河一病身。", "得喪窮通雖付命，雙眸忍淚已沾巾。"]'),
('4254f76b-19e5-4ec1-a349-9ece93987e1f','寄都下二三子失舉二首  其二','王令','宋','宋诗','song-poetry','','[]','太學虀鹽共苦辛，寒窗筆硯日相親。',64,'全唐诗/poet.song.39000.json','["太學虀鹽共苦辛，寒窗筆硯日相親。", "梁王臺畔一分袂，揚子江頭三換春。", "篋裏黄金須買酒，髩邊白髪解欺人。", "窮通得喪誰能定，况是男兒有此身。"]'),
('37ce5e3c-bdc9-402d-a95e-f657927ddd90','李南夫罷舉歸隐','王令','宋','宋诗','song-poetry','','[]','夢寐風儀近十年，塵埃無路覩雲天。',64,'全唐诗/poet.song.39000.json','["夢寐風儀近十年，塵埃無路覩雲天。", "清朝未得榮簪紱，黄卷何妨樂聖賢。", "物外髙情誰與共，人間佳句已爭傳。", "欲知富貴終難動，一片丹心本寂然。"]'),
('aa83547d-8946-4bdc-ac56-9d8a14cd40f3','甫里','王令','宋','宋诗','song-poetry','','[]','甫里先生得古風，放身全入隐淪中。',64,'全唐诗/poet.song.39000.json','["甫里先生得古風，放身全入隐淪中。", "足磨漢榻星辰動，筆挫吳天物象空。", "往事欲尋人寂寂，舊田安在雨濛濛。", "當時引重髙才者，誰是曾來一畝宫。"]'),
('3e1241fc-8aec-4c53-9e19-f1f9fc9f0536','次韵朱昌叔見贈','王令','宋','宋诗','song-poetry','','[]','雖無才學可人羣，偶有誠心與古親。',64,'全唐诗/poet.song.39000.json','["雖無才學可人羣，偶有誠心與古親。", "兹世幾人能永富，此身何恤不終貧。", "生無簪綬身寧屈，死有詩書志尚伸。", "自匪與君嘗素計，斯言何敢易謀人。"]'),
('50757206-4f37-41e1-8789-af72d7e66ef2','次韵滿子權見寄','王令','宋','宋诗','song-poetry','','[]','當世雄圖不可懷，退居蒿艾自沉埋。',64,'全唐诗/poet.song.39000.json','["當世雄圖不可懷，退居蒿艾自沉埋。", "門無來足荆生道，病不能鋤草上階。", "自是直方違世易，况将疏懶合人乖。", "無由與子同樵種，回首平林浪可柴。"]'),
('9207511c-9e35-4ddd-b532-94254ebdb9fb','和束熙之論舊','王令','宋','宋诗','song-poetry','','[]','當年齠齔偶同門，餬口重來已十春。',64,'全唐诗/poet.song.39000.json','["當年齠齔偶同門，餬口重來已十春。", "仰嘆早成渾屬子，始知老拙盡輸人。", "火烟論友勞薫灼，桂蘗爲生合苦辛。", "待看聖賢堂奥去，願持箕帚掃遺塵。"]'),
('75b99b5b-b0b3-43ac-b259-1ef80e01f6b9','謝束丈','王令','宋','宋诗','song-poetry','','[]','喜赴西招足屢蹉，自慚愚鄙取無他。',64,'全唐诗/poet.song.39000.json','["喜赴西招足屢蹉，自慚愚鄙取無他。", "能終未學生何幸，得活諸孤賜最多。", "愧面未甘徒已矣，報心全寄命如何。", "須知下客終思用，不必時時彈鋏歌。"]'),
('668e4c08-0c0f-46bb-9c38-8babc53aa3e3','答許勤之','王令','宋','宋诗','song-poetry','','[]','不作明堂柱石臣，要當歸去老江濱。',32,'全唐诗/poet.song.39000.json','["不作明堂柱石臣，要當歸去老江濱。", "不知何處田堪買，抛却浮生一片塵。"]'),
('fa657c9a-4cf3-4faa-8ed3-16645bc3e366','答劉成父四愁詩','王令','宋','宋诗','song-poetry','','[]','倦客維揚每自悲，有時雙淚等閑垂。',64,'全唐诗/poet.song.39000.json','["倦客維揚每自悲，有時雙淚等閑垂。", "眼前所識皆庸我，天下爲憂可語誰。", "把臂便嫌逢子晚，開縢乃見起予詩。", "卷舒萬徹吟千遍，此後多應手有胝。"]'),
('69847657-2885-474e-bddf-34f7db846039','謝成父','王令','宋','宋诗','song-poetry','','[]','舊說詩無三百年，于今拭目讀君篇。',96,'全唐诗/poet.song.39000.json','["舊說詩無三百年，于今拭目讀君篇。", "已嗟吾道微如綫，不意斯文未喪天。", "金玉有聲情不俗，蕙蘭之臭美尤全。", "塵埃滿眼逢何晚，氣類相期久合堅。", "以義求人今遂得，于心無愧果爲賢。", "不須刺口論憔悴，吾輩恓惶自古然。"]'),
('d427b36e-7148-47c9-a22a-aba411854599','還蕭幾道詩卷','王令','宋','宋诗','song-poetry','','[]','武夷山骨插青冥，秀氣中蟠産俊英。',64,'全唐诗/poet.song.39000.json','["武夷山骨插青冥，秀氣中蟠産俊英。", "髙似君平于市隐，窮如東野以詩鳴。", "驊騮老騁青雲足，綠綺純含太古聲。", "顧我自憂衰病久，爲君雙眼暫時明。"]'),
('389cb1ac-c03f-4509-9b61-d711ebde5b7e','再次元韵答幾道','王令','宋','宋诗','song-poetry','','[]','塵囂擺落到鴻冥，始見當時遁世英。',64,'全唐诗/poet.song.39000.json','["塵囂擺落到鴻冥，始見當時遁世英。", "叢棘敢思丹鳯至，寸筳慚叩巨鐘鳴。", "須知奔競浮榮路，未若喧傳不朽聲。", "此道固爲流俗笑，苟非夫子欲誰明。"]'),
('40fe736c-784e-43ef-9442-778d3dfa14a5','謝幾道見示佳什因次元韵二首  其一','王令','宋','宋诗','song-poetry','','[]','曾酬唱和向家溪，嫫母終慚敵艶妻。',64,'全唐诗/poet.song.39000.json','["曾酬唱和向家溪，嫫母終慚敵艶妻。", "豈意誤將三獻玉，翻來輕博一丸泥。", "利能絕地同莊劍，巧可凌雲上魯梯。", "巾衍珍藏雖已固，祗愁飛去化爲霓。"]'),
('aa3dadf5-0a80-4fae-8116-f6343e1923f2','謝幾道見示佳什因次元韵二首  其二','王令','宋','宋诗','song-poetry','','[]','篇篇光絕奪春華，中有純音正不邪。',64,'全唐诗/poet.song.39000.json','["篇篇光絕奪春華，中有純音正不邪。", "跛鼈久慚追駿足，降旗今巳怯崇牙。", "清新格調空吟諷，猥冗言辭自咄嗟。", "爲我指迷終有得，曲蓬從此長叢麻。"]'),
('1db49042-42ec-4a84-a9fe-791da487a5dd','偶占','王令','宋','宋诗','song-poetry','','[]','卒卒往來舟，翻翻逐利謀。',24,'全唐诗/poet.song.39000.json','["卒卒往來舟，翻翻逐利謀。", "中流誰自溺，方去不回頭。"]'),
('ec7130a7-44d6-4cf8-a2b1-27dbfd63e108','思歸','王令','宋','宋诗','song-poetry','','[]','平生孤憤自潸然，不作春蠺但食眠。',64,'全唐诗/poet.song.39000.json','["平生孤憤自潸然，不作春蠺但食眠。", "干禄有心羞枉道，無田虛日望豐年。", "每將浩嘆期黄卷，已許多憂競白顛。", "舊笑古人輕獨往，近來還自憶林泉。"]'),
('9d0ba365-181d-4ee1-88e2-ae8d5f7d15db','秋日感憤二首  其一','王令','宋','宋诗','song-poetry','','[]','擊劍髙歌四顧遐，男兒何事繫如瓜。',64,'全唐诗/poet.song.39000.json','["擊劍髙歌四顧遐，男兒何事繫如瓜。", "蛟龍不是池中物，燕雀烏知隴上嗟。", "命有儻來猶未耳，天徒生我使窮耶。", "謝安未是才難者，底事蒼生却盛誇。"]'),
('7aabf165-1335-4d91-9e9c-9de221f7ad97','秋日感憤二首  其二','王令','宋','宋诗','song-poetry','','[]','坐睨歸鴻起自嗟，西風吹落淚痕斜。',64,'全唐诗/poet.song.39000.json','["坐睨歸鴻起自嗟，西風吹落淚痕斜。", "聚書老懶堆塵楮，秋劍寒酸蟄鐡蛇。", "自是卧龍猶戢角，浪嗟穴虎向生牙。", "從來思擲班傭筆，况是西山舊有家。"]'),
('8e83f835-9878-4b0e-97d3-171f133a39f4','襲襲','王令','宋','宋诗','song-poetry','','[]','襲襲前修與後生，要言髙爵是身榮。',32,'全唐诗/poet.song.39000.json','["襲襲前修與後生，要言髙爵是身榮。", "却將獵較誣師聖，不見三年學有成。"]'),
('721b45d5-5d67-4c8e-aa08-97bb91add8de','病中','王令','宋','宋诗','song-poetry','','[]','十日身無一日寧，病源知向百憂生。',64,'全唐诗/poet.song.39000.json','["十日身無一日寧，病源知向百憂生。", "寒侵騏驥應方瘦，蠧滿楩楠豈易榮。", "小閣晝閑書帙亂，畫堂風静藥羅聲。", "北山扶杖終歸去，寄語嵒猿莫曉驚。"]'),
('63c4c0c6-050c-4232-bb5d-464d512f836c','寄介甫','王令','宋','宋诗','song-poetry','','[]','已推事業皆歸命，空有文章自滿家。',64,'全唐诗/poet.song.39000.json','["已推事業皆歸命，空有文章自滿家。", "借使牛羊雖有責，豈于鳯鳥獨無嗟。", "人留孟子皆非道，客議揚雄正自譁。", "賢哲相望每千古，得逢猶說與時差。"]'),
('74171ed8-7268-4d56-8319-d43be00908f2','上杭帥吕舍人','王令','宋','宋诗','song-poetry','','[]','玉海澄中粹，金山拔外佳。',216,'全唐诗/poet.song.39000.json','["玉海澄中粹，金山拔外佳。", "無前誰與敵，獨進不容偕。", "列象明星璧，遺思結舘娃。", "一麾迎日下，四海望霖乖。", "今見詢僉允，從來注意諧。", "推溝常己任，濟域定民皆。", "富裕吳中俗，優游治外懷。", "樽環常滿客，醉擁坐添釵。", "賤子儒名業，平生客旁淮。", "塵埃方困頓，時命兩沉埋。", "居拙思營窟，炊窮欲析骸。", "毛生禰衡刺，麻繋吕匡鞋。", "海遠狂圖酌，天髙妄欲階。", "請雖非義得，來實爲貧嗟。", "况是常瞻目，将希未施崖。", "雖然愚者慮，庶享惡人齋。", "肉骨非難力，銘心謝莫涯。", "定須爲進互，庶或未愚柴。"]'),
('ed4c4352-4259-491c-af16-4961a15bfe09','上邵寶文','王令','宋','宋诗','song-poetry','','[]','出處身之道，窮通命所關。',240,'全唐诗/poet.song.39000.json','["出處身之道，窮通命所關。", "孔猶聞宋逐，軻亦退梁還。", "兹道方中否，流風有後艱。", "客來方病憲，人戚不堪顔。", "士有髙山仰，身嘗逸駕攀。", "徑心思古到，獨手欲今扳。", "憔悴窮年學，乖疏五兩綸。", "魚鹽聞古隐，畎畝識今閑。", "蹈海時何謂，無田力亦孱。", "清醒甘澤畔，富貴奈墦間。", "進壯羝羊觸，行屯乘馬班。", "食貧欣道在，愠見笑兒頑。", "時已輸雌雉，心猶恥瘠環。", "偶逢邦有道，喜睠涕無潸。", "觀水求窺海，知天願適山。", "雖歸滕國聖，尚賤許行蠻。", "進効無横草，希仁等棄官。", "聖門猶進惑，惠政况先鰥。", "自道非能賦，幾希不敢刪。", "誤知何以報，忠信赤心殷。"]'),
('a43195c3-0bca-498b-b5f3-8e178425e027','贈致政郭大丞','王令','宋','宋诗','song-poetry','','[]','冠盖冲冲語退居，幾人年少褫銀魚。',64,'全唐诗/poet.song.39000.json','["冠盖冲冲語退居，幾人年少褫銀魚。", "風波脫去都無累，日月閑來靜有餘。", "一斗獨傾花下酒，五車時晒腹中書。", "論詩深愧非商也，敢向邱門望起予。"]'),
('3826e6ea-3dce-4347-a9ee-892195b1f9de','閑居奉寄幾道','王令','宋','宋诗','song-poetry','','[]','門前一徑長寒莎，耳冷不聞車馬過。',64,'全唐诗/poet.song.39000.json','["門前一徑長寒莎，耳冷不聞車馬過。", "疏竹有風堪待月，空庭無雀可張羅。", "道心自覺閑中得，懶性還從病後多。", "回首西城望詩老，此心此性復如何。"]'),
('204c2cc0-aa5c-40e6-b65c-497a135b88df','慵','王令','宋','宋诗','song-poetry','','[]','衣冠慵整鬂慵梳，萬事從來静有餘。',32,'全唐诗/poet.song.39000.json','["衣冠慵整鬂慵梳，萬事從來静有餘。", "却笑嵇康慵未得，區區猶作絕交書。"]'),
('0e4e8c4f-c1a9-45e7-b5d1-45673763d0e8','金山寺','王令','宋','宋诗','song-poetry','','[]','萬頃清江浸碧山，乾坤都向此中寛。',64,'全唐诗/poet.song.39000.json','["萬頃清江浸碧山，乾坤都向此中寛。", "樓臺影落魚龍駭，鐘磬聲來水石寒。", "日暮海門飛白鳥，潮回瓜步見黄灘。", "當時戶外風波惡，祗得髙僧静處看。"]'),
('040192bb-ba52-46e0-86bd-8c9c5005b0d3','登甘露寺閣','王令','宋','宋诗','song-poetry','','[]','忽忽勞生歲月催，時偷髙跡出浮埃。',64,'全唐诗/poet.song.39000.json','["忽忽勞生歲月催，時偷髙跡出浮埃。", "風沾草樹紅朝動，春入川源綠夜回。", "欲出壮懷臨八極，可無樽酒到髙臺。", "江山不與人相語，似待忘言野客來。"]'),
('02e3ebad-7a79-4038-ad9e-ae65e3a1a5e8','讀西漢','王令','宋','宋诗','song-poetry','','[]','漢得孤秦萬弊時，當年丞相要無爲。',32,'全唐诗/poet.song.39000.json','["漢得孤秦萬弊時，當年丞相要無爲。", "洛陽年少空流涕，誰謂書生果有知。"]'),
('2518befd-d4dc-4038-b2d1-b6699bc067ab','讀東漢','王令','宋','宋诗','song-poetry','','[]','漢鼎重炎逆血熬，當時天子亦勤勞。',32,'全唐诗/poet.song.39000.json','["漢鼎重炎逆血熬，當時天子亦勤勞。", "不能乘作唐虞計，未會嚴陵所謂髙。"]'),
('dba78a50-ece2-4032-b338-e9a3053a8d38','讀商君傳','王令','宋','宋诗','song-poetry','','[]','利害從來識所存，固難輕重與人論。',32,'全唐诗/poet.song.39000.json','["利害從來識所存，固難輕重與人論。", "趙良不自身爲客，剛欲都君使灌園。"]'),
('030e27f8-0328-49c9-a298-6ab23c9ea499','書孔融傳','王令','宋','宋诗','song-poetry','','[]','戲撥虎鬚求不嚙，何如縮手袖中歸。',32,'全唐诗/poet.song.39000.json','["戲撥虎鬚求不嚙，何如縮手袖中歸。", "虛云坐上客常滿，許下惟聞哭習脂。"]'),
('ffb33821-a19f-44e7-94a7-b0abaf1ed9b3','武侯','王令','宋','宋诗','song-poetry','','[]','三顧雖然志意深，出非由道此何心。',32,'全唐诗/poet.song.39000.json','["三顧雖然志意深，出非由道此何心。", "平時胸腹能多少，且與羣兒梁父吟。"]'),
('cae7d44a-90ec-4630-b3bc-44a9f2d564a8','叔孫通','王令','宋','宋诗','song-poetry','','[]','弟子從來學未純，異時得失亦頻頻。',32,'全唐诗/poet.song.39000.json','["弟子從來學未純，異時得失亦頻頻。", "一官所買知多少，便議先生作聖人。"]'),
('87b96ee7-16b4-4ef7-b110-6ef98d125faf','韓吏部','王令','宋','宋诗','song-poetry','','[]','宣尼夾谷叱強齊，吏部深州破賊圍。',32,'全唐诗/poet.song.39000.json','["宣尼夾谷叱強齊，吏部深州破賊圍。", "始信真儒能見用，可爲邦國大皇威。"]'),
('17286ee8-952f-42aa-a361-ba996e66bfeb','讀老杜詩集','王令','宋','宋诗','song-poetry','','[]','氣吞風雅妙無倫，碌碌當年不見珍。',64,'全唐诗/poet.song.39000.json','["氣吞風雅妙無倫，碌碌當年不見珍。", "自是古賢因發憤，非關詩道可窮人。", "鐫鑱物象三千首，照耀乾坤四百春。", "寂寞有名身後事，惟餘孤塜耒江濱。"]'),
('c9e6717c-23cd-4080-b81d-cd9124979f3c','讀白樂天集','王令','宋','宋诗','song-poetry','','[]','北邙山下一孤墳，流落三千綺麗文。',64,'全唐诗/poet.song.39000.json','["北邙山下一孤墳，流落三千綺麗文。", "後世聲名髙白日，當年榮利等浮雲。", "屏除憂憤歸禪寂，消遣光陰在酒醺。", "若使篇章深李杜，竹符還不到君分。"]'),
('32373e4a-41df-4472-beab-1d91d4055318','過伍子胥廟','王令','宋','宋诗','song-poetry','','[]','西風騷客倦遊吳，弔古心懷此暫舒。',64,'全唐诗/poet.song.39000.json','["西風騷客倦遊吳，弔古心懷此暫舒。", "鬼籙久應除佞嚭，民思今果廟神胥。", "雖然邪正皆歸死，奈有忠讒各異書。", "回首舊江江水在，怒濤猶是不平初。"]'),
('89ec3f8f-3838-44c7-8a76-1f46bfb5c14b','泰伯廟','王令','宋','宋诗','song-poetry','','[]','古廟鬰崔嵬，朱門傃道開。',24,'全唐诗/poet.song.39000.json','["古廟鬰崔嵬，朱門傃道開。", "今人不爲讓，間或乞靈來。"]'),
('c401f7a9-9f62-4558-9310-e0429ba8c4f1','和人古劍','王令','宋','宋诗','song-poetry','','[]','安知歲月幾經今，傳記汗漫不可尋。',64,'全唐诗/poet.song.39000.json','["安知歲月幾經今，傳記汗漫不可尋。", "得自廢墟埋萬古，失曾飛將購千金。", "客思秋水龍泉冷，士嘆中原虎穴深。", "好與壯夫同隱約，鐡房寒澁壁塵侵。"]'),
('0994aff9-51cf-48e4-9475-f23379a1f34c','琴二首  其一','王令','宋','宋诗','song-poetry','','[]','古風寥落欲何尋，常記南風素意深。',32,'全唐诗/poet.song.39000.json','["古風寥落欲何尋，常記南風素意深。", "聞說五弦弦不斷，欲于何處借人琴。"]'),
('30d3ee62-7fb8-4a8e-a144-d70f3920615e','琴二首  其二','王令','宋','宋诗','song-poetry','','[]','不獨區區操縵間，要期追逐古風還。',32,'全唐诗/poet.song.39000.json','["不獨區區操縵間，要期追逐古風還。", "吾民有愠何當解，學得南風不敢彈。"]'),
('33fc38c3-4fa2-4423-b25f-5fb91c753f71','謝張和仲惠寶雲茶','王令','宋','宋诗','song-poetry','','[]','故人有意真憐我，靈荈封題寄蓽門。',64,'全唐诗/poet.song.39000.json','["故人有意真憐我，靈荈封題寄蓽門。", "與療文園消渇病，還招楚客獨醒魂。", "烹來似带吳雲脚，摘處應無糓雨痕。", "果肯同嘗竹林下，寒泉應有惠山存。"]'),
('3776b508-59c2-4013-b989-8d65a83504ad','和人孤雁','王令','宋','宋诗','song-poetry','','[]','朔磧雲深憶舊行，心驚漢月忽騫翔。',64,'全唐诗/poet.song.39000.json','["朔磧雲深憶舊行，心驚漢月忽騫翔。", "江南水濶無天地，漠北沙寒有雪霜。", "遠目送飛沉暮靄，西風吹影過斜陽。", "衡南未到歸何日，須信張羅近稻粱。"]'),
('8337fb2a-7bdd-45bc-b061-14b176aa2020','雁','王令','宋','宋诗','song-poetry','','[]','萬里長爲客，飛飛豈自由。',48,'全唐诗/poet.song.39000.json','["萬里長爲客，飛飛豈自由。", "情知稻粱急，莫近網羅求。", "關塞風髙夜，江湖水落秋。", "哀鳴徒自切，誰謂爾悲愁。"]'),
('f5628767-09c5-454a-b29f-f96d29cfd059','送雁','王令','宋','宋诗','song-poetry','','[]','來時羣雁去相随，病眼看天遠不知。',64,'全唐诗/poet.song.39000.json','["來時羣雁去相随，病眼看天遠不知。", "爲有客愁歸未得，獨凴斜日望多時。", "遲遲南國無春雪，細細東風滿柳枝。", "蝴蝶黄鶯有期約，好加歸翥莫令遲。"]'),
('1925ba04-bf1d-434b-bd7c-7d9a43f73393','鴉鳴','王令','宋','宋诗','song-poetry','','[]','庭前佳樹綠陰成，樹抄飛鴉去就輕。',64,'全唐诗/poet.song.39000.json','["庭前佳樹綠陰成，樹抄飛鴉去就輕。", "自顧主人無敗德，豈嫌爾口有凶聲。", "平生直道常多禍，兩耳清風一聽鳴。", "輙莫爲人輕自重，須知彈射易忘生。"]'),
('b221a8a2-51ae-489b-9f99-5aa56cd4f622','馴鹿','王令','宋','宋诗','song-poetry','','[]','日日野心新，籠欄外強馴。',48,'全唐诗/poet.song.39000.json','["日日野心新，籠欄外強馴。", "祗消指馬相，便有逐原人。", "昔起歌賓興，今無伏囿仁。", "豺狼好牙爪，應笑角如麟。"]'),
('28885899-16e4-4333-9f16-49ede25c7c57','和人放魚','王令','宋','宋诗','song-poetry','','[]','春溪水暖綠蒲沉，兩兩遊鱗躍紫金。',64,'全唐诗/poet.song.39000.json','["春溪水暖綠蒲沉，兩兩遊鱗躍紫金。", "必以直鈎應不得，果知非命亦何心。", "舟吞遠海鯨鯢老，餌滿平湖網罟深。", "縱爾豈知吾有意，渭川人去事難尋。"]'),
('0b16de04-e2e1-4f08-a22c-4eb034672244','和人促織','王令','宋','宋诗','song-poetry','','[]','秋虫何爾亦怱怱，何處人心與爾同。',64,'全唐诗/poet.song.39000.json','["秋虫何爾亦怱怱，何處人心與爾同。", "夢枕幾年懸客淚，曉窗殘月破西風。", "人思絕漠冰霜早，婦嘆窮閻杼柚空。", "更有孤砧共岑寂，平明華髪滿青銅。"]'),
('aa02617d-2ae4-470e-97ac-a61b5a35ffa0','聞促織','王令','宋','宋诗','song-poetry','','[]','衰草風來響不知，破窗燈滅月藏輝。',32,'全唐诗/poet.song.39000.json','["衰草風來響不知，破窗燈滅月藏輝。", "白頭老婦無機織，卧聽鄰兒懶擣衣。"]'),
('5826162b-8257-402e-bdd2-6063f6bbaf7c','苦熱','王令','宋','宋诗','song-poetry','','[]','土燥木根焦，禽窮自拔毛。',48,'全唐诗/poet.song.39000.json','["土燥木根焦，禽窮自拔毛。", "龍遺赤日走，天避火雲髙。", "虎懼千山熾，鯨憂四海熬。", "風微不飽腹，蟬亦爲身號。"]'),
('21409cc2-e263-4783-93e7-3df0318838f6','和束蒙初九日不見菊登髙','王令','宋','宋诗','song-poetry','','[]','從來秋菊不曾栽，敢向西風怨不開。',32,'全唐诗/poet.song.39000.json','["從來秋菊不曾栽，敢向西風怨不開。", "我自傷秋有髙興，非關特爲菊花來。"]'),
('25128127-e118-4a6b-a964-7b9d3a5c4fd3','簾','王令','宋','宋诗','song-poetry','','[]','髙明庭宇好崇基，枉把疏簾窣地垂。',64,'全唐诗/poet.song.39000.json','["髙明庭宇好崇基，枉把疏簾窣地垂。", "必欲滿堂陰有樂，誰能暗室自無欺。", "卷舒未必風無意，間隙須防燕解窺。", "莫道人終可遮障，可終遮障亦何爲。"]'),
('fe693f3a-c3f3-4c34-bdd3-ce8f9ac00eb3','詆燕','王令','宋','宋诗','song-poetry','','[]','金屋人嬌奈燕何，暮簾好捲放來過。',32,'全唐诗/poet.song.39000.json','["金屋人嬌奈燕何，暮簾好捲放來過。", "今年已見燕無數，何况明年燕更多。"]'),
('d51c0bbb-aecb-4cd0-831b-8a3fd708c5ed','燕答','王令','宋','宋诗','song-poetry','','[]','春日樓臺暖氣低，東風無主自東西。',32,'全唐诗/poet.song.39000.json','["春日樓臺暖氣低，東風無主自東西。", "尋常簾幙有多少，何處畫梁無燕泥。"]'),
('566f28ab-4932-4422-b67e-9cbed2815995','觀飲','王令','宋','宋诗','song-poetry','','[]','不飲雖然合衆難，何妨衆客自盤桓。',32,'全唐诗/poet.song.39000.json','["不飲雖然合衆難，何妨衆客自盤桓。", "已看手足互顛倒，更聽人人自謂歡。"]'),
('635994e5-c138-4db6-bd53-8919705cd41e','答耿奎','王令','宋','宋诗','song-poetry','','[]','浮生飄泊委蓬蒿，洴澼無封敢嘆勞。',64,'全唐诗/poet.song.39000.json','["浮生飄泊委蓬蒿，洴澼無封敢嘆勞。", "心學古人方有愧，身從衰俗忽爲髙。", "苟慚枉道干簞食，肯謂非時愛一毛。", "末學從兹益知守，善人不鄙與華褒。"]'),
('93bae897-abf2-48b3-925f-bef6007dfcb3','江上','王令','宋','宋诗','song-poetry','','[]','浩渺烟波不可名，我來閑自濯塵纓。',64,'全唐诗/poet.song.39000.json','["浩渺烟波不可名，我來閑自濯塵纓。", "久思滄海收身去，安得長舟破浪行。", "天濶水雲連黯淡，日間鷗鷺自飛鳴。", "屈平死後漁人盡，後世憑誰論濁清。"]'),
('5ef33ac7-ff09-4368-abff-24e965b26f6d','洗竹','王令','宋','宋诗','song-poetry','','[]','去年春笋密相扶，洗去心圖翠色疏。',64,'全唐诗/poet.song.39000.json','["去年春笋密相扶，洗去心圖翠色疏。", "髙節欲令人盡見，枉枝何惜手親除。", "臨川常可持爲釣，待鳳猶能飽有餘。", "須看月明風勁夜，寒聲薄影滿茅居。"]'),
('9423e069-8265-47d4-88c1-eac176a1cbf3','春夢','王令','宋','宋诗','song-poetry','','[]','湘水茫茫春意關，岑郎一睡片時間。',32,'全唐诗/poet.song.39000.json','["湘水茫茫春意關，岑郎一睡片時間。", "誰知行盡江南路，枕上離家枕上還。"]'),
('4af543e0-17f9-4c60-938e-8c2355e328ed','秋日偶成呈杜子長顯之兼簡仲美劉丈','王令','宋','宋诗','song-poetry','','[]','丈夫不合自窮愁，藜藿先須天下憂。',64,'全唐诗/poet.song.39000.json','["丈夫不合自窮愁，藜藿先須天下憂。", "君不唐虞皆我罪，民推溝壑更誰尤。", "須将兼濟爲吾事，若只誠身亦我羞。", "滿紙古人皆有道，如其所學願軻邱。"]'),
('ce0415a2-c281-4eb9-8e14-335d4ffd7231','歲暮言懷呈諸友','王令','宋','宋诗','song-poetry','','[]','萬事無成只一吁，窮年况復嘆窮途。',64,'全唐诗/poet.song.39000.json','["萬事無成只一吁，窮年况復嘆窮途。", "功名未立頭先白，貧病相仍氣尚粗。", "富貴早知皆有命，窮通料是不由吾。", "會須開口随時笑，一曲長歌醉倒壺。"]'),
('7d924903-b2c4-44bf-9a52-82eb6d70d8ab','日益無聊賴偶成呈子長','王令','宋','宋诗','song-poetry','','[]','一夕西風葉下柯，覊人憔悴發沉疴。',64,'全唐诗/poet.song.39000.json','["一夕西風葉下柯，覊人憔悴發沉疴。", "窮來無子知難得，命薄于人可奈何。", "困卧牛衣空有泪，劇彈鐡劍不成歌。", "陶家壁冷塵埃滿，何日雲雷起鐡梭。"]'),
('38ba0f7b-34b5-44c2-bf3b-19a93e11c5b0','醉後','王令','宋','宋诗','song-poetry','','[]','醉裏分明别是天，最宜沉溺過流年。',64,'全唐诗/poet.song.39000.json','["醉裏分明别是天，最宜沉溺過流年。", "平時政要全稽古，盛世朝廷不乏賢。", "但得有生皆自遂，不妨吾屬亦陶然。", "沉湘死屈如何者，却把醒名欲自專。"]'),
('3a8bed9d-0368-45be-9d81-84eea1aa9c41','梅花','王令','宋','宋诗','song-poetry','','[]','曉枝開早未多稠，屢齅清香不忍收。',64,'全唐诗/poet.song.39000.json','["曉枝開早未多稠，屢齅清香不忍收。", "萬木已知春盡到，百花常負後來羞。", "東風也合相和暖，臘雪無端欲滯留。", "滿眼蕭疏正堪惜，莫将横笛起人愁。"]'),
('e91a99e3-858e-423a-bcfe-9e55d6f2dbb8','木瓜花','王令','宋','宋诗','song-poetry','','[]','簇簇紅葩間綠荄，陽和閑暇不須催。',32,'全唐诗/poet.song.39000.json','["簇簇紅葩間綠荄，陽和閑暇不須催。", "天教爾艶呈奇絕，不與夭桃次第開。"]'),
('ad1bfd2a-c164-4e55-85df-3caa8a76f4c2','蔬蘭','王令','宋','宋诗','song-poetry','','[]','曉折寒蔬野圃間，荒林深處有芳蘭。',32,'全唐诗/poet.song.39000.json','["曉折寒蔬野圃間，荒林深處有芳蘭。", "世無賢士紉爲佩，猶有幽人日取餐。"]'),
('d7521fc5-6673-4423-8256-6ee8aa81002d','九曲池悼古','王令','宋','宋诗','song-poetry','','[]','刳地決洪波，深流隐木鵝。',192,'全唐诗/poet.song.39000.json','["刳地決洪波，深流隐木鵝。", "檣髙帆繫錦，堤暖柳藏河。", "泰甚心方兆，顛危念則那。", "去都如脫屣，東下若瘳疴。", "殿脚千論女，宫眉斛計螺。", "迷樓插空遠，水調掲聲和。", "忠切聞無路，愚諛面自阿。", "君顔未回笑，賊首已稱戈。", "運去天移鼎，人遷地見禾。", "當年遺廢沼，及此尚名歌。", "古往悲奚寄，今傳跡未訛。", "水寒波刺甲，土老岸髯莎。", "落照留歸鳥，西風困舊荷。", "暮林迷遠嶼，夕靄暝前波。", "亡國誰堪問，覊人恨自多。", "凭欄不成去，歸意爲蹉跎。"]'),
('ba393202-f883-4a9f-9e11-0c9c2386ab4e','寄宿倅陸經子履','王令','宋','宋诗','song-poetry','','[]','勳業悠悠未可貪，直須随處酌醺酣。',64,'全唐诗/poet.song.39000.json','["勳業悠悠未可貪，直須随處酌醺酣。", "君知仕路三無愠，我與人情七不堪。", "聞借朱衣爲别乘，想回青眼憶髙談。", "東風尚有西行約，甬水橋邊定解驂。"]'),
('92852922-09a5-4dde-88d8-9ab384722640','太湖','王令','宋','宋诗','song-poetry','','["\u592a\u6e56"]','西南無盡望，吞恐罄吳郊。',156,'全唐诗/poet.song.39000.json','["西南無盡望，吞恐罄吳郊。", "海近私憑蓄，天低不敢包。", "蛟龍宜自宅，螾蛭莫令巢。", "遠浦纔分點，歸檣略認梢。", "水乘潮更濶，地過底宜坳。", "鳥絕烟維斷，風凌浪脊交。", "大橋横作書，別岸缺成爻。", "吟恐詩無氣，圖憂筆費抄。", "歸輸范蠡得，官許季鷹抛。", "去憶心應繫，歸誇口定勞。", "窮何須蹈海，來好卜編茅。", "著户生同隐，居民釣自庖。", "滄浪未容濯，魚枻夜停敲。"]'),
('9d5ee55f-b1dc-48d1-afb8-390ddfb8fb2b','答劉仲美','王令','宋','宋诗','song-poetry','','[]','莽莽晴川水，寥寥病客舟。',48,'全唐诗/poet.song.39000.json','["莽莽晴川水，寥寥病客舟。", "來随風浩蕩，去逐雨淹留。", "生計梁邊燕，歸心海上鷗。", "多慚故人句，欹卧一長謳。"]'),
('b2ce0ff0-3c61-4dab-9087-f55670394212','平山堂寄歐陽公','王令','宋','宋诗','song-poetry','','[]','廢苑繁華未可尋，孤城西北路嶔崟。',64,'全唐诗/poet.song.39000.json','["廢苑繁華未可尋，孤城西北路嶔崟。", "檐邊月過峰巒頂，柱下雲回草樹陰。", "賓客日随千騎樂，管絃風入萬家深。", "知公白玉堂中夢，未負當時壮觀心。"]'),
('37b614b6-002d-4f3a-9de4-614a26583e21','歲暮呈王介甫平甫','王令','宋','宋诗','song-poetry','','[]','歲暮遠爲客，一身歸計深。',48,'全唐诗/poet.song.39000.json','["歲暮遠爲客，一身歸計深。", "塵沙日翳翳，雨雪夜陰陰。", "喜色開南信，悲懷動北琴。", "感時須寂寞，何獨少陵心。"]'),
('6c711245-65ae-4205-8e2b-1b460df85ec2','塵土呈介甫','王令','宋','宋诗','song-poetry','','[]','塵土紛紛起處微，祗随風力亂嘘吹。',64,'全唐诗/poet.song.39000.json','["塵土紛紛起處微，祗随風力亂嘘吹。", "髙張白霧横宫闕，低引輕雲暗路岐。", "客坐昏蒙歸耳目，人行斑白上鬚眉。", "誰知霶霈天飛雨，洗滌輕浮會有時。"]'),
('006c4cbc-e93a-4f2f-b58c-f7360b9222c8','溪上','王令','宋','宋诗','song-poetry','','[]','溪上清漣樹老蒼，行穿溪樹踏青陽。',32,'全唐诗/poet.song.39000.json','["溪上清漣樹老蒼，行穿溪樹踏青陽。", "溪深樹密無人處，祗有幽花度水香。"]'),
('5d26c6e6-48c6-4a73-9532-06bde5bf2bc2','金山','王令','宋','宋诗','song-poetry','','[]','馬蹄行盡九州閑，無處歡娛得破顔。',32,'全唐诗/poet.song.39000.json','["馬蹄行盡九州閑，無處歡娛得破顔。", "只有此中宜曠望，誰令天作海門山。"]'),
('2d3e7238-282c-4a01-bca8-c2e9681ceacf','朝雲','王令','宋','宋诗','song-poetry','','[]','朝雲飛飛來無窮，暮雲漠漠昏相蒙。',64,'全唐诗/poet.song.39000.json','["朝雲飛飛來無窮，暮雲漠漠昏相蒙。", "閑來既自不成雨，拂去安用遮長空。", "擬鞭屏翳問白日，更謫星伯誅長風。", "盡令萬物被光景，夜看北斗朝天中。"]'),
('612c35f2-8898-4c0f-95c3-37f64076c577','登城','王令','宋','宋诗','song-poetry','','[]','病來萬事懶自宜，髙城有樓閑登躋。',64,'全唐诗/poet.song.39000.json','["病來萬事懶自宜，髙城有樓閑登躋。", "來期清風脱日熱，坐厭遠日看天低。", "閑郊草樹漫蒙昧，落日燕雀争依棲。", "臨風一嘆人不會，直氣飛去添虹霓。"]'),
('0736d454-0bfc-4b24-9a47-8b8cdb206cd6','招束伯仁杜子長夜話','王令','宋','宋诗','song-poetry','','[]','久陰忽晴已可賞，况復夜氣驅蚊藏。',64,'全唐诗/poet.song.39000.json','["久陰忽晴已可賞，况復夜氣驅蚊藏。", "清風逆回六月熱，急雨借得三秋凉。", "非惟歸雲人目快，更有白月天心當。", "從來萬古有未盡，待子一夕心胸張。"]'),
('564b64b1-a68a-442d-b0a9-5a94a54772df','臨別瓜州','王令','宋','宋诗','song-poetry','','[]','十年來往常依依，此日復去來何時。',64,'全唐诗/poet.song.39000.json','["十年來往常依依，此日復去來何時。", "青山有意退弗忍，白髪不逢歸未遲。", "乾坤不盡萬里望，草木無限西風悲。", "塵纓欲濯惡獨潔，滄浪流去清無涯。"]'),
('1319255f-ae9e-45ea-a7c6-e7e6a5adda97','春意','王令','宋','宋诗','song-poetry','','[]','春空漠漠多愁容，春意冉冉随歸鴻。',64,'全唐诗/poet.song.39000.json','["春空漠漠多愁容，春意冉冉随歸鴻。", "寒雲飛髙不肯雨，白日翳暗何時風。", "閑花野草各意態，濃烟弱柳相昏蒙。", "北窗厭睡不知夜，起見海月如秋空。"]'),
('1f537fd7-37ec-4cd1-9bfb-8bebd4c3bbdf','酒船','王令','宋','宋诗','song-poetry','','[]','刳木以爲舟，蓋取諸渙象。',72,'全唐诗/poet.song.39000.json','["刳木以爲舟，蓋取諸渙象。", "有能爲其模，黄金役良匠。", "虛中無檣楫，所載惟佳釀。", "繡段圍華堂，妖姬發清唱。", "坐乘歡來時，落日翻紅浪。", "試問醉鄉遊，何如江海上。"]'),
('258134d5-d51e-47e0-a068-e9f7fe1499c1','別表弟司秀才','王令','宋','宋诗','song-poetry','','[]','吾學老無長，吾日亦自愛。',48,'全唐诗/poet.song.39000.json','["吾學老無長，吾日亦自愛。", "念當相捨去，反覆互嗟慨。", "謀道苟能同，千里如坐會。", "又何重子行，吾意自有在。"]'),
('bdd4c9a5-8b4c-454d-aaf9-ce445190be88','別黄端微','王令','宋','宋诗','song-poetry','','[]','滄江無纖鱗，太岳無低岑。',60,'全唐诗/poet.song.39000.json','["滄江無纖鱗，太岳無低岑。", "鳳凰遺其卵，意欲留清音。", "昂昂臥虎兒，已有吞牛心。", "吳山山雖高，滿路紅棘林。", "不如早西來，草堂松竹深。"]'),
('6e6fbd8e-8981-4b19-90c5-e66a7244b335','長江萬頃明如鏡','王令','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江萬頃明如鏡，江面無風江水靜。',96,'全唐诗/poet.song.39000.json','["長江萬頃明如鏡，江面無風江水靜。", "白日當空照江底，蛟穴龍居難隱映。", "亂山影落碧波寒，漁翁醉臥愁不醒。", "遲暮東南見海門，海門目斷煙雲暝。", "幾度狂濤日月低，舟師鼓枻歌相慶。", "長江雖長繒網多，纖鱗何處逃生命。"]'),
('4cd330a5-4221-42f9-a933-17e202c19eee','題步君敘園亭','王令','宋','宋诗','song-poetry','','[]','我愛練湖春柳好，四十里圍青玉城。',128,'全唐诗/poet.song.39000.json','["我愛練湖春柳好，四十里圍青玉城。", "平流中澄綠鏡匣，遠山旁臥翠虎橫。", "黄林主人樂此地，瞰壓湖面開以亭。", "常將醉目望野色，數曲老畫誰家屏。", "山禽水鳥盡相識，飛入欄壁馴不驚。", "有時落照到波上，一眼萬疊金鱗明。", "伊余與世既齟齪，奈此有地來歸耕。", "迴頭把眼看市道，愁向塵埃著脚行。"]'),
('cb627185-fdd1-4312-b54d-e49cb44dbdd0','樓上曲','王令','宋','宋诗','song-poetry','','[]','逆口不唱當時歌，當時笑聲與曲和。',160,'全唐诗/poet.song.39000.json','["逆口不唱當時歌，當時笑聲與曲和。", "忍目不視當時字，當時字寫當時意。", "當時意斷字空存，縱有前歌不忍聞。", "樓憑西北欄干暖，病眼看天淚瘴昏。", "望望行雲迷笑電，曉夢依稀有時見。", "雙眉聚綠眼揉紅，猶似臨歸別時面。", "秋夜遲遲夜燈短，翠被孤眠不成暖。", "舊時笑月不長圓，如今愁看月空滿。", "武陵幾欲尋歸路，桃花迷人不知步。", "霜餘芳草不成青，暮鴻飛入斜陽去。"]'),
('5653a165-1328-43f6-a720-b82a97284de0','憶江陰呈介甫','王令','宋','宋诗','song-poetry','','[]','江上城隍古鏡中，城邊山色翠屏風。',64,'全唐诗/poet.song.39000.json','["江上城隍古鏡中，城邊山色翠屏風。", "魚蝦接海隨時足，稻米連湖逐歲豐。", "泰伯人民堪教育，春申溝港可疏通。", "朱輪天使從君欲，異日能忘笑語同。"]'),
('75660278-5098-4716-a2e7-2b718aa4ada7','平山堂','王令','宋','宋诗','song-poetry','','[]','豁豁虛堂巧架成，地平相與遠山平。',64,'全唐诗/poet.song.39000.json','["豁豁虛堂巧架成，地平相與遠山平。", "橫巖積翠檐邊出，度隴浮蒼瓦上生。", "春入壺觴分蜀井，風回談笑落蕪城。", "謝公已去人懷想，向此還留召伯名。"]'),
('7e600bd5-2eb7-4a33-be12-9d8b36bd7580','吳學士席上作','王令','宋','宋诗','song-poetry','','[]','塵沙欺客日冥冥，喜對賢豪耳目清。',64,'全唐诗/poet.song.39000.json','["塵沙欺客日冥冥，喜對賢豪耳目清。", "爛熳共誇文字飲，歡娛誰憶管絃聲。", "風牽翠幕燈相照，月掛朱簾酒屢傾。", "後夜想當繁劇處，夢魂還繞北池行。"]'),
('59225d72-4795-4a0f-a7dc-ec8804c6baf2','羈旅呈介甫','王令','宋','宋诗','song-poetry','','[]','羈旅迫歲晚，班毛混滿簪。',48,'全唐诗/poet.song.39000.json','["羈旅迫歲晚，班毛混滿簪。", "遊無輠下馬，坐乏囊中金。", "塵漲風聲濁，天昏雪氣深。", "幸聞清論數，竟日解悲吟。"]'),
('075b6b89-b5b5-44ca-98af-1c9c85b329b3','送介甫行畿縣','王令','宋','宋诗','song-poetry','','[]','廄牧三年厭苦頻，況令持斧似行春。',64,'全唐诗/poet.song.39000.json','["廄牧三年厭苦頻，況令持斧似行春。", "民氓墮窳懷寬政，吏士因循倚近親。", "被水田疇思貸種，經冬鰥寡待周貧。", "想今愈有江湖興，亦欲同君一釣綸。"]'),
('d54dfbfd-6f4a-4563-a909-7fc438c2cfcb','次韻介甫懷舒州山水見示之什','王令','宋','宋诗','song-poetry','','[]','皖上相逢昔少留，登樓隱几聽鳴鳩。',64,'全唐诗/poet.song.39000.json','["皖上相逢昔少留，登樓隱几聽鳴鳩。", "山峰行處今何在，溪水流乘此有不。", "就食四方甘不繫，爲生一世信長浮。", "共知局促京沙裏，回首當時始覺差。"]'),
('01c04947-4e50-4f72-92df-56c3777f942f','因憶灊樓讀書之樂呈介甫','王令','宋','宋诗','song-poetry','','[]','憶昨灊樓幸久留，乾坤談罷論雎鳩。',64,'全唐诗/poet.song.39000.json','["憶昨灊樓幸久留，乾坤談罷論雎鳩。", "它時已恨相從少，此日能忘共學不。", "南去溪山隨夢斷，北來身世若雲浮。", "行藏願與君同道，祇恐蹉跎我獨羞。"]'),
('da1532dd-9350-4e49-8f43-fdc7cb5bd286','次韻介甫集禧池上詠鵝','王令','宋','宋诗','song-poetry','','[]','池上溶溶浮暖日，野鵝無數自相於。',64,'全唐诗/poet.song.39000.json','["池上溶溶浮暖日，野鵝無數自相於。", "謀生跡與風波密，擇地心將網弋疏。", "毛羽鮮明疑振鷺，聲鳴和好似關雎。", "應憐豢養輕身者，只直羲之數紙書。"]'),
('2c32ebb4-d8ce-4e51-9b80-05329f9f52f6','存目','王令','宋','宋诗','song-poetry','','[]','詩題：有約首句：黄梅時節家家雨。',16,'全唐诗/poet.song.39000.json','["詩題：有約首句：黄梅時節家家雨。"]'),
('160de938-2d08-44bb-992c-992166bcc6c1','答弟逢原','王氏','宋','宋诗','song-poetry','','[]','無求子樂我何悲，且與兒曹並日饑。',32,'全唐诗/poet.song.39000.json','["無求子樂我何悲，且與兒曹並日饑。", "子道合人終不苟，有求雖欲可從誰。"]'),
('c727e6f5-8731-4324-a47c-c57ff129cca7','第一青原階級頌','釋義青','宋','宋诗','song-poetry','','[]','無見頂露雲攢急，劫外靈枝不带春。',32,'全唐诗/poet.song.39000.json','["無見頂露雲攢急，劫外靈枝不带春。", "那邊不坐空王殿，爭肯耘田向日輪。"]'),
('f4ac3ae7-d2ac-49ab-af18-3c22bcae8669','第二非但曹溪頌','釋義青','宋','宋诗','song-poetry','','[]','白雲藏王鳳，紅日照無寥。',24,'全唐诗/poet.song.39000.json','["白雲藏王鳳，紅日照無寥。", "隱隱星攢處，無私鎮九霄。"]'),
('1753e891-f110-42bb-a8ff-235b08cd6b65','第三雲巖遊山頌','釋義青','宋','宋诗','song-poetry','','[]','大鵬無伴遇天池，師子將兒絕後隨。',32,'全唐诗/poet.song.39000.json','["大鵬無伴遇天池，師子將兒絕後隨。", "崑崙觸犯歸行路，一吼吞雲萬像馳。"]'),
('48e6a0d8-3051-471e-86a3-d8744821abd0','第四道吾深深頌','釋義青','宋','宋诗','song-poetry','','[]','驪龍海臥瑞雲高，四望歸宗萬派潮。',32,'全唐诗/poet.song.39000.json','["驪龍海臥瑞雲高，四望歸宗萬派潮。", "木人來問西宮事，回惠東園一顆桃。"]'),
('f06ca2c2-388c-4ca2-8b3e-11d856cef34c','第五巖參藥山頌','釋義青','宋','宋诗','song-poetry','','[]','行盡千山路轉高，肯歸方憶舊雲房。',32,'全唐诗/poet.song.39000.json','["行盡千山路轉高，肯歸方憶舊雲房。", "貪尋古調單于曲，暨蹉胡家一韻長。"]'),
('753c9cf2-34f2-4175-8b96-7be87133201d','第六夾山船子頌','釋義青','宋','宋诗','song-poetry','','[]','泛舟駕嶮三十春，擊處竿頭活死人。',32,'全唐诗/poet.song.39000.json','["泛舟駕嶮三十春，擊處竿頭活死人。", "夾嶺桂分千古韻，朗江山翠萬重新。"]'),
('a661f9b5-1eed-4aba-935f-d995a62a49be','第七我國宴然頌','釋義青','宋','宋诗','song-poetry','','[]','興亡雲去輿雲來，渠無國上絕塵埃。',32,'全唐诗/poet.song.39000.json','["興亡雲去輿雲來，渠無國上絕塵埃。", "須彌頂上無根草，不受春風花自開。"]'),
('05ffd4a5-4ba2-433e-ab25-8d63a79dd2b9','第八僧問石霜頌','釋義青','宋','宋诗','song-poetry','','[]','三更月落兩山明，古道程遙苔滿生。',32,'全唐诗/poet.song.39000.json','["三更月落兩山明，古道程遙苔滿生。", "金鎮搖時無手犯，碧波心月兔常行。"]'),
('1f72f806-8fed-4dd9-b41a-a856429c3269','第九洞山祖意頌','釋義青','宋','宋诗','song-poetry','','[]','古源無水月何生，滿岸西流一派分。',32,'全唐诗/poet.song.39000.json','["古源無水月何生，滿岸西流一派分。", "蔥嶺罷詢熊耳夢，雪庭休話少林春。"]'),
('194a8b44-41d1-42b4-a4c2-16809ff4ee79','第十夾山答佛頌','釋義青','宋','宋诗','song-poetry','','[]','親言言處幾人知，今古無儔類莫齊。',32,'全唐诗/poet.song.39000.json','["親言言處幾人知，今古無儔類莫齊。", "玉馬雪行歸半夜，羚羊掛角月沉西。"]'),
('083a92d3-3a8a-4389-a97d-80be7f7e90fc','第十一萬戶俱開頌','釋義青','宋','宋诗','song-poetry','','[]','古殿巖開月鎖松，霜凝雪露韻無窮。',32,'全唐诗/poet.song.39000.json','["古殿巖開月鎖松，霜凝雪露韻無窮。", "星前人臥千峰室，佛祖無因識得渠。"]'),
('f9058cdd-3c84-4625-bccc-7f37a0f92278','第十二九峰丹青頌','釋義青','宋','宋诗','song-poetry','','[]','荆山美玉卞人尋，至寶無瑕絕見因。',32,'全唐诗/poet.song.39000.json','["荆山美玉卞人尋，至寶無瑕絕見因。", "鐵牛带子踏滄海，撞月石龜長羽鱗。"]'),
('64387cdf-d079-4c6e-836f-570e50fe3b11','第十三韶山是非頌','釋義青','宋','宋诗','song-poetry','','[]','白雲不到中峰頂，滿目煙蘿景象殊。',32,'全唐诗/poet.song.39000.json','["白雲不到中峰頂，滿目煙蘿景象殊。", "一句曲寒千古調，萬重青碧月來初。"]'),
('8f29220f-15e4-4f76-853c-3155379d3b3f','第十四粱山祖意頌','釋義青','宋','宋诗','song-poetry','','[]','國令嚴嚴擬者危，毫釐才動鐵輪隨。',32,'全唐诗/poet.song.39000.json','["國令嚴嚴擬者危，毫釐才動鐵輪隨。", "心萌口應三千里，齒露言來苦怨誰。"]'),
