('e6f66455-7dcf-4172-8c49-81daa4b1656d','第八十九北斗藏身頌','釋義青','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南嶽峰高北嶽低，行人泣淚兩遲疑。',32,'全唐诗/poet.song.39000.json','["南嶽峰高北嶽低，行人泣淚兩遲疑。", "火星昨夜移牛斗，照見西瞿人不知。"]'),
('5a289112-2d45-4065-927b-18f70a64e978','第九十鳳樓前頌','釋義青','宋','宋诗','song-poetry','','[]','深宮禁殿隔重闈，簾靜簷楹紫氣垂。',32,'全唐诗/poet.song.39000.json','["深宮禁殿隔重闈，簾靜簷楹紫氣垂。", "苔地不通朝請近，家人指路莫遲疑。"]'),
('59db2805-516f-4d42-9d25-99289434a580','第九十一仰山插鍬頌','釋義青','宋','宋诗','song-poetry','','[]','溈山問處少知音，插地酬時佛祖沉。',32,'全唐诗/poet.song.39000.json','["溈山問處少知音，插地酬時佛祖沉。", "踏倒玄沙傍不肯，免教蒼翠带春深。"]'),
('a3e34b10-c9ec-49f6-8508-18ad6ffb84a9','第九十二法眼慧超頌','釋義青','宋','宋诗','song-poetry','','[]','巇嶮行時問路難，有人相指北村南。',32,'全唐诗/poet.song.39000.json','["巇嶮行時問路難，有人相指北村南。", "長安無限人來往，幾個無鈴遇得關。"]'),
('0c17cfdb-0732-45e3-81d2-2d625a2706c1','第九十三趙州勘婆頌','釋義青','宋','宋诗','song-poetry','','[]','靈龜未兆無凶吉，變動臨時在卜人。',32,'全唐诗/poet.song.39000.json','["靈龜未兆無凶吉，變動臨時在卜人。", "路頭問破誰人委，王老東村努目嗔。"]'),
('7a610a38-aae4-4b74-8260-b57ffc159273','謝王耿太博惠藤床王虞部惠藤枕','魏野','宋','宋诗','song-poetry','','[]','藤床藤枕睡騰騰，軟勝眠莎與曲肱。',33,'全唐诗/poet.song.4000.json','["藤床藤枕睡騰騰，軟勝眠莎與曲肱。", "知似邊韶偏寄惠，夢中長亦感空心朋。"]'),
('1f1c5b02-a26f-481c-901d-016138431200','苔錢八韻','魏野','宋','宋诗','song-poetry','','[]','物外幽奇物，吟看復歎吁。',96,'全唐诗/poet.song.4000.json','["物外幽奇物，吟看復歎吁。", "豪家如可用，窮巷却應無。", "閑共僧贏得，卑嫌俗競呼。", "山疑和雨買，地似带煙租。", "密鎖憐庭竹，深藏恨砌蕪。", "貪多寧損志，嫌少不爲愚。", "良冶何由鑄，常流豈易圖。", "野人唯自愛，難把悅妻孥。"]'),
('7ee5e61d-468d-49fc-8fca-337c25ea6867','題崇勝院河亭','魏野','宋','宋诗','song-poetry','','[]','陝郡衙中寺，亭臨翠靄閒。',48,'全唐诗/poet.song.4000.json','["陝郡衙中寺，亭臨翠靄閒。", "數聲離岸艫，幾點別州山。", "野客猶思住，江鷗亦忘還。", "隔牆歌舞地，喧靜不相關。"]'),
('6dccb977-c281-4993-abfd-6a021ececcd6','送徐道士赴闕','魏野','宋','宋诗','song-poetry','','[]','捧詔異常倫，無官豈累真。',48,'全唐诗/poet.song.4000.json','["捧詔異常倫，無官豈累真。", "瓢知空似性，琴想重於身。", "卧必思雲切，行應待鶴頻。", "林間起相送，漸覺世還淳。"]'),
('879d82cf-0e23-401a-a7d8-a2f495768af3','寄贈藍田王闢寺丞','魏野','宋','宋诗','song-poetry','','[]','藍田名冠古京華，詩匠移風更可誇。',64,'全唐诗/poet.song.4000.json','["藍田名冠古京華，詩匠移風更可誇。", "解使射生人改業，能令逐熟客安家。", "韓文公記存廳壁，王右丞居對縣衙。", "見說偷閑偏往處，悟真寺最好煙霞。"]'),
('f3c27c8e-b913-48b5-b9e7-e52a68d08054','送趙寺簿東歸','魏野','宋','宋诗','song-poetry','','[]','官滿猶如下第貧，軒車迎頼舊田文。',64,'全唐诗/poet.song.4000.json','["官滿猶如下第貧，軒車迎頼舊田文。", "九皋禽畔偏辭我，六出花中獨送君。", "易把當盃唯俗物，難持賮路是溪雲。", "孝終且覓甘棠倅，談笑還圖得再聞。"]'),
('a45cfdad-ccbb-476e-ba65-e4d9c222e464','和寇寺丞夏日遊麗春園','魏野','宋','宋诗','song-poetry','','[]','麗春園甲召公城，池想遊魚恨至清。',64,'全唐诗/poet.song.4000.json','["麗春園甲召公城，池想遊魚恨至清。", "一簇樓臺如畫出，數羣鷗鷺似家生。", "芰荷香裏垂綸坐，楊柳陰中把卷行。", "不領管絃唯靜憩，相門年少有高情。"]'),
('17c31f4b-0491-4cbf-bf77-b43fb01856b3','謝龍圖李待制見寄  其一','魏野','宋','宋诗','song-poetry','','[]','煙霄閑似在煙霞，唯有龍圖學士家。',32,'全唐诗/poet.song.4000.json','["煙霄閑似在煙霞，唯有龍圖學士家。", "和了御詩垂錦帳，卧聽仙樂出宮花。"]'),
('77090503-26e5-4f8d-a57a-e905db7a1dca','謝龍圖李待制見寄  其二','魏野','宋','宋诗','song-poetry','','[]','遥知清貴孰能攀，天上閑勝地上閑。',32,'全唐诗/poet.song.4000.json','["遥知清貴孰能攀，天上閑勝地上閑。", "除對聖君論道外，時題詩句落人間。"]'),
('5a3b8cc1-377a-48c5-bb67-816939ec1fbd','喜岐賁王闈見訪','魏野','宋','宋诗','song-poetry','','[]','久別思方切，同來宿弊廬。',48,'全唐诗/poet.song.4000.json','["久別思方切，同來宿弊廬。", "閑聽一夜話，勝讀十年書。", "拙喜交情在，貧慚主禮疏。", "共嗟高會少，且願更躊躇。"]'),
('aba3bb63-79ad-4270-9741-f97984df3792','謝孫舍人題名水亭因有紀贈','魏野','宋','宋诗','song-poetry','','[]','紫微客寫青苔壁，不與尋常姓字同。',32,'全唐诗/poet.song.4000.json','["紫微客寫青苔壁，不與尋常姓字同。", "多謝溪煙知我意，預先替作碧紗籠。"]'),
('fe03f784-c30b-40ae-af9e-f8efa8cc2032','贈潘閬','魏野','宋','宋诗','song-poetry','','[]','昔賢放志多狂怪，若比今來總未如。',32,'全唐诗/poet.song.4000.json','["昔賢放志多狂怪，若比今來總未如。", "從此華山圖籍上，又添潘閬倒騎馿。"]'),
('2baf5aea-432d-4316-9f09-6c9b28305b11','春日述懷','魏野','宋','宋诗','song-poetry','','[]','春暖出茅亭，携筇傍水行。',48,'全唐诗/poet.song.4000.json','["春暖出茅亭，携筇傍水行。", "易諳馴鹿性，難辨鬭禽情。", "妻喜栽花活，童誇鬭草贏。", "翻嫌我慵拙，不解强謀生。"]'),
('79eceba8-f284-49b0-978a-4b039265db16','同大孫狀元送楊甫之蒲中','魏野','宋','宋诗','song-poetry','','[]','蒲本舜都州，君思獨去遊。',48,'全唐诗/poet.song.4000.json','["蒲本舜都州，君思獨去遊。", "雲分五老頂，河噴二妃樓。", "雨足禾初熟，霜遲葉尚稠。", "此行貧莫歎，飲餞是三頭。"]'),
('7869ad87-e8f9-4f7a-8061-358456577036','送王衢赴舉','魏野','宋','宋诗','song-poetry','','[]','獨薦因公道，孤寒去若何。',48,'全唐诗/poet.song.4000.json','["獨薦因公道，孤寒去若何。", "遥裝行李少，近事祖筵多。", "小雪飄嵩嶽，微冰結汴河。", "歸來乘駟馬，林下願重過。"]'),
('fc970991-56b7-4211-a9a2-4eeb40e4871c','寄贈陳越兼簡臧奎','魏野','宋','宋诗','song-poetry','','[]','君遊帝里共喧喧，我向溪邊獨悄然。',64,'全唐诗/poet.song.4000.json','["君遊帝里共喧喧，我向溪邊獨悄然。", "工部聲華窮委地，翰林風骨醉看天。", "朱門想少投封狀，兩制應多借盛編。", "佇聽彤庭呈試罷，龍頭相讓一人前。"]'),
('d6b3fc01-7534-4dfe-978f-5a88b595a0af','白菊','魏野','宋','宋诗','song-poetry','','[]','濃露繁霜著似無，幾多光彩照庭除。',32,'全唐诗/poet.song.4000.json','["濃露繁霜著似無，幾多光彩照庭除。", "何須更待螢兼雪，便好叢邊夜讀書。"]'),
('f678ec42-fecc-493e-b6d3-48009287651f','四十自詠','魏野','宋','宋诗','song-poetry','','[]','閑心雖不動，記性覺潛衰。',48,'全唐诗/poet.song.4000.json','["閑心雖不動，記性覺潛衰。", "棋退難饒客，琴生却問兒。", "手慵農器信，身散道裝知。", "筆硯將何用，除因改舊詩。"]'),
('f1696df0-0962-4a87-8ac5-700c92604a6b','喜大孫狀元見訪','魏野','宋','宋诗','song-poetry','','[]','道同忘貴賤，陋巷每頻看。',48,'全唐诗/poet.song.4000.json','["道同忘貴賤，陋巷每頻看。", "相見唯呼字，留題不著官。", "狂吟無所忌，靜坐有餘歡。", "却恨歸公署，茅堂會宿難。"]'),
('55a6bf39-dd03-4201-8ebf-73bccbcea284','謝師刑部見召','魏野','宋','宋诗','song-poetry','','[]','錦帳公餘後，紗巾召見初。',48,'全唐诗/poet.song.4000.json','["錦帳公餘後，紗巾召見初。", "一言忻契合，三拜愧生疏。", "漸見詩多拙，方知譽轉虛。", "猶能時遣吏，相問到貧居。"]'),
('f7388510-e1fc-439a-aca7-8871bfb82d31','贈三門漕運錢舍人','魏野','宋','宋诗','song-poetry','','[]','相知有宿緣，一見兩忻然。',48,'全唐诗/poet.song.4000.json','["相知有宿緣，一見兩忻然。", "我拙宜名野，君廉恨姓錢。", "唱酬思閣筆，迎送愧樓船。", "却恐徵歸闕，慵過砥柱邊。"]'),
('518a504c-23b4-48f1-b2fc-63eedf68bbf5','送太白山人俞太中之商於訪道友王知常洎歸故山','魏野','宋','宋诗','song-poetry','','[]','羨我詩中偶有名，輸君物外更無縈。',64,'全唐诗/poet.song.4000.json','["羨我詩中偶有名，輸君物外更無縈。", "水聲山色爲聲色，鶴性雲情是性情。", "四皓雲間尋舊友，三清路上指前程。", "連天太白從今去，林下何時得再迎。"]'),
('32962db6-c661-42e3-b84a-92032cbb23c2','暮秋懷閏師','魏野','宋','宋诗','song-poetry','','[]','風清月白樹紅時，無奈重城隔閏師。',32,'全唐诗/poet.song.4000.json','["風清月白樹紅時，無奈重城隔閏師。", "却羨潺湲階下水，夜深流入白蓮池。"]'),
('c3eb7406-86f9-4d32-98e0-9989c859f186','聞潘閬新授滁州散參因以寄賀','魏野','宋','宋诗','song-poetry','','[]','江鄉去想勝還鄉，官職尋常事不常。',32,'全唐诗/poet.song.4000.json','["江鄉去想勝還鄉，官職尋常事不常。", "會得聖君無別意，只應圖繼賈司倉。"]'),
('2088d1fd-d83f-49b9-9382-8ffb687a83db','送朱台符學士關西巡撫','魏野','宋','宋诗','song-poetry','','["\u534e\u5c71"]','聖主念黎庶，選君來撫綏。',96,'全唐诗/poet.song.4000.json','["聖主念黎庶，選君來撫綏。", "望高虛兩制，權重带三司。", "帝澤隨車布，文星逐郡移。", "語稀如學淺，僕少似官卑。", "疏減民間賦，編添馬上詩。", "經遊憐勝異，迎送厭歌吹。", "寒別申湖晚，晴過華嶽遲。", "瓊林想迴日，未失賞花期。"]'),
('e370b14b-cedc-41ad-80b4-c40f59089b9d','陪喬職方泛舟之三門謁禹祠','魏野','宋','宋诗','song-poetry','','[]','波浪濺旌旗，東浮謁禹祠。',48,'全唐诗/poet.song.4000.json','["波浪濺旌旗，東浮謁禹祠。", "千秋花發日，兩院獄空時。", "城裏閑棠樹，船中舞柘枝。", "晉公曾禊洛，不召野人隨。"]'),
('61011461-3abd-4f38-88d7-4c5673713faf','冬日述懷','魏野','宋','宋诗','song-poetry','','[]','癭枕閑欹葦箔褰，浩然情性雪晴天。',32,'全唐诗/poet.song.4000.json','["癭枕閑欹葦箔褰，浩然情性雪晴天。", "却嫌雛鶴饒聲氣，驚覺茅簷曝背眠。"]'),
('9e7a985c-16cd-4dd3-989a-95dfe0dc04dc','和三門竇寺丞見寄','魏野','宋','宋诗','song-poetry','','[]','風情不獨少人同，滿腹書寧愧郝隆。',64,'全唐诗/poet.song.4000.json','["風情不獨少人同，滿腹書寧愧郝隆。", "職務恰如波正急，輜囊長似獄長空。", "柳藏衙樹侵堤綠，旗插樓船照岸紅。", "見說公餘無一事，題詩多在禹祠中。"]'),
('b25cf53e-ab84-4679-ab9d-1162a8332797','送李主簿之任南陵','魏野','宋','宋诗','song-poetry','','[]','無歎徒勞向宦途，不羣氣岸有誰如。',64,'全唐诗/poet.song.4000.json','["無歎徒勞向宦途，不羣氣岸有誰如。", "南陵暫掌仇香印，北闕終行賈誼書。", "且喜江山尋勝境，莫辭韋杜別幽居。", "少年躍馬同星使，免得詩中道跨馿。"]'),
('5f73b089-4a58-4873-ae19-dbfc4c3f3a93','酬王太博見寄','魏野','宋','宋诗','song-poetry','','[]','錦川誰爲寄陽春，清浄堂中清浄人。',32,'全唐诗/poet.song.4000.json','["錦川誰爲寄陽春，清浄堂中清浄人。", "二十八言刊石處，長如列宿照閑身。"]'),
('fa564f47-8275-4e24-82b8-1f739f01dfe2','題閏師禪庭雙竹','魏野','宋','宋诗','song-poetry','','[]','離叢並長對禪扃，乍見翻疑是一莖。',32,'全唐诗/poet.song.4000.json','["離叢並長對禪扃，乍見翻疑是一莖。", "我恨與師居隔郭，他生願似此君生。"]'),
('312e2556-f304-4214-ac43-8f1a6c32bc59','謝喬職方惠山菜','魏野','宋','宋诗','song-poetry','','[]','山菜尋常見眼明，使君偏賜況新生。',64,'全唐诗/poet.song.4000.json','["山菜尋常見眼明，使君偏賜況新生。", "野人屈指皆知性，老圃從頭不識名。", "五鼎減來爲異味，一簞添出稱閑情。", "兒童笑道真嘉饌，詩思因餐覺轉清。"]'),
('dc86a8c8-a89b-4e5d-a6d8-9d71612c35ea','送丕上人南遊','魏野','宋','宋诗','song-poetry','','[]','江山獨去遊，遊遍始應休。',48,'全唐诗/poet.song.4000.json','["江山獨去遊，遊遍始應休。", "雲外敲清磬，船中剃白頭。", "阻風孤島晚，聽雨二林秋。", "南國多嘉境，詩牌幾處留。"]'),
('aa5e216b-3a3e-4100-a26d-96a36be95f2a','和王衢見寄','魏野','宋','宋诗','song-poetry','','[]','久向東郊住，漸同麋鹿情。',96,'全唐诗/poet.song.4000.json','["久向東郊住，漸同麋鹿情。", "遊山岐路熟，見寄禮儀生。", "藜杖新仍重，荷衣破轉輕。", "身猶爲外物，詩亦是虛名。", "自愛閑無敵，誰憂道未行。", "絕疑疏日者，相許愧時英。", "窮易憐無著，圍棋惡有爭。", "唯應心友至，林下笑相迎。"]'),
('9858628a-5d0a-4146-9f44-e4d1bd78734f','送師刑部赴闕','魏野','宋','宋诗','song-poetry','','[]','白首休嗟嘆，君方任老臣。',96,'全唐诗/poet.song.4000.json','["白首休嗟嘆，君方任老臣。", "鳳書纔入手，鵲印喜離身。", "錦帳眠來舊，花磚步去新。", "離情棠樹曉，吟思洛陽春。", "御札催應併，天文動已頻。", "拜迎臺有吏，泣送巷無人。", "寺宿知題壁，山行想駐輪。", "從茲歸近密，閑謁轉無因。"]'),
('638648dc-0b47-4c34-8e46-7d52ba60514d','河中孫學士以詩見寄因次本韻繼和三章用爲酬贈  其一','魏野','宋','宋诗','song-poetry','','[]','表裏山河舜帝基，聖君館殿選賢知。',64,'全唐诗/poet.song.4000.json','["表裏山河舜帝基，聖君館殿選賢知。", "開筵想任佳人擁，遊寺應嫌俗吏隨。", "政訝龔黄推絕席，文疑元白豎降旗。", "逍遥樓逈閑登處，幾感皇唐御製詩。"]'),
('a9545616-7b79-4453-b4cb-606387cb7f7b','河中孫學士以詩見寄因次本韻繼和三章用爲酬贈  其二','魏野','宋','宋诗','song-poetry','','[]','入居蘭省歸羣望，出守薄關自聖知。',64,'全唐诗/poet.song.4000.json','["入居蘭省歸羣望，出守薄關自聖知。", "清禁乍辭仙漏遠，白樓閑上彩牋隨。", "伯夷廟下停金勒，大舜門中亞繡旗。", "遥想雄藩多少境，祇應公暇遍留詩。"]'),
('b7c8adf9-d047-4b02-a994-7f64c2fe4b27','河中孫學士以詩見寄因次本韻繼和三章用爲酬贈  其三','魏野','宋','宋诗','song-poetry','','[]','山前衙署枕河湄，遂意榮居事可知。',64,'全唐诗/poet.song.4000.json','["山前衙署枕河湄，遂意榮居事可知。", "華省圖書雖暫別，故鄉風物似相隨。", "遶城奔浪喧更鼓，隔岸征帆映酒旗。", "刻石將同王閣長，永留遺愛向歌詩。"]'),
('d31e7591-a366-4cea-9a93-2a91342e7f3e','送劉法曹東歸','魏野','宋','宋诗','song-poetry','','[]','上官多是嘆窮途，得替行裝盡有餘。',32,'全唐诗/poet.song.4000.json','["上官多是嘆窮途，得替行裝盡有餘。", "唯有甘棠劉法掾，來時騎馬去騎馿。"]'),
('18ca1d58-9d14-4134-a889-1902b9888623','贈惠崇上人','魏野','宋','宋诗','song-poetry','','[]','張籍眼昏心不昧，崇師耳聵性還聰。',32,'全唐诗/poet.song.4000.json','["張籍眼昏心不昧，崇師耳聵性還聰。", "是非言語徒喧世，贏得長如在定中。"]'),
('352be1e6-866e-4efe-b723-cd04fc0f340a','送臧奎赴舉','魏野','宋','宋诗','song-poetry','','[]','艱難天府解，去掇喜還悲。',96,'全唐诗/poet.song.4000.json','["艱難天府解，去掇喜還悲。", "舊相和文薦，偏親带病辭。", "劍如機不用，琴似影相隨。", "僕爲初招戇，馿因賤買羸。", "窮途誰惻隠，貧卷自裝褫。", "餞送重陽後，榮歸上巳時。", "淚多同永別，酒少若輕離。", "又使林中客，從今役所思。"]'),
('f07b92bd-f29b-425b-8ff3-6491d96b9e65','贈潁陽知縣劉燁著作','魏野','宋','宋诗','song-poetry','','[]','門風是相門，積慶豈須論。',48,'全唐诗/poet.song.4000.json','["門風是相門，積慶豈須論。", "祖德書儀在，科名榜貼存。", "政聲聞牧豎，墨跡見花村。", "物論將徵用，多應入諫垣。"]'),
('b9be24e6-4bd8-4abe-807c-54acca2e63dc','聞張師德狀元登第因以寄賀兼呈梁固狀元','魏野','宋','宋诗','song-poetry','','[]','科場消息到柴扉，皇宋風流事可知。',32,'全唐诗/poet.song.4000.json','["科場消息到柴扉，皇宋風流事可知。", "封禪汾陰連歲榜，狀元俱是狀元兒。"]'),
('38484cc3-0da2-45b5-9751-c122e1435b61','寄贈河中表兄李瀆','魏野','宋','宋诗','song-poetry','','[]','早年聲譽壓羣公，恥與浮華鬭競同。',64,'全唐诗/poet.song.4000.json','["早年聲譽壓羣公，恥與浮華鬭競同。", "似我枉教縻好爵，如君方信是冥鴻。", "軒車少見權門下，圖籍多於祕閣中。", "豈獨聖朝無賀監，退藏自怯達堯聰。"]'),
('7f305ee9-d56b-413a-b37f-6e6a824240ca','和并州劉密學見寄','魏野','宋','宋诗','song-poetry','','[]','還如裴度鎮河東，百萬軍民畏愛中。',64,'全唐诗/poet.song.4000.json','["還如裴度鎮河東，百萬軍民畏愛中。", "鍾鼓久喧刁斗靜，旌幢一指鴈門空。", "瀟湘故友參時務，燕趙佳人接土風。", "密地再歸知不出，莫將竹馬約童蒙。"]'),
('6219afce-39bc-44a5-ac40-a2c1b1fe14e7','寄贈三門漕運卞寺丞二首  其一','魏野','宋','宋诗','song-poetry','','[]','威權自與轉輸同，僕從衙庭事事雄。',64,'全唐诗/poet.song.4000.json','["威權自與轉輸同，僕從衙庭事事雄。", "十郡山河關職務，一門忠孝是家風。", "圖書半在仙舟裏，碑板多留禹廟中。", "閑想春堤遊賞處，桃花浪照舞筵紅。"]'),
('1070cc85-4a31-4e6b-86d4-656f7b794b7f','寄贈三門漕運卞寺丞二首  其二','魏野','宋','宋诗','song-poetry','','[]','三門閑想六龍家，多少春來事可誇。',64,'全唐诗/poet.song.4000.json','["三門閑想六龍家，多少春來事可誇。", "閣道尋僧同鷲嶺，樓船載妓勝仙槎。", "送迎幾拂新亭柳，巡歷時穿舊縣花。", "野客尋常思重謁，却愁詩酒勢難加。"]'),
('1477e836-dce0-4665-af78-c170f8c8d0e0','檉師告歸廬岳贈之筇杖','魏野','宋','宋诗','song-poetry','','[]','瘦筇生本接西蠻，我已携來二十年。',32,'全唐诗/poet.song.4000.json','["瘦筇生本接西蠻，我已携來二十年。", "輟贈檉師歸老處，稱將吟倚虎溪邊。"]'),
('a828b256-39b1-4a59-a0ab-b8a460abb93d','聞王衢王專下第因有所感','魏野','宋','宋诗','song-poetry','','[]','忽見僧來說，千愁集病顔。',48,'全唐诗/poet.song.4000.json','["忽見僧來說，千愁集病顔。", "聞君俱下第，使我轉思山。", "疑欲鑽龜卜，窮應嘆雉還。", "此懷何處寫，月上太虛閒。"]'),
('b7e9b6aa-b14c-49c4-a793-cd4077f39531','送臧奎之寧州謁韓使君','魏野','宋','宋诗','song-poetry','','[]','路遠邠郊外，嚴冬去若何。',48,'全唐诗/poet.song.4000.json','["路遠邠郊外，嚴冬去若何。", "時平防賊少，山險下馿多。", "塞色晴猶慘，蕃音譯尚訛。", "賢侯雖禮待，陟屺願頻歌。"]'),
('e1fd2c6d-5169-49df-a6f4-0b7e86ccde81','贈長安知縣陳堯佐','魏野','宋','宋诗','song-poetry','','[]','少作長安宰，尋常似隠夫。',72,'全唐诗/poet.song.4000.json','["少作長安宰，尋常似隠夫。", "琴書家慣有，杖印客疑無。", "錦水心雖役，圭峰眼不辜。", "閑簽歸業狀，貧典舊山圖。", "酒爲廉猶斷，棋因讓忽輸。", "即看聯鴈序，相繼在蓬壺。"]'),
('9dad7a18-2953-47f9-a912-5329b9177689','上致仕趙中令','魏野','宋','宋诗','song-poetry','','[]','王業致艱難，功成退自安。',48,'全唐诗/poet.song.4000.json','["王業致艱難，功成退自安。", "閑中猶有俸，品外更無官。", "洛水垂簾聽，嵩峰憑几看。", "唯應問安詔，時復到門闌。"]'),
('3d42be40-8d59-42a6-ba4c-1c5550cb5f3b','題高都監新亭','魏野','宋','宋诗','song-poetry','','[]','高氏創高亭，亭因地得名。',72,'全唐诗/poet.song.4000.json','["高氏創高亭，亭因地得名。", "半空雲咫尺，百里鏡分明。", "襟带山圍陝，咽喉地接京。", "晝閑多待士，時靜少論兵。", "鍾磬聞蓮舍，槍旗見柳營。", "吾廬正相望，不似在重城。"]'),
('26cbee34-5c10-4e75-a3ff-3ceb8204c640','上左馮陳使君','魏野','宋','宋诗','song-poetry','','[]','祖德相門闌，分符衆比難。',144,'全唐诗/poet.song.4000.json','["祖德相門闌，分符衆比難。", "憂民如有病，見客似無官。", "地鎮三秦重，衙當二華寒。", "道心輕仗鉞，詩性鄙登壇。", "佐幕多名士，開筵少俗歡。", "星連蒲分野，河带渭波瀾。", "勸課耕初動，行香漏未殘。", "書容吾道借，琴聽越僧彈。", "拜敕風鳴珮，朝元露溼冠。", "皇恩終錫馬，清夢必驂鸞。", "報國嫌言利，脩真笑鍊丹。", "高碑人待立，此詠願同刊。"]'),
('86181fb7-e5c6-4031-ad7f-5dad56751195','謝孫狀元寒食見贈','魏野','宋','宋诗','song-poetry','','[]','一首狀元詩，封來到竹扉。',48,'全唐诗/poet.song.4000.json','["一首狀元詩，封來到竹扉。", "讀留寒食燭，拜換道家衣。", "譽過心無愧，酬遲禮轉非。", "閑思播琴裏，誰更會玄微。"]'),
('28bee8f1-a8cc-47a0-b106-e7f07c403828','送馬共之任內江縣尉兼主簿','魏野','宋','宋诗','song-poetry','','[]','馿上吟詩賈島同，內江歸去指江東。',64,'全唐诗/poet.song.4000.json','["馿上吟詩賈島同，內江歸去指江東。", "封疆半在猿聲裏，道路多穿竹箐中。", "想得兩衙長鎖印，應過三載不張弓。", "重登制策高科在，筆硯公餘莫廢功。"]'),
('8f98ff72-22ea-43c7-a12f-2735de3f205d','送喬職方赴闕','魏野','宋','宋诗','song-poetry','','[]','一種徵書下九重，漢唐賢士豈能同。',64,'全唐诗/poet.song.4000.json','["一種徵書下九重，漢唐賢士豈能同。", "定歸金馬殊黄散，不解銀魚勝白公。", "千騎擁行歧路滿，萬人泣送郡城空。", "他時若繼前交代，肯意棠郊鶴髮翁。"]'),
('306db8d8-77e4-4a4e-98d3-dec97a1a7b5b','喬職方將赴闕詔領河東轉輸再成長句送之','魏野','宋','宋诗','song-poetry','','[]','河東控塞詔通儒，二十餘州繫慘舒。',64,'全唐诗/poet.song.4000.json','["河東控塞詔通儒，二十餘州繫慘舒。", "位列九天應自致，權除兩地更誰如。", "薦賢表想慇懃發，詠物詩應取次書。", "不爲龍鍾頭半白，好拋泉石從軒車。"]'),
('b7efdc4a-1e8e-499f-a1f8-bbd178448000','留題滻川姚氏鳴琴泉','魏野','宋','宋诗','song-poetry','','[]','琴裏休誇石上泉，爭如此處聽潺湲。',32,'全唐诗/poet.song.4000.json','["琴裏休誇石上泉，爭如此處聽潺湲。", "愛於琴裏無他意，落砌聲聲是自然。"]'),
('fc9548c7-28a4-4228-a4c3-a88587bbf089','將離藍田同王闢太博飲於王氏亭聯成二韻  其一','魏野','宋','宋诗','song-poetry','','[]','白鹿原東滻水西，楊花漠漠草萋萋。',16,'全唐诗/poet.song.4000.json','["白鹿原東滻水西，楊花漠漠草萋萋。"]'),
('c5ffd250-0c69-4338-a0bf-1a9fc2c04b4d','將離藍田同王闢太博飲於王氏亭聯成二韻  其二','魏野','宋','宋诗','song-poetry','','[]','那堪對此還醒別，況是醍醐鳥正啼。',16,'全唐诗/poet.song.4000.json','["那堪對此還醒別，況是醍醐鳥正啼。"]'),
('4a41a473-cef3-48af-ae99-6f790d650aa8','謝馮亞惠鶴','魏野','宋','宋诗','song-poetry','','[]','慇懃親惠鶴，迢遞自江濆。',48,'全唐诗/poet.song.4000.json','["慇懃親惠鶴，迢遞自江濆。", "情性渾如我，精神酷似君。", "舞思同座看，唳想隔城聞。", "從此添詩景，爲題好共分。"]'),
('341e8e2a-88dd-4ed5-8a57-418b4d758ae8','送元上人歸寧','魏野','宋','宋诗','song-poetry','','[]','禪性雖無著，偏親奈白頭。',48,'全唐诗/poet.song.4000.json','["禪性雖無著，偏親奈白頭。", "直應飛錫到，方是倚門休。", "雪裏猶思去，花前豈易留。", "如何迎侍得，住近免離愁。"]'),
('767f708c-8250-4067-a9e4-c4aa9ee573fe','詠懷','魏野','宋','宋诗','song-poetry','','[]','靜顧身兼世，何須哂復吁。',48,'全唐诗/poet.song.4000.json','["靜顧身兼世，何須哂復吁。", "境牽情各有，道斷事皆無。", "拜少腰寧負，眠多眼不辜。", "權豪任相笑，適性自爲娛。"]'),
('eb93765f-45c6-4401-9417-3fe7409ad92b','酬謝商祕丞見贈詩牌','魏野','宋','宋诗','song-poetry','','[]','初得春方暖，今來歲已闌。',48,'全唐诗/poet.song.4000.json','["初得春方暖，今來歲已闌。", "紫泥辭却易，白雪和終難。", "頻拂心寧倦，時吟齒覺寒。", "會須親謝去，閑拄折魚竿。"]'),
('0d7147d5-1142-451a-a0be-f65a6fd0f57f','和長安孫舍人見寄','魏野','宋','宋诗','song-poetry','','[]','長安君到轉民安，夏少炎蒸臘少寒。',64,'全唐诗/poet.song.4000.json','["長安君到轉民安，夏少炎蒸臘少寒。", "接使管絃登月榭，勸農旌旆入煙巒。", "龍池似錦花堪賞，鶉野如雲稼好觀。", "見說添蘇亞蘇小，隨軒應是珮珊珊。"]'),
('f1b0f14c-52cc-4558-afe9-b5981090cb6f','謝喬職方惠書','魏野','宋','宋诗','song-poetry','','[]','珍重君郎一紙書，親書何啻敵瓊琚。',64,'全唐诗/poet.song.4000.json','["珍重君郎一紙書，親書何啻敵瓊琚。", "便迴豈易逢歸鴈，頻看應難長蠹魚。", "先寄路經千里外，後批情更萬重餘。", "靜思貴不忘貧賤，當日荆州亦未如。"]'),
('db983374-df70-432f-8d53-457023e648e6','送陳越之河中寧覲','魏野','宋','宋诗','song-poetry','','[]','寧覲高堂舜井西，欲辭東閤思依依。',96,'全唐诗/poet.song.4000.json','["寧覲高堂舜井西，欲辭東閤思依依。", "三台筵上飛觴送，五老峰前負米歸。", "莫嘆貴無蘇子印，且憐榮有老萊衣。", "舊書達少應投杼，新集鎸多肯斷機。", "紅葉村坊臨水迥，黄花岐路入山微。", "重陽雖近難留住，把酒登高會又違。"]'),
('8eee1148-6da4-43e6-9c76-2195b57763fc','太保瑯琊相公見惠酒因成二絕用爲紀謝  其一','魏野','宋','宋诗','song-poetry','','[]','從前相輔皆頻出，獨在中書十五秋。',32,'全唐诗/poet.song.4000.json','["從前相輔皆頻出，獨在中書十五秋。", "太嶽汾陰封祀了，這迴好共赤松遊。"]'),
('18ecba96-cf5d-4dd8-8418-d053d0680582','太保瑯琊相公見惠酒因成二絕用爲紀謝  其二','魏野','宋','宋诗','song-poetry','','[]','玉液定從金口輟，曹樽分又到顔瓢。',32,'全唐诗/poet.song.4000.json','["玉液定從金口輟，曹樽分又到顔瓢。", "雖無愁悶憑銷處，麴糵恩濃豈易銷。"]'),
('ea8998d9-d181-4c60-98a9-9ff388302157','冬暮郊居','魏野','宋','宋诗','song-poetry','','[]','村落欲黄昏，寒雲片片凝。',48,'全唐诗/poet.song.4000.json','["村落欲黄昏，寒雲片片凝。", "隔城鐘似磬，遠岫燒如燈。", "名利堪彈指，林泉但枕肱。", "何由遂閑散，自喜本無能。"]'),
('8b99a712-a0b1-42e7-bb79-9be4dda5dd84','送俞極山人歸太華','魏野','宋','宋诗','song-poetry','','[]','三峰倚太虛，四嶽境難如。',48,'全唐诗/poet.song.4000.json','["三峰倚太虛，四嶽境難如。", "雲向中方起，人歸絕頂居。", "道全忘世態，詩必答天書。", "不待辭榮去，還應笑二疏。"]'),
('5570dda6-b3f4-4a4d-b37d-cd9d23e467d3','謝長安孫舍人寄惠蜀牋并茶二首  其一','魏野','宋','宋诗','song-poetry','','[]','彩牋一軸敵瓊瑰，喜見親題手自開。',64,'全唐诗/poet.song.4000.json','["彩牋一軸敵瓊瑰，喜見親題手自開。", "遠勝浣花人寄到，貴從視草客分來。", "百張重疊霞初卷，十色參差錦乍裁。", "紅藥篇章方雅稱，老夫無用擬封迴。"]'),
('0e6b1042-f612-4571-90dc-10c6e048a7f7','謝長安孫舍人寄惠蜀牋并茶二首  其二','魏野','宋','宋诗','song-poetry','','[]','誰將新茗寄柴扉，京兆孫家小紫微。',64,'全唐诗/poet.song.4000.json','["誰將新茗寄柴扉，京兆孫家小紫微。", "鼎是舒州烹始稱，甌除越國貯皆非。", "盧仝詩裏功堪比，陸羽經中法可依。", "不敢頻嘗無別意，却嫌睡少夢君稀。"]'),
('8134fe6a-21ff-47f7-a47b-dd7f03e80365','和進士田亞夫見贈','魏野','宋','宋诗','song-poetry','','[]','失意人方羨野人，因酬嘉句謝知聞。',64,'全唐诗/poet.song.4000.json','["失意人方羨野人，因酬嘉句謝知聞。", "都緣月桂終難捨，豈是煙蘿不肯分。", "且縱高情歌白雪，莫嗟下第負青雲。", "孤寒自古功成晚，那獨昌朝只有君。"]'),
('b256aab6-cd27-4509-bde0-339a9f1ac339','寄題石都尉林亭','魏野','宋','宋诗','song-poetry','','[]','園林都尉宅，景好冠京華。',48,'全唐诗/poet.song.4000.json','["園林都尉宅，景好冠京華。", "便合名金谷，其如是石家。", "池塘分御水，樓閣見宮花。", "有客因來說，令人動嘆嗟。"]'),
('148a7557-2426-4459-98eb-81d40da74125','謝潘閬寄惠白雞','魏野','宋','宋诗','song-poetry','','[]','遠惠雞同雪，應圖警卧雲。',48,'全唐诗/poet.song.4000.json','["遠惠雞同雪，應圖警卧雲。", "如君鳴有信，似我素無文。", "映樹迷蟾彩，臨流雜鷺羣。", "朝昏何所恨，不共隔籬聞。"]'),
('ac06b5c4-862b-4f1a-810c-dd0886c02b11','夏日書事','魏野','宋','宋诗','song-poetry','','[]','尋常苦出門，況復在炎蒸。',48,'全唐诗/poet.song.4000.json','["尋常苦出門，況復在炎蒸。", "短褐披猶懶，長裾曳豈能。", "松風輕賜扇，石井勝頒冰。", "只此貧無事，常愁不易勝。"]'),
('b270156c-5c5e-4922-93cf-3fa429a2b707','寄贈長安宋澥逸人十韻','魏野','宋','宋诗','song-poetry','','[]','家盛翻嘉遁，誰同物外情。',120,'全唐诗/poet.song.4000.json','["家盛翻嘉遁，誰同物外情。", "徵君爲密友，內翰是難兄。", "靜論儒宗服，狂歌俠少驚。", "道裝輕紫綬，酒旆勝紅旌。", "將相慵趨謁，漁樵喜送迎。", "門開紫閣色，歌枕漕河聲。", "野鶴聽調瑟，沙鷗看濯纓。", "煙霞連杜曲，桑柘接昆明。", "丹訣皆親寫，芝田忽自耕。", "終須盡室去，相並掩柴荆。"]'),
('fb1f6d6f-2a83-4e7b-895d-2a0900c1f220','和陳推官暮春感興','魏野','宋','宋诗','song-poetry','','[]','角冠閑戴任欹斜，騎馬人稀到我家。',64,'全唐诗/poet.song.4000.json','["角冠閑戴任欹斜，騎馬人稀到我家。", "僧體盤餐唯筍味，道情欄檻只松花。", "驚迴馴鹿林閒犬，聒殺靈龜雨後蛙。", "春去尋常何足歎，自將寂寞並繁華。"]'),
('d611bdd0-ad87-4b80-9cfb-b483a783a8e1','和河中孫諫議見送同薛田察院之龍門謁劉燁大著','魏野','宋','宋诗','song-poetry','','[]','閑憶披雲輟卧雲，盡驚獬豸鹿同羣。',64,'全唐诗/poet.song.4000.json','["閑憶披雲輟卧雲，盡驚獬豸鹿同羣。", "舜耕山下辭廉使，禹鑿門前謁宰君。", "莫訝樓臺拋接武，却愁泉石動移文。", "花時離別尤堪惜，頭白三分欲二分。"]'),
('8cd0da9c-8ee0-4d7d-8208-b94898ebd2cc','登原州城呈張蕡從事','魏野','宋','宋诗','song-poetry','','[]','異鄉何處最牽愁，獨上邊城城上樓。',64,'全唐诗/poet.song.4000.json','["異鄉何處最牽愁，獨上邊城城上樓。", "日暮北來唯有鴈，地寒西去更無州。", "數聲塞角高還咽，一派涇河凍不流。", "君作貧官我爲客，此中離恨共難收。"]'),
('55cc8223-7edb-4fbe-8e81-28777f935aa3','送長安趙侍郎赴闕','魏野','宋','宋诗','song-poetry','','[]','嗣君徵舊相，物論更無餘。',120,'全唐诗/poet.song.4000.json','["嗣君徵舊相，物論更無餘。", "聖日歸黄閣，台星正碧虛。", "四方聞樂只，一郡泣漣如。", "灞水猶疑噎，秦雲亦不舒。", "綺羅圍祖席，朱紫擁征車。", "從樂時調瑟，行厨忽饌蔬。", "先牌唯選寺，遞鋪只擔書。", "古道禾殘後，長亭木落初。", "朝官逢下馬，野客送騎馿。", "從此門尤峻，何由再曳裾。"]'),
('a0567a1b-45de-4193-9ddf-6de3d97e9ba8','白鷴  其一','魏野','宋','宋诗','song-poetry','','[]','萬里南禽未說珍，且論得處到來因。',32,'全唐诗/poet.song.4000.json','["萬里南禽未說珍，且論得處到來因。", "尚書遠託誰相寄，制策登科第一人。"]'),
('5a24fd62-8a33-49cd-bab0-4a6147bd8c5b','白鷴  其二','魏野','宋','宋诗','song-poetry','','[]','山雞形狀鶴精神，紋似漣漪動白蘋。',32,'全唐诗/poet.song.4000.json','["山雞形狀鶴精神，紋似漣漪動白蘋。", "物異恩殊堪鄭重，廟堂人寄草堂人。"]'),
('bdddcd27-97da-4f31-aa4b-a15e085e8e99','白鷴  其三','魏野','宋','宋诗','song-poetry','','[]','水國籠來到水村，也應懷土也懷恩。',32,'全唐诗/poet.song.4000.json','["水國籠來到水村，也應懷土也懷恩。", "曾爲閑客還同我，今日俱遥舊相門。"]'),
('1caf4847-7263-4921-9511-6fdae0500692','白鷴  其四','魏野','宋','宋诗','song-poetry','','[]','李白詩中聞未識，謝莊賦裏見長思。',32,'全唐诗/poet.song.4000.json','["李白詩中聞未識，謝莊賦裏見長思。", "今朝得爾心雖喜，致謝慚無吐鳳詩。"]'),
('ced53e0a-2edb-4287-9c28-8c93f4213ffc','送王闢赴舉','魏野','宋','宋诗','song-poetry','','[]','何必問龜長，知音在玉堂。',48,'全唐诗/poet.song.4000.json','["何必問龜長，知音在玉堂。", "十全才衆許，雙美卷親裝。", "雲少離山驛，塵多近帝鄉。", "花時新榜帖，先爲達巖房。"]'),
('5eaa8869-a1a6-4ad1-a7b8-d43199ed5d04','知玄武縣薛祕丞繼示手書因以謝','魏野','宋','宋诗','song-poetry','','[]','至交忘貴賤，豈可與常論。',48,'全唐诗/poet.song.4000.json','["至交忘貴賤，豈可與常論。", "少似君書札，多於我夢魂。", "楊岐從蜀邑，雁遞到煙村。", "倒篋時將讀，誰言我眼昏。"]'),
('5baedfff-9cee-4540-bcc6-415ecba3c9e9','秋霽草堂閑望','魏野','宋','宋诗','song-poetry','','[]','草堂高逈勝危樓，時節殘陽向晚秋。',64,'全唐诗/poet.song.4000.json','["草堂高逈勝危樓，時節殘陽向晚秋。", "野色青黄禾半熟，雲容黑白雨初收。", "依依永巷聞村笛，隠隠長河認客舟。", "正是詩家好風景，懶隨前哲却悲愁。"]'),
('293fc7a8-b595-47c8-82d4-83d1b594d3c6','和孫舍人重過陝下二首  其一','魏野','宋','宋诗','song-poetry','','[]','二陝重過一紀强，麻衣已變椹袍光。',64,'全唐诗/poet.song.4000.json','["二陝重過一紀强，麻衣已變椹袍光。", "數宵黄閤延三字，幾處青樓認五郎。", "顧我豈能誇舌在，逢君寧復嘆脣亡。", "大龍頭喪同傷處，吏隠亭欹鄭谷傍。"]'),
('56a8a6ce-6605-468d-bcea-f1bf4c61dcc5','和孫舍人重過陝下二首  其二','魏野','宋','宋诗','song-poetry','','[]','一種分符兩種榮，朱衣院吏引紅旌。',64,'全唐诗/poet.song.4000.json','["一種分符兩種榮，朱衣院吏引紅旌。", "全家首赴酇侯鎮，半路重過召伯城。", "迎步綺羅無舊態，隨軒絲竹有新聲。", "野人相見忻還愧，爲愛交情似世情。"]'),
('3fe010a6-96e8-4ed0-b14d-5a54f60606a6','酬閏師見贈','魏野','宋','宋诗','song-poetry','','[]','絕唱知難繼，因茲久滯淹。',48,'全唐诗/poet.song.4000.json','["絕唱知難繼，因茲久滯淹。", "隔年酬不得，終日誦無厭。", "曬曝偏防蠹，收藏別著簽。", "偶吟聊報謝，遲拙莫相嫌。"]'),
('2aaf8415-8432-4692-87ea-4c409d6ae57f','乞牋紙寄犀浦王專著作','魏野','宋','宋诗','song-poetry','','[]','故人何處暫驅雞，犀浦封疆濯錦西。',32,'全唐诗/poet.song.4000.json','["故人何處暫驅雞，犀浦封疆濯錦西。", "五色彩牋宜寄惠，知君管得浣花溪。"]'),
('0badd445-b5fd-4106-999b-4c7f3e061720','送王遷歸青社','魏野','宋','宋诗','song-poetry','','[]','此別重傷情，寒天二十程。',48,'全唐诗/poet.song.4000.json','["此別重傷情，寒天二十程。", "弟分微祿送，兒逐蹇驢行。", "雪蔽千山色，冰含萬水聲。", "何時再相見，去去海邊城。"]'),
('c42e5c29-2e5d-4f8f-92a2-cda5e274ec24','送諤師赴王寺丞召寫碑','魏野','宋','宋诗','song-poetry','','[]','才高吐鳳欺黄絹，墨妙迴鸞命碧雲。',32,'全唐诗/poet.song.4000.json','["才高吐鳳欺黄絹，墨妙迴鸞命碧雲。", "雙美便堪傳萬古，羲之書法退之文。"]'),
('3c720403-6fcb-4c58-9e00-55d6b7819085','寄用晦上人','魏野','宋','宋诗','song-poetry','','[]','帝里如何忘舊山，却因知己得名賢。',64,'全唐诗/poet.song.4000.json','["帝里如何忘舊山，却因知己得名賢。", "司倉道合唯無可，吏部交遊祇大顛。", "紫色袈裟無蕙带，清齋襯施有苔錢。", "詩中琴裏偏相憶，用晦還應信仲先。"]'),
('2622ed84-dfb1-47dd-bfce-27ec60bf069d','和三門竇程寺丞見贈','魏野','宋','宋诗','song-poetry','','[]','禹門分署似仙居，誰羨同年在直廬。',64,'全唐诗/poet.song.4000.json','["禹門分署似仙居，誰羨同年在直廬。", "閑製曲教鴉角唱，醉吟詩遣鳳毛書。", "蒙過村巷驚玄豹，命踏廳階上白馿。", "莫訝此篇酬更晚，只緣思澀豈情疏。"]'),
('425b7ddf-7e52-458c-94fe-387f5e53801b','同閏師宿三門開化院二首  其一','魏野','宋','宋诗','song-poetry','','[]','白蓮社主碧溪人，同宿三門寺裏雲。',32,'全唐诗/poet.song.4000.json','["白蓮社主碧溪人，同宿三門寺裏雲。", "四面濤聲秋更怒，並床猶恐話難聞。"]'),
('851de176-3169-4b05-afef-da1c90506520','同閏師宿三門開化院二首  其二','魏野','宋','宋诗','song-poetry','','[]','瘦筇輕錫共携遊，砥柱峰前宿寺樓。',32,'全唐诗/poet.song.4000.json','["瘦筇輕錫共携遊，砥柱峰前宿寺樓。", "各有溪居懶歸去，經旬不是兩相留。"]'),
('01f39a9b-2b07-452d-807a-89e60900300b','寄題洪州華林胡氏書齋','魏野','宋','宋诗','song-poetry','','[]','江僧昨日到茅齋，曾向華林挂錫來。',32,'全唐诗/poet.song.4000.json','["江僧昨日到茅齋，曾向華林挂錫來。", "因說胡家宗族盛，御書樓對義門臺。"]'),
('ad2d0a06-3324-4490-8ab3-ab484c425315','上解梁潘學士十韻','魏野','宋','宋诗','song-poetry','','[]','盡繼祖風流，其如髩未秋。',120,'全唐诗/poet.song.4000.json','["盡繼祖風流，其如髩未秋。", "石渠陳表讓，山郡折資求。", "舜禹城分界，神仙嶽映樓。", "淫祠隨處毀，學校逐鄉修。", "密疏多親寫，狂詩少自收。", "通宵營有樂，度歲獄無囚。", "酒席圍紅粉，鹽池照碧油。", "藥同方士煉，壺共野僧投。", "瓦礫今徒獻，瓊瑶舊未酬。", "幾多懷抱事，欲去復遲留。"]'),
('06538a48-dca6-4c68-b3da-21900b55902e','寄逸人陳孟','魏野','宋','宋诗','song-poetry','','[]','姑射山前住，朝昏事若何。',48,'全唐诗/poet.song.4000.json','["姑射山前住，朝昏事若何。", "爐消文火疾，琴斷武弦多。", "絕粒身彌健，酬杯性轉和。", "相思與僧約，春暖杖藜過。"]'),
('27775ca5-d41b-4fed-92e5-8d44e3759254','詠懷','魏野','宋','宋诗','song-poetry','','[]','道心雖博愛，遇物忽難兼。',48,'全唐诗/poet.song.4000.json','["道心雖博愛，遇物忽難兼。", "樹更因巢惜，雲曾爲月嫌。", "酒中寧有感，詩裏覺無厭。", "漸老成何事，疏慵病轉添。"]'),
('706e4ddd-63e9-468d-bb7b-560c94ede196','贈安邑知縣方寺丞','魏野','宋','宋诗','song-poetry','','[]','尋常少往還，門靜似居山。',48,'全唐诗/poet.song.4000.json','["尋常少往還，門靜似居山。", "書爲傳家秘，琴因國忌閑。", "坐衙更鶴氅，行樂到禪關。", "約我休官後，鄰居竹樹間。"]'),
('100dd47e-0647-4c25-b852-d72463284884','嵩嶽十四韻','魏野','宋','宋诗','song-poetry','','[]','東西南北嶽，峻極盡難羣。',168,'全唐诗/poet.song.4000.json','["東西南北嶽，峻極盡難羣。", "有感生賢相，無偏像聖君。", "四方觀玉像，萬壑絕妖氛。", "影入周公側，聲曾漢后聞。", "民居依巨蔭，敕祭答殊勳。", "洞府高低接，都城左右分。", "烟浮巢父水，嵐濕許由墳。", "頂闊星難轉，巖高日易曛。", "薜蘿藏隠逸，瀑布濺耕耘。", "帝籍頒新讀，天香降廟焚。", "石危名啟母，柏大號將軍。", "獻壽臨雙闕，呈祥出五雲。", "將仙存舊跡，封禪驗遺文。", "終待移家住，閑眠樂放勳。"]'),
('0e7dc762-6007-4852-8a49-1bdc4bd92a3c','和陳推官見贈','魏野','宋','宋诗','song-poetry','','[]','白髮朱衣好寫真，鵷行佐幕異常倫。',64,'全唐诗/poet.song.4000.json','["白髮朱衣好寫真，鵷行佐幕異常倫。", "勘書幾見招閑客，斷案常思出罪人。", "棠樹政聲僧說遠，蘇臺實錄世傳新。", "仍知公退無餘事，惟祇焚香禮北辰。"]'),
('6ed3061d-04cb-45d0-8dc6-d44fe53483c8','張生示予詠菊詩且古之作者遲晚之意頗同體狀之功未盡因書一絕以答之','魏野','宋','宋诗','song-poetry','','[]','正當摇落獨芳妍，向晚吟看露泫然。',32,'全唐诗/poet.song.4000.json','["正當摇落獨芳妍，向晚吟看露泫然。", "還似六宮人競怨，幾多珠淚濕金鈿。"]'),
('95f1c851-0c44-476c-a0d4-c758e0ea5d7e','送薛端公赴右蜀均輸兼呈司理劉大著二首  其一','魏野','宋','宋诗','song-poetry','','[]','金魚新躍綉衣邊，暫委均輸出劍關。',64,'全唐诗/poet.song.4000.json','["金魚新躍綉衣邊，暫委均輸出劍關。", "九折路危驄馬怯，一方塵靜木牛閑。", "諸侯迎送威風下，赤子歌謠喜氣間。", "更羨錦城劉大著，海棠花裏恣追攀。"]'),
('51a9bd48-4ae6-49dc-984b-22bdbebf12d0','送薛端公赴右蜀均輸兼呈司理劉大著二首  其二','魏野','宋','宋诗','song-poetry','','[]','旌旆悠悠出陝時，白頭人送倍依依。',64,'全唐诗/poet.song.4000.json','["旌旆悠悠出陝時，白頭人送倍依依。", "蜀川尚憶蒲蘆政，蠻洞先驚獬豸威。", "祖席香濃花未老，行厨味簡筍初肥。", "公餘若薦相如賦，郫縣梅仙好發揮。"]'),
('2ed0318e-20f7-4a09-8371-7211b59bf605','謝益州司理劉大著寄惠筇竹杖','魏野','宋','宋诗','song-poetry','','[]','雖勝斑竹與紅藤，絕遠羸軀豈易憑。',32,'全唐诗/poet.song.4000.json','["雖勝斑竹與紅藤，絕遠羸軀豈易憑。", "爭得化龍歸錦水，老身騎去見心朋。"]'),
('cfca134d-e849-4b92-81d9-d82a5935f64a','和孫虞部見贈','魏野','宋','宋诗','song-poetry','','[]','朝客惠詩牌，山人愧不才。',48,'全唐诗/poet.song.4000.json','["朝客惠詩牌，山人愧不才。", "旱田春雨足，暗室夜光來。", "燈下吟三復，琴中鼓數迴。", "性愚非賜也，微旨尚難猜。"]'),
('97a37c6b-006e-40fd-a1f9-e26adf166fc2','貽不出院真公','魏野','宋','宋诗','song-poetry','','[]','閉戶頭初剃，今來已白頭。',48,'全唐诗/poet.song.4000.json','["閉戶頭初剃，今來已白頭。", "五侯堂上見，四海定中遊。", "鑿井還依砌，栽松欲映樓。", "人間思慮絕，擁衲任經秋。"]'),
('7db5dde7-cf05-4ec2-98a7-cdd9c79558a5','別後却寄三門發運卞寺丞兼簡臧推官','魏野','宋','宋诗','song-poetry','','[]','共泛樓船去，臨流羨送君。',48,'全唐诗/poet.song.4000.json','["共泛樓船去，臨流羨送君。", "烟中旗不見，風裏樂猶聞。", "李郭情堪並，荀陳事豈分。", "歸來溪路上，特地愴離羣。"]'),
('99bc283c-6ab7-496c-b50a-3e8f2afcbfda','送劉大著赴任益州司理','魏野','宋','宋诗','song-poetry','','[]','金口親除向錦川，一般監郡最榮遷。',64,'全唐诗/poet.song.4000.json','["金口親除向錦川，一般監郡最榮遷。", "從來才已欺鸚鵡，此去冤應雪杜鵑。", "迎接僧攜筇竹杖，歌謠民寫浣花箋。", "移風定不妨吟笑，絕唱宜磨玉壘鎸。"]'),
('9ea3938d-730c-42f0-bf45-2d178f7e9308','晨興','魏野','宋','宋诗','song-poetry','','[]','夜長乞待得晨興，躭睡童猶喚不應。',64,'全唐诗/poet.song.4000.json','["夜長乞待得晨興，躭睡童猶喚不應。", "燒葉爐中無宿火，讀書窗下有殘燈。", "臨階短髮梳和月，傍岸衰容洗带冰。", "料得巢禽翻怪訝，尋常日午起慵能。"]'),
('f5cf089e-3206-4a96-9fee-43e54bc9003d','酬和知制誥孫舍人見寄','魏野','宋','宋诗','song-poetry','','[]','也知皇宋足名人，至論誰堪繼後塵。',64,'全唐诗/poet.song.4000.json','["也知皇宋足名人，至論誰堪繼後塵。", "已見世傳元相制，將聞詔寫白公真。", "紫微星宿雖潛望，紅藥階除豈易親。", "野客多慚惠佳句，强酬應信廢精神。"]'),
('21437b3d-28d0-4bcf-af7f-a16d1cbab7bd','送紫微孫舍人赴鎮長安','魏野','宋','宋诗','song-poetry','','[]','長安千古帝王城，鎮選詞臣自聖情。',64,'全唐诗/poet.song.4000.json','["長安千古帝王城，鎮選詞臣自聖情。", "三字带來天上貴，雙旌擁出世間榮。", "朱衣尚列神仙步，紅藥宜吟雅正聲。", "預想前春遊賞處，九龍池上百花明。"]'),
('8fc33a3d-3569-47e9-ab41-5c82e820bb59','和郡侯詠雪','魏野','宋','宋诗','song-poetry','','[]','時節初過打獵天，山河一色曉漫漫。',64,'全唐诗/poet.song.4000.json','["時節初過打獵天，山河一色曉漫漫。", "梁王宴罷樽猶濕，謝傅詩成墨未乾。", "筆硯窗間寧覺夜，管絃堂上豈知寒。", "須知祥瑞同霖雨，莫作梅花柳絮看。"]'),
('eb44ddca-b645-45eb-9b2e-4626582a0d45','謝孫紫微同郡侯石太尉見訪','魏野','宋','宋诗','song-poetry','','[]','誰共東郊訪懶魁，一時文武盡奇才。',64,'全唐诗/poet.song.4000.json','["誰共東郊訪懶魁，一時文武盡奇才。", "朱衣列到柴門住，皂纛隨穿竹徑來。", "乍照兒童戈似雪，忽驚猿鶴鼓如雷。", "眼看兩地翱翔去，溪上無由更接陪。"]'),
('a6fc90c2-8cc1-4923-8964-e8b011a3029e','詠菊','魏野','宋','宋诗','song-poetry','','[]','榮雖同雨露，晚不怨乾坤。',168,'全唐诗/poet.song.4000.json','["榮雖同雨露，晚不怨乾坤。", "五色中偏貴，千花後獨尊。", "馨非慚黍稷，採合勝蘋蘩。", "蛺蝶寒猶至，鷦鷯靜亦存。", "味堪資玉鉉，光欲奪金樽。", "带霧叢猶密，經霜艷更繁。", "砌蟲親有路，梁燕識無門。", "薜荔宜求友，茱萸好結婚。", "栽培勞婢僕，服食教兒孫。", "易把方先哲，難爲繼後昆。", "敗莎承亞朵，落葉擁纖根。", "雖異皇家瑞，寧孤白帝恩。", "延齡仙訣著，應候禮經言。", "不與羣芳競，還如我避喧。"]'),
('a8ca0b14-951b-4ed1-807e-01feef385827','上知府石太尉二首  其一','魏野','宋','宋诗','song-poetry','','[]','陝城天險枕河湄，茆土真風勝暫知。',64,'全唐诗/poet.song.4000.json','["陝城天險枕河湄，茆土真風勝暫知。", "雲霧雖頻霑虎節，雪霜全未染虬髭。", "白霓放作軍中練，紅袖行爲帳下旗。", "公暇不妨遊賞外，佐僚時得一篇詩。"]'),
('d3fcba35-3aa1-423a-9652-89b59a87af75','上知府石太尉二首  其二','魏野','宋','宋诗','song-poetry','','[]','功名早歲立艱難，今日堪銷費百般。',64,'全唐诗/poet.song.4000.json','["功名早歲立艱難，今日堪銷費百般。", "婢僕出來皆會樂，兒童生下便爲官。", "實封萬戶方應足，密賜千金旋已殘。", "輟坐棠間慚豹略，莫嫌拘束動嗟嘆。"]'),
('18abb633-c92a-4506-8db6-05bac3c8956c','送三門發運辛寺丞赴闕','魏野','宋','宋诗','song-poetry','','[]','山河仗忠信，盡室去安然。',48,'全唐诗/poet.song.4000.json','["山河仗忠信，盡室去安然。", "白浪爲行路，紅旗認坐船。", "禹門辭有燕，隋柳到無蟬。", "豈羨乘槎客，風流載管絃。"]'),
('ab175991-92f4-4c6a-8103-66bf9f00b213','疏小渠','魏野','宋','宋诗','song-poetry','','[]','分得前溪水，縈紆遶砌流。',48,'全唐诗/poet.song.4000.json','["分得前溪水，縈紆遶砌流。", "清泠雖可樂，嗚咽不關愁。", "靜稱浮花片，閑宜泛酒甌。", "却嫌川上看，時復有沉舟。"]'),
('1093735f-7c8a-4d7e-86ae-af93d01ce0f4','寄河中田沃兼呈李瀆徵君','魏野','宋','宋诗','song-poetry','','[]','未遂去蓬瀛，閒居在舜城。',48,'全唐诗/poet.song.4000.json','["未遂去蓬瀛，閒居在舜城。", "七絃調似性，萬卷記如名。", "下榻留山相，敲門認竺卿。", "中條與太華，窗里見崢嶸。"]'),
('3354e317-f20e-444c-bd15-1a0b5cdd84c0','送唐肅察院赴東川提刑','魏野','宋','宋诗','song-poetry','','[]','按察東川十四州，幾多山水似蓬丘。',32,'全唐诗/poet.song.4000.json','["按察東川十四州，幾多山水似蓬丘。", "清時應喜無冤雪，贏得乘驄到處遊。"]'),
('61def3fc-fc68-46c5-8c64-f272bf1643ed','薛田察院洎壽師同宿三門開化院','魏野','宋','宋诗','song-poetry','','[]','繡衣蕙带方袍客，身計雖殊性共閒。',32,'全唐诗/poet.song.4000.json','["繡衣蕙带方袍客，身計雖殊性共閒。", "同宿河心山頂寺，數宵無一事相關。"]'),
('e19e3807-2757-46b0-bd68-d42ccae15941','寄王谷推官','魏野','宋','宋诗','song-poetry','','[]','登科二十載，佐幕尚如初。',48,'全唐诗/poet.song.4000.json','["登科二十載，佐幕尚如初。", "官爲詩磨折，家因酒破除。", "青衫應懶補，白髮想慵梳。", "別後常相憶，何緣得共居。"]'),
('118b117d-1254-4fb5-8128-a8a4d32c2c3b','值雨宿諤師房','魏野','宋','宋诗','song-poetry','','[]','信步閑遊處，妨歸路豈賒。',48,'全唐诗/poet.song.4000.json','["信步閑遊處，妨歸路豈賒。", "因琴避山寺，和鶴宿僧家。", "語直非關酒，眠遲不爲茶。", "共論塵世裏，夜亦事如麻。"]'),
('b84dbf9b-fac3-4194-ac92-fe09e454bbf3','送王希赴任衢州判官','魏野','宋','宋诗','song-poetry','','[]','秋江四十有餘程，稱作紅蓮泛去清。',32,'全唐诗/poet.song.4000.json','["秋江四十有餘程，稱作紅蓮泛去清。", "從闕到州堪羨處，船中坐卧看山行。"]'),
('e4ea0c70-1698-461c-87cb-49c095fa2430','和江南提刑王國博見寄','魏野','宋','宋诗','song-poetry','','[]','欲寫情懷難一一，擬尋山水隔千千。',32,'全唐诗/poet.song.4000.json','["欲寫情懷難一一，擬尋山水隔千千。", "輸他吳越閑鷗鷺，朝夕常親畫舫前。"]'),
('5da7578b-c228-4a91-bb86-09c79a1bb351','送潤上人南遊','魏野','宋','宋诗','song-poetry','','[]','山水興如燒，難留住陝郊。',48,'全唐诗/poet.song.4000.json','["山水興如燒，難留住陝郊。", "五湖携磬去，幾夜在船敲。", "犀跡來沙岸，蟬聲起樹梢。", "南方未迴日，何處暫編茆。"]'),
('a69e6e5d-5793-4f3f-add2-04aa100c6c28','聞王衢王闢登第因有寄賀','魏野','宋','宋诗','song-poetry','','[]','人間第一榮，初得好科名。',48,'全唐诗/poet.song.4000.json','["人間第一榮，初得好科名。", "萬乘登樓看，三台讓路行。", "搜羅空草澤，宴會敵蓬瀛。", "榜眼兼衣鉢，偏依野客情。"]'),
('675661ff-b31a-456e-a5ed-5262695b3483','送宣筆與成都司理劉大著','魏野','宋','宋诗','song-poetry','','[]','宣城彩筆真堪愛，蜀色紅箋更可誇。',32,'全唐诗/poet.song.4000.json','["宣城彩筆真堪愛，蜀色紅箋更可誇。", "雅稱風流劉大著，閑時題詠海棠花。"]'),
('82275e0e-13e5-4009-b406-afd36efa93f3','用晦上人遊渼陂','魏野','宋','宋诗','song-poetry','','[]','渼陂寒水碧溶溶，野客江僧望不窮。',32,'全唐诗/poet.song.4000.json','["渼陂寒水碧溶溶，野客江僧望不窮。", "更值晚來風雨歇，終南一半浸波中。"]'),
('3cc25a11-7894-48c2-a801-64a56eb8bdce','還何學士詩集','魏野','宋','宋诗','song-poetry','','[]','魏野非商也，微言豈易窮。',48,'全唐诗/poet.song.4000.json','["魏野非商也，微言豈易窮。", "看雖許朋友，寫不倚兒童。", "合在龍圖上，難留蝸舍中。", "因思投納處，還浦與珠同。"]'),
('f43092f5-0437-4cb3-844f-803545bc207a','送高生歸青社','魏野','宋','宋诗','song-poetry','','[]','去指滄溟畔，來辭翠靄間。',48,'全唐诗/poet.song.4000.json','["去指滄溟畔，來辭翠靄間。", "程遥過鳳闕，家近見牛山。", "紅葉飄行色，清溪照別顔。", "蹇馿看上處，拄杖出柴關。"]'),
('8edf8531-3e91-4ac8-8d17-95beaad68345','聞周孟下第','魏野','宋','宋诗','song-poetry','','[]','乙巳暮春天，端居忽愴然。',48,'全唐诗/poet.song.4000.json','["乙巳暮春天，端居忽愴然。", "一名傷聖祖，三榜作遺賢。", "我自空彈指，君誰可比肩。", "何由銷此恨，獨坐落花前。"]'),
('f8cf1f1f-f064-4ee2-be51-9550a859e4ef','送孫磻西遊','魏野','宋','宋诗','song-poetry','','[]','貧居勝富貴，况復是貧遊。',48,'全唐诗/poet.song.4000.json','["貧居勝富貴，况復是貧遊。", "前路誰青眼，高堂母白頭。", "秦山晴望好，隴水夜聽愁。", "早作歸寧計，逢歡莫滯留。"]'),
('bd855948-d83a-4d0e-bcd5-f0cfd3d3fe9d','詠竹杯珓子','魏野','宋','宋诗','song-poetry','','[]','誰知破筠根，還同一氣分。',48,'全唐诗/poet.song.4000.json','["誰知破筠根，還同一氣分。", "吉凶終在我，翻覆謾勞君。", "酒欲祈先酹，香臨擲更焚。", "吾嘗學丘禱，懶把祝云云。"]'),
('7e79b225-e2b7-4ca5-8bc5-3e9da7026803','喜懷古上人見訪','魏野','宋','宋诗','song-poetry','','[]','隔嶺僧來宿，閑同倚石樓。',48,'全唐诗/poet.song.4000.json','["隔嶺僧來宿，閑同倚石樓。", "漏聲過半夜，月色近中秋。", "雅道玄須到，權門險莫遊。", "此心方共適，明月更相留。"]'),
('b3cd0162-ad81-418b-a1ca-ea11fe087190','村居述懷','魏野','宋','宋诗','song-poetry','','[]','布褐楮皮冠，朝昏信自然。',48,'全唐诗/poet.song.4000.json','["布褐楮皮冠，朝昏信自然。", "眼明山雨後，髮亂晚風前。", "鶴病生閑惱，僧來廢靜眠。", "自知慵懶性，至死豈能悛。"]'),
('866a2a79-c41d-465b-bfc7-017c847cfc45','上知府鮑少卿','魏野','宋','宋诗','song-poetry','','[]','五福三朝客，同年想少存。',120,'全唐诗/poet.song.4000.json','["五福三朝客，同年想少存。", "立功從太祖，卧裏見曾孫。", "易進因仁政，難休爲帝恩。", "權臨二陝重，官處九卿尊。", "烟翠甘棠柳，風清畫戟門。", "四門潛遂意，百吏動驚魂。", "不病輕丹曶，無愁鄙酒樽。", "出衙清道路，在宅素盤飧。", "上馬身猶健，看書眼未昏。", "獄空時擁旆，多謝到山村。"]'),
('f84b94c9-c2d9-401a-b1e7-c5f3a7f3bb1e','懷寄河中表兄李徵君','魏野','宋','宋诗','song-poetry','','[]','蒲津棠樹兩閒人，我愧虛名帝亦聞。',64,'全唐诗/poet.song.4000.json','["蒲津棠樹兩閒人，我愧虛名帝亦聞。", "三世往還爲近戚，一時遞互喚徵君。", "雖同閉戶辭丹詔，尚阻連牀卧白雲。", "苦恨中條鎮相隔，老來離思轉紛紛。"]'),
('18e77054-86e2-4c46-be7a-039c1627a57e','送鮑大監赴闕','魏野','宋','宋诗','song-poetry','','[]','紫詔徵黄下碧虛，棠郊人送去何如。',64,'全唐诗/poet.song.4000.json','["紫詔徵黄下碧虛，棠郊人送去何如。", "深宜我后尊三老，未許伊川學二疏。", "到想烟霞侵几杖，行愁花雨濕圖書。", "歸期野客難陪從，空有吟魂逐後車。"]'),
('2c83229f-2150-4bf1-8932-cab622e1bbfa','依韻和長安龍圖陳學士登熙熙臺之什二首  其一','魏野','宋','宋诗','song-poetry','','[]','鶉野龍圖陳學士，迎秋登眺稱英奇。',64,'全唐诗/poet.song.4000.json','["鶉野龍圖陳學士，迎秋登眺稱英奇。", "一聲玉管風流處，百尺金臺雨霽時。", "雲近上清爭縹緲，山連太白鬭參差。", "碧紗他日裁多少，籠得園園寺寺詩。"]'),
('1bd81b59-4b80-436e-ade8-6f9e5d23050e','依韻和長安龍圖陳學士登熙熙臺之什二首  其二','魏野','宋','宋诗','song-poetry','','[]','臺號熙熙倚半空，新秋景好與春同。',32,'全唐诗/poet.song.4000.json','["臺號熙熙倚半空，新秋景好與春同。", "朱衣吏列登臨處，百二山河一望中。"]'),
('10df3d28-55a3-4f36-a285-b006a93ab061','謝大著劉燁寄惠玉箋','魏野','宋','宋诗','song-poetry','','[]','皎潔分明如我鬢，卷舒方正似君心。',32,'全唐诗/poet.song.4000.json','["皎潔分明如我鬢，卷舒方正似君心。", "三千里外情多少，一幅真堪值萬金。"]'),
('b3f992f0-6ef9-4f64-a9c8-661ce55e68bd','送王國博赴江南提刑','魏野','宋','宋诗','song-poetry','','[]','聖主憂民意，過于民自憂。',72,'全唐诗/poet.song.4000.json','["聖主憂民意，過于民自憂。", "一麾常慎選，八使更親求。", "車馬皆新賜，江山半舊遊。", "蠻旌飄後騎，水弩下仙舟。", "貧愛憐吾道，寬思雪楚囚。", "莫忘相送處，村店凍溪頭。"]'),
('6d4ae101-9c89-472c-9d08-b1c1ceb82ede','陪留臺李學士筵上賦得文石酒杯分得杯字','魏野','宋','宋诗','song-poetry','','[]','知自何山得，磨礱作酒杯。',48,'全唐诗/poet.song.4000.json','["知自何山得，磨礱作酒杯。", "斟疑五色動，醉認一拳開。", "漥似泉舂出，痕如蘚漬來。", "主人心樸素，愛惜過璚瑰。"]'),
('07274970-532e-4e5e-82ca-1cfbe060186f','貽司馬池','魏野','宋','宋诗','song-poetry','','[]','年少老成人，林間訪我頻。',48,'全唐诗/poet.song.4000.json','["年少老成人，林間訪我頻。", "文雖如貌古，道不似家貧。", "題柱寧慚祖，干時不爲身。", "鰲山將首冠，莫歎尚沉淪。"]'),
('61dbcb90-4acb-40df-a8de-6dd32a22338b','寄贈洛下達三藏','魏野','宋','宋诗','song-poetry','','[]','曾携鉢錫到靈，古寺歸來洛水邊。',63,'全唐诗/poet.song.4000.json','["曾携鉢錫到靈，古寺歸來洛水邊。", "新譯經文傳北闕，舊遊詩句在西天。", "爐中香想諸方施，籠裏燈應數世傳。", "別有空門難繼處，宋尚書序本師編。"]'),
('74065239-5eb6-40b0-a859-af0c34e577c1','寄贈長安孫紫微','魏野','宋','宋诗','song-poetry','','[]','带掌絲綸出鎮時，樂天當日未如之。',64,'全唐诗/poet.song.4000.json','["带掌絲綸出鎮時，樂天當日未如之。", "九遷官職光鵷鷺，百二山河壯虎貔。", "漢殿舊題司馬賦，秦樓新唱舍人詩。", "相思大欲相尋處，酒戶如何敵酒巵。"]'),
('453e2461-5547-4067-8639-4c6d03f999be','依韻和益州司理劉大著喜與運使薛端公相見之什','魏野','宋','宋诗','song-poetry','','[]','錦川風物似蓬丘，運使詩流壓九流。',64,'全唐诗/poet.song.4000.json','["錦川風物似蓬丘，運使詩流壓九流。", "五色雲中題寺觀，四時花裏按軍州。", "棠郊野客空遥羨，蘭省才郎稱共遊。", "縱使謫仙今復出，難陪倡和却應愁。"]'),
('aff35745-5470-4f60-828e-3214f7c25a73','依韻和酬用晦上人見題所居','魏野','宋','宋诗','song-poetry','','[]','陋巷西鄰召伯祠，入城流水透疏籬。',64,'全唐诗/poet.song.4000.json','["陋巷西鄰召伯祠，入城流水透疏籬。", "雨來石室琴先覺，春去松庭鶴不知。", "薜荔交加侵甕牖，莓苔斑駁遶盆池。", "草堂近日猶增價，添得湯休兩首詩。"]'),
('08638661-2119-4d7b-b2fc-51f2ef854967','送王甲宰青石縣','魏野','宋','宋诗','song-poetry','','[]','陶潛但植當門柳，潘岳惟栽滿縣花。',32,'全唐诗/poet.song.4000.json','["陶潛但植當門柳，潘岳惟栽滿縣花。", "爭似伯玄青石去，教民先只種桑麻。"]'),
('ab98b0a1-7c96-4a99-ad03-6b4a80868547','書三門開化院琳師房','魏野','宋','宋诗','song-poetry','','[]','四邊浪打山疑動，寺在半空山頂頭。',32,'全唐诗/poet.song.4000.json','["四邊浪打山疑動，寺在半空山頂頭。", "遶檻門窗多晝掩，應嫌坐卧見沉舟。"]'),
('e0035f62-d6f4-467b-bffb-34e226025638','送閏師之長安謝紫衣','魏野','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.4000.json','["無正文。"]'),
('ec673876-afb7-4bfd-a5da-eea3f3f4eb24','送秘丞王利通倅閬州','魏野','宋','宋诗','song-poetry','','[]','到想行仁政，民間豈復言。',48,'全唐诗/poet.song.4000.json','["到想行仁政，民間豈復言。", "冤思雪蜀魄，哀欲吊巴猿。", "山水州城僻，烟嵐路徑昏。", "遥思上事日，正值海棠溫。"]'),
('9cb5dbf5-f769-4acb-bc11-9d7e3f6bffac','暮冬郊居懷李安','魏野','宋','宋诗','song-poetry','','[]','草屋松篁杪，寒多市井閒。',48,'全唐诗/poet.song.4000.json','["草屋松篁杪，寒多市井閒。", "嚴風生北戶，愛日落南山。", "下第人何處，林居鳥自還。", "琴樽雖在側，難以解愁顔。"]'),
('bcdd9385-8292-4956-9036-3dd9f807c442','送太博知榮州','魏野','宋','宋诗','song-poetry','','[]','莫嘆迢迢遠帝京，且憐叱馭繼家聲。',64,'全唐诗/poet.song.4000.json','["莫嘆迢迢遠帝京，且憐叱馭繼家聲。", "歌鐘競出棠郊送，鼓角應過劍閣迎。", "椶葉带風驚玉勒，梅花和雪照紅旌。", "下車遥想無餘事，政譽遥同在陝城。"]'),
('5e8e2344-5c2b-491f-b8dc-4a611f161509','依韻和李安見寄','魏野','宋','宋诗','song-poetry','','[]','三舉休嗟尚陸沉，獻書已得帝知音。',64,'全唐诗/poet.song.4000.json','["三舉休嗟尚陸沉，獻書已得帝知音。", "燒殘灰燼方分玉，披盡泥沙始見金。", "思苦任成潘岳鬢，道窮莫動孟軻心。", "公車再召應非晚，疏懶猶難卜訪尋。"]'),
('f87d178f-8c4d-478b-b670-bd638860a72f','咸陽道中作','魏野','宋','宋诗','song-poetry','','[]','渭水凍無波，終南翠色多。',48,'全唐诗/poet.song.4000.json','["渭水凍無波，終南翠色多。", "雲臨殘照霽，客向故城過。", "驚雁遠猶叫，牧童寒不歌。", "心愁人不會，謂我欲求何。"]'),
('fc8ac7ab-139a-476b-a6d7-78ab1669e4e9','送孫狀元監丞赴闕','魏野','宋','宋诗','song-poetry','','[]','詔命雖殊異，行裝亦等閑。',48,'全唐诗/poet.song.4000.json','["詔命雖殊異，行裝亦等閑。", "蓬壺如得路，藜杖似歸山。", "赴約過嵩嶺，辭家到竹關。", "從茲位清峻，野客轉難攀。"]'),
('4b52c29c-877f-4e74-88e9-e9bc2aa68129','暮秋懷王專臧奎王衢三從事','魏野','宋','宋诗','song-poetry','','[]','舊友各西東，閒思興莫窮。',48,'全唐诗/poet.song.4000.json','["舊友各西東，閒思興莫窮。", "盡居花幕下，獨在竹林中。", "白屋貧雖異，清宵夢想同。", "吟餘遥望處，寒雨正濛濛。"]'),
('24962b56-828a-4f7c-8530-d812368e8d3e','送石太尉移鎮許昌','魏野','宋','宋诗','song-poetry','','[]','厭居棠樹遠京師，新自飛章白玉墀。',64,'全唐诗/poet.song.4000.json','["厭居棠樹遠京師，新自飛章白玉墀。", "許郡虎符依口得，凉州龍節逐身移。", "離聲銀字調家樂，行李金函鎖御詩。", "想到即徵歸密地，碧波亭上不多時。"]'),
('3cd6ec4b-1d7b-41d9-966b-80c065527133','送司馬池歸夏臺','魏野','宋','宋诗','song-poetry','','[]','芳草垂楊弄色初，山中好酒想躊踟。',32,'全唐诗/poet.song.4000.json','["芳草垂楊弄色初，山中好酒想躊踟。", "他時駟馬乘如祖，莫忘今朝跨蹇馿。"]'),
('3c9ed49a-107a-48fc-b65a-4b9a95cff847','雪竹','魏野','宋','宋诗','song-poetry','','[]','溪南一向幾多垂，欲詠終難比並伊。',32,'全唐诗/poet.song.4000.json','["溪南一向幾多垂，欲詠終難比並伊。", "應是彤庭將御試，麻衣羣見折腰時。"]'),
('c20bba55-2f80-4e6f-8000-2a6ff34cc9b3','哭岐賁從事','魏野','宋','宋诗','song-poetry','','[]','君喪重堪悲，才高位竟卑。',48,'全唐诗/poet.song.4000.json','["君喪重堪悲，才高位竟卑。", "寄孤偏囑我，知己更求誰。", "祭德宜脩廟，傳名不在碑。", "何人與爲傳，願錄野人詩。"]'),
('e132107c-1099-4f89-9655-1648ba00588c','送懷古上人遊錢塘','魏野','宋','宋诗','song-poetry','','[]','正當摇落日，忽憶向江天。',48,'全唐诗/poet.song.4000.json','["正當摇落日，忽憶向江天。", "猿避經行路，鷗隨入定船。", "袖携詩卷重，杖揭鉢囊偏。", "約我湖心寺，相尋結白蓮。"]'),
('8871fbdb-f517-43d1-8a3e-d8498f1d23fd','悼鶴','魏野','宋','宋诗','song-poetry','','[]','誰折仙禽足，經旬致枉終。',48,'全唐诗/poet.song.4000.json','["誰折仙禽足，經旬致枉終。", "讎宜天與報，恨使我難窮。", "風月猶疑慘，園林頓覺空。", "殷勤親起塚，只在草堂東。"]'),
('9717eb8f-1584-4fcd-b5f5-f09b60b6ab65','送王國博赴江南提刑  其一','魏野','宋','宋诗','song-poetry','','[]','江南按察去如何，詔敕雖然密賜多。',32,'全唐诗/poet.song.4000.json','["江南按察去如何，詔敕雖然密賜多。", "不斷仙舟來往處，狎鷗載鶴聽漁歌。"]'),
('cb76039d-933c-4bad-a7f0-2aff33367579','送王國博赴江南提刑  其二','魏野','宋','宋诗','song-poetry','','[]','江南刑省到時和，十郡應從宴樂多。',32,'全唐诗/poet.song.4000.json','["江南刑省到時和，十郡應從宴樂多。", "自有山迎兼水送，清陰不斷勝清歌。"]'),
('5f4c0411-70d7-4d56-88ed-f3400c59fd31','送王國博赴江南提刑  其三','魏野','宋','宋诗','song-poetry','','[]','江南大半舊經過，君稱心多我恨多。',32,'全唐诗/poet.song.4000.json','["江南大半舊經過，君稱心多我恨多。", "好景阻陪遊賞去，空縈老病動悲歌。"]'),
('59b00953-ceca-4bbb-99a0-538ee599cbab','送李安赴舉','魏野','宋','宋诗','song-poetry','','[]','野客復何陳，賢侯首薦人。',48,'全唐诗/poet.song.4000.json','["野客復何陳，賢侯首薦人。", "俗流寧肯餞，良璞不嫌貧。", "棠樹離偏曉，函關過已頻。", "花時好消息，佇聽向溪濱。"]'),
('ee4aee34-7dbc-4ecf-b808-37d4be21e683','醍醐鳥','魏野','宋','宋诗','song-poetry','','[]','解啼能解酌，啼處靜堪聽。',48,'全唐诗/poet.song.4000.json','["解啼能解酌，啼處靜堪聽。", "林下雖沽酒，人間最獨醒。", "石泉窺認甕，花露飲爲瓶。", "翻嘆耽杯者，還應損性靈。"]'),
('74e715ea-6390-420c-9551-ed1e878fae31','寄贈知洋州李澤屯田','魏野','宋','宋诗','song-poetry','','[]','一種分符命最優，翠微深處是洋州。',64,'全唐诗/poet.song.4000.json','["一種分符命最優，翠微深處是洋州。", "白雲遶座疑山相，紅旆隨行表郡侯。", "禪定僧疑陪靜話，音聲鳥稱伴閒遊。", "更輸屬邑錢希聖，四季花前共倡酬。"]'),
('0477300f-24c1-4cc4-9f28-6fea620f2973','三門與臧奎推官聯句題東樓','魏野','宋','宋诗','song-poetry','','[]','二陝三門境，江城想未勝。',48,'全唐诗/poet.song.4000.json','["二陝三門境，江城想未勝。", "早衙連廟鼓，夜市雜船燈。", "乞任多朝市，忘歸有海僧。", "東樓仍更好，欲去又同登。"]'),
('d7af8cd3-4554-4a68-9445-c5e31268b9ea','書逸人俞太中屋壁','魏野','宋','宋诗','song-poetry','','[]','羨君還似我，居處傍林泉。',48,'全唐诗/poet.song.4000.json','["羨君還似我，居處傍林泉。", "洗硯魚吞墨，烹茶鶴避烟。", "閒惟歌聖代，老不恨流年。", "每到論詩外，慵多對榻眠。"]'),
('5e6732e0-4107-4e7f-a080-78d5ed9cc3d9','送文兆上人南歸','魏野','宋','宋诗','song-poetry','','[]','自由由獨自，誰滯復誰催。',48,'全唐诗/poet.song.4000.json','["自由由獨自，誰滯復誰催。", "住笑雲無定，歸嫌水不迴。", "瓶惟添瀑布，杖祇卓莓苔。", "如此真行脚，餘堪我靜咍。"]'),
('0d61a1a2-5330-420b-8902-488a9e0e2ec0','述懷','魏野','宋','宋诗','song-poetry','','[]','東郭魏仲先，生計且隨緣。',48,'全唐诗/poet.song.4000.json','["東郭魏仲先，生計且隨緣。", "任懶自掃地，更貧誰怨天。", "有名閒富貴，無事小神仙。", "不覺流光速，身將半百年。"]'),
('0afd11dd-2a62-466d-a59b-9cacbb648e1a','和宗人見寄','魏野','宋','宋诗','song-poetry','','[]','兀坐幾忘形，柴門夜不扃。',96,'全唐诗/poet.song.4000.json','["兀坐幾忘形，柴門夜不扃。", "稔憐丞相雨，瑞愛老人星。", "妻識琴材料，童諳鶴性靈。", "遠山延頸望，疏竹枕肱聽。", "祖業存圭竇，年支有茯苓。", "閒身寄精舍，狂迹在旗亭。", "養藥依丹訣，嘗茶驗水經。", "何時得相見，靜話向松庭。"]'),
('66c74e53-5c1a-41aa-89ab-c24860ac1993','送進士孫磻赴舉','魏野','宋','宋诗','song-poetry','','[]','半生養銳向棠郊，此去深宜奪錦標。',64,'全唐诗/poet.song.4000.json','["半生養銳向棠郊，此去深宜奪錦標。", "莫嘆遷鶑方出谷，只看一鶚迥沖霄。", "送詩吟恨冰生硯，別酒携從雪濯瓢。", "馿蹇童羸山路險，他時貴不忘今朝。"]'),
('b8d97fed-e960-484f-9a82-3faf862fc5ab','送王闢太博赴闕呈劉正言','魏野','宋','宋诗','song-poetry','','[]','吟坐俱頭白，分携重愴情。',48,'全唐诗/poet.song.4000.json','["吟坐俱頭白，分携重愴情。", "才堪親帝座，貧不似官行。", "曉霧迷山徑，秋霖破驛程。", "唯應劉小諫，到闕始相迎。"]'),
('b1a89155-8e56-4051-a8ea-076f9823a90d','酬和提刑王國博見寄兼謝惠竹簟','魏野','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','召伯城邊勞夢想，滕王閣上動詩心。',64,'全唐诗/poet.song.4000.json','["召伯城邊勞夢想，滕王閣上動詩心。", "閑思已隔江山遠，老別那堪歲月深。", "三徑出稀青草合，雙眸望久墨花侵。", "翻嗟珍簟雖蒙寄，早晚同將坐卧吟。"]'),
('bff4573c-2626-4e8f-84de-18180ca41bf6','寄贈西川御史薛端公益州司理劉大著陝路運使臧殿院梓州提刑唐察院','魏野','宋','宋诗','song-poetry','','[]','四賢同在兩川時，不獨民間鬭察微。',64,'全唐诗/poet.song.4000.json','["四賢同在兩川時，不獨民間鬭察微。", "蜀魄血流啼亦少，巴猿腸斷叫應稀。", "文君酒旨停紅旆，神女雲從慝繡衣。", "雪盡沉冤題盡景，齊看詔向十州歸。"]'),
('5d198bff-f642-4a95-b9cd-71f4843661ec','送薛奎殿院赴闕','魏野','宋','宋诗','song-poetry','','[]','謫監陝郡滯賢才，清雪忻將紫詔開。',64,'全唐诗/poet.song.4000.json','["謫監陝郡滯賢才，清雪忻將紫詔開。", "緩步未親龍扆去，迴車願擁隼輿來。", "辭蒙得得過三徑，送合迢迢到柏臺。", "秋霽山川行色好，乘驄策蹇恨難陪。"]'),
('5ae66530-3e67-4aa5-b5e4-d23ec4c9efeb','薛殿院將赴闕先歸絳臺迎覲','魏野','宋','宋诗','song-poetry','','[]','不妨赴詔暫歸寧，躍馬惟消兩火程。',32,'全唐诗/poet.song.4000.json','["不妨赴詔暫歸寧，躍馬惟消兩火程。", "七十嚴君千萬喜，綵衣爭似繡衣榮。"]'),
('aaf1c91d-d0fc-4d57-ad6a-1518bd2c27f1','謝孫大諫惠茶','魏野','宋','宋诗','song-poetry','','[]','盧仝曾謝諫官茶，狂作長歌任過誇。',32,'全唐诗/poet.song.4000.json','["盧仝曾謝諫官茶，狂作長歌任過誇。", "爭似君今相惠者，分從金口到村家。"]'),
('1735bb8c-82ac-4890-8f92-931490c76545','贈華山何學士致仕','魏野','宋','宋诗','song-poetry','','[]','累表乞眠雲，明君始許君。',48,'全唐诗/poet.song.4000.json','["累表乞眠雲，明君始許君。", "三峰同鶴住，半俸與僧分。", "益壽藥誰得，朝元香自焚。", "承家多令子，冠蓋世紛紛。"]'),
('00007b62-35e4-4e76-83a8-d78d0ad4452f','依韻和馮亞見贈','魏野','宋','宋诗','song-poetry','','[]','君向城中住，淳風想獨還。',48,'全唐诗/poet.song.4000.json','["君向城中住，淳風想獨還。", "相逢多解夢，不見少開顔。", "期約多尋藥，商量共買山。", "羨予庭際石，重疊蘚痕斑。"]'),
('6ccf0be1-a55d-4ff3-8dcf-239c59f8724f','贈薛田察院兼呈劉大著','魏野','宋','宋诗','song-poetry','','[]','居喪貧御史，家近亦難歸。',48,'全唐诗/poet.song.4000.json','["居喪貧御史，家近亦難歸。", "却恐詔起復，如何贖繡衣。", "僕夫潛去盡，親友頻來稀。", "惟有劉東觀，時時扣掩扉。"]'),
('ec5aca20-93ac-465f-b61d-b8ebf1671914','寄贈河中孫大諫兼簡劉大著李瀆處士','魏野','宋','宋诗','song-poetry','','[]','暫出皇州路不賒，莫同夢得動咨嗟。',64,'全唐诗/poet.song.4000.json','["暫出皇州路不賒，莫同夢得動咨嗟。", "雙旌況鎮重華國，五府猶爲大尹家。", "劉耀卿方知屬邑，李長源舊寄生涯。", "相逢應是星頻聚，豈獨山河勢可誇。"]'),
('40b12215-e280-4f18-aca2-1abb6a43d25f','和酬孫大諫見訪之什','魏野','宋','宋诗','song-poetry','','[]','冬日開門忽似春，溫顔和氣接如親。',64,'全唐诗/poet.song.4000.json','["冬日開門忽似春，溫顔和氣接如親。", "貴能尚故尋村叟，醉誤猶呼作舍人。", "茜旆空林行蘚上，椹袍拂石坐溪濱。", "仍留雅詠酬雖晚，每看長先整角巾。"]'),
('36cc24de-011b-4018-a055-690a66b9838a','送賈注歸蜀','魏野','宋','宋诗','song-poetry','','[]','將爲干名入帝都，却言歸隠蜀鄉閭。',64,'全唐诗/poet.song.4000.json','["將爲干名入帝都，却言歸隠蜀鄉閭。", "永拋丹桂辭京輦，深入青山侍板輿。", "囊裏幾般仙藥草，杖頭數卷道經書。", "相門親友應相羨，富貴終難復舊居。"]'),
('659d13a2-8497-4795-8f52-0e06ded922a5','長安龍圖陳學士寵示重陽日翠微樓上見覽拙詩之作兼蒙寄翠微樓長樂亭二記各述一絕寄而謝之','魏野','宋','宋诗','song-poetry','','[]','京兆重陽大尹家，翠微樓上賞黄花。',32,'全唐诗/poet.song.4000.json','["京兆重陽大尹家，翠微樓上賞黄花。", "秦娥應怪停歌吹，看我狂詩到日斜。"]'),
('2fa69d9e-77cf-4c87-840e-bd3f9213ca54','長安龍圖陳學士寵示重陽日翠微樓上見覽拙詩之作兼蒙寄翠微樓長樂亭二記各述一絕寄而謝之 翠微樓','魏野','宋','宋诗','song-poetry','','[]','斗城誰建翠微樓，富貴陳家小狀頭。',32,'全唐诗/poet.song.4000.json','["斗城誰建翠微樓，富貴陳家小狀頭。", "和記從今爲四絕，鳳毛玉筯與銀鈎。"]'),
('d5474c41-e423-4e94-be7b-a8e610283436','長安龍圖陳學士寵示重陽日翠微樓上見覽拙詩之作兼蒙寄翠微樓長樂亭二記各述一絕寄而謝之 長樂亭','魏野','宋','宋诗','song-poetry','','[]','長安長樂古來坡，新創離亭景致多。',32,'全唐诗/poet.song.4000.json','["長安長樂古來坡，新創離亭景致多。", "從此祖筵休別唱，記中自有斷腸歌。"]'),
('84c996f0-3ba9-4c43-965d-d60cbd4d7251','和夏臺知縣李尚賢殿直見贈','魏野','宋','宋诗','song-poetry','','[]','咫尺縣前山，陽城舊掩關。',48,'全唐诗/poet.song.4000.json','["咫尺縣前山，陽城舊掩關。", "兩衙公務靜，三載使星閑。", "雪入司房暗，苔侵界石斑。", "曾爲攀桂客，多謝訪林間。"]'),
('1ad88446-8555-4dda-8ba6-82ffc75961bf','送王專著作之任犀浦','魏野','宋','宋诗','song-poetry','','[]','西山宰字選清强，東觀修文輟佐郎。',64,'全唐诗/poet.song.4000.json','["西山宰字選清强，東觀修文輟佐郎。", "濯錦江邊趨郡府，浣花溪上問封疆。", "半年訟必消民境，數月歌應徹帝鄉。", "百里舊聞風物好，公餘遥想入篇章。"]'),
('dbb6f1ac-e78f-4e68-bce4-bff8a8d5b462','送張子皋推官赴闕','魏野','宋','宋诗','song-poetry','','[]','閑想何人得似君，汎蓮難滯五侯門。',64,'全唐诗/poet.song.4000.json','["閑想何人得似君，汎蓮難滯五侯門。", "風流自是神仙客，雅淡誰知將相孫。", "寒籟忍堪飄別曲，秋霖那更洒離魂。", "青春漸上青雲去，後會應難向水村。"]'),
('3358dc06-7382-4b2b-b46c-22d90368d70d','次韻和酬洛下宋京見寄','魏野','宋','宋诗','song-poetry','','[]','聲名獨步向西都，主將風騷敵亞夫。',64,'全唐诗/poet.song.4000.json','["聲名獨步向西都，主將風騷敵亞夫。", "龜洛泛應隨釣叟，龍門遊想領生徒。", "公車未召身猶散，相府深知道豈孤。", "可惜春時還不見，眼前花卉謾芬敷。"]'),
('92d4ae51-7b5f-4eb3-a188-d2c5ac429a02','知府石太尉閑抱瑶琴榮臨圭竇燒筍供膳刻竹題名因成二絕紀而謝之  其一','魏野','宋','宋诗','song-poetry','','[]','分茆人忽到茅齋，踏破溪邊萬點苔。',32,'全唐诗/poet.song.4000.json','["分茆人忽到茅齋，踏破溪邊萬點苔。", "却恐歌鐘喧靜境，隨軒祇背古琴來。"]'),
('b34543f8-5ca9-4006-8843-d6e600f39cf3','知府石太尉閑抱瑶琴榮臨圭竇燒筍供膳刻竹題名因成二絕紀而謝之  其二','魏野','宋','宋诗','song-poetry','','[]','筍就林燒厭八珍，烟爲翠幙草爲茵。',32,'全唐诗/poet.song.4000.json','["筍就林燒厭八珍，烟爲翠幙草爲茵。", "功臣名姓留何處，自把金刀刻翠筠。"]'),
('1b4dc763-ed60-439b-849d-8e0ce1586008','池上閑詠','魏野','宋','宋诗','song-poetry','','[]','微物滿池塘，吟看向夕陽。',48,'全唐诗/poet.song.4000.json','["微物滿池塘，吟看向夕陽。", "草蟲腰盡細，水鳥嘴多長。", "科斗漁翁字，芙蓉野客裳。", "詩成堪寫處，蓮葉碧牋香。"]'),
('b136f8d5-f6af-4478-8a66-c1dd82be7edf','送縣宰王希之闕下','魏野','宋','宋诗','song-poetry','','[]','到任預憂替，替歸貧類初。',48,'全唐诗/poet.song.4000.json','["到任預憂替，替歸貧類初。", "離情似芳草，遠道逐征車。", "遺愛偏留記，行裝祇擔書。", "將來好官職，願載此間除。"]'),
('05db2c48-d493-4c2d-b6b4-5a5306e27172','寄唐異山人','魏野','宋','宋诗','song-poetry','','[]','不見琴書友，相思二十秋。',48,'全唐诗/poet.song.4000.json','["不見琴書友，相思二十秋。", "能消幾度別，便是一生休。", "未得雲迎步，還應雪滿頭。", "何時各携杖，竟去會嵩丘。"]'),
('e80522bc-5ec4-4a64-924e-0f7ce050cad1','送王祕丞赴闕','魏野','宋','宋诗','song-poetry','','[]','詔下儒中選將臣，衆推何處避君恩。',64,'全唐诗/poet.song.4000.json','["詔下儒中選將臣，衆推何處避君恩。", "圖書官職人間美，斧鉞威權閫外尊。", "蘭省交朋迎適願，棠郊寒士送銷魂。", "功成佇聽居藩翰，肯憶漁樵在水村。"]'),
('63be542f-7894-40f6-8345-3c7bd177c3b8','和薛田察院詠雪三首  其一','魏野','宋','宋诗','song-poetry','','[]','林間踏去宜沽酒，石上收來好煮茶。',32,'全唐诗/poet.song.4000.json','["林間踏去宜沽酒，石上收來好煮茶。", "除却子猷當此景，高情偏憶戴逵家。"]'),
('f14636e7-56a0-450f-bb4a-800ef8f13b2b','和薛田察院詠雪三首  其二','魏野','宋','宋诗','song-poetry','','[]','七字空吟六出花，與君無酒祇烹茶。',32,'全唐诗/poet.song.4000.json','["七字空吟六出花，與君無酒祇烹茶。", "門前俱絕行蹤跡，還似袁安卧在家。"]'),
('f3bf4605-0991-45de-bf9c-d3a8d9eb7848','和薛田察院詠雪三首  其三','魏野','宋','宋诗','song-poetry','','[]','密壓溪筠入戶斜，照開睡眼不須茶。',32,'全唐诗/poet.song.4000.json','["密壓溪筠入戶斜，照開睡眼不須茶。", "誰言落處無偏黨，牽率詩家比酒家。"]'),
('c3110cb0-f532-482d-ba35-4d94d35593de','送趙推官赴王太尉辟命','魏野','宋','宋诗','song-poetry','','[]','舊友敦詩將，邊城辟去初。',96,'全唐诗/poet.song.4000.json','["舊友敦詩將，邊城辟去初。", "坐籌銷劍戟，行李減琴書。", "虜帳應先遁，屯田想未鋤。", "蕭關迎有騎，瀚海食無魚。", "家道寧思慮，軍容計慘舒。", "唱籌戎幙靜，登眺戍樓虛。", "馬飲沙河闊，蟬鳴隴樹疏。", "佇看歸闕日，官向粉闈除。"]'),
('8d5d4e94-194f-413e-aef6-e5b5f664da78','新栽葦','魏野','宋','宋诗','song-poetry','','[]','臨砌復臨流，栽初尚未稠。',48,'全唐诗/poet.song.4000.json','["臨砌復臨流，栽初尚未稠。", "長因带風雨，遠似在汀洲。", "靜閒宜紅蓼，閑栖稱白鷗。", "前春應更好，江上夢潛休。"]'),
('15cf0dd2-4854-480f-95e4-f577a360374b','送王太博出鎮桂林','魏野','宋','宋诗','song-poetry','','[]','主上求人鎮大藩，桂林雖遠莫嗟嘆。',64,'全唐诗/poet.song.4000.json','["主上求人鎮大藩，桂林雖遠莫嗟嘆。", "薛能嘉樹非真命，韓愈潮陽是謫官。", "甘雨將沾蠻草潤，仁風先掃瘴煙殘。", "龍鐘不得相隨去，願寄州圖枕石看。"]'),
('213f6df9-ebbb-4835-955e-d4e91d429e5a','謝何學士王專推官王道士同見訪','魏野','宋','宋诗','song-poetry','','[]','閑離錦帳带紗巾，誰從東郊訪隠淪。',64,'全唐诗/poet.song.4000.json','["閑離錦帳带紗巾，誰從東郊訪隠淪。", "舊在幕中珠履客，新遊門下羽衣人。", "掃苔雖是開三徑，採蕨何繇致八珍。", "太史還應怪躔次，郎官星犯客星頻。"]'),
('b80e6883-c488-441f-8a27-ea1077844666','經嵩陽廢觀因有戲題','魏野','宋','宋诗','song-poetry','','[]','嵩陽多廢觀，欲驗少碑文。',48,'全唐诗/poet.song.4000.json','["嵩陽多廢觀，欲驗少碑文。", "地屬村夫子，苔漫石老君。", "草生泉更浸，松死燒猶焚。", "欲問神仙事，悠悠空白雲。"]'),
('84a26c48-41e4-49f4-b826-11590e2f5d22','送馮介迎覲','魏野','宋','宋诗','song-poetry','','[]','離聲無管絃，空把指頻彈。',48,'全唐诗/poet.song.4000.json','["離聲無管絃，空把指頻彈。", "惟子猶爲客，何人不作官。", "前程貧豈易，後會老應難。", "拜想高堂下，麻衣淚始乾。"]'),
('41a506a3-fa52-4dc5-b7fd-183301581950','送無用上人遊中條','魏野','宋','宋诗','song-poetry','','[]','迢遞中條寺，秋尋忘險途。',48,'全唐诗/poet.song.4000.json','["迢遞中條寺，秋尋忘險途。", "屐蹤臨水有，錫影入雲無。", "像閣分秦樹，經窗見舜都。", "我曾題壁處，閑看想踟躕。"]'),
('076f8a1e-ef55-4cdf-b41f-65be23b0f0d2','秋夜與陳孟話別','魏野','宋','宋诗','song-poetry','','[]','草堂燈暗雨蕭蕭，欲話分携重鬰陶。',32,'全唐诗/poet.song.4000.json','["草堂燈暗雨蕭蕭，欲話分携重鬰陶。", "何事琴中猶怨切，凄凉調裏鼓離騷。"]'),
('f841a50b-5963-4cbd-981d-9799b48ee4df','寄盩厔知縣解旦著作','魏野','宋','宋诗','song-poetry','','[]','盩厔樂天初任地，此時君又繼多才。',32,'全唐诗/poet.song.4000.json','["盩厔樂天初任地，此時君又繼多才。", "閒應時到遊仙寺，石上題詩掃綠苔。"]'),
('364af14f-e99d-425d-b710-2ee2893c2e86','三門留題','魏野','宋','宋诗','song-poetry','','[]','何由通九曲，始自鑿三門。',168,'全唐诗/poet.song.4000.json','["何由通九曲，始自鑿三門。", "夏禹功如小，東溟位豈尊。", "黿鼉當日窟，雞犬此時村。", "渦恐和山漩，濤疑若石奔。", "勢愁舂地軸，聲想震天閽。", "寺廟中流聳，煙雲兩岸屯。", "樓臺疑蜃吐，舟檝畏鯨吞。", "遊客雖驚險，居僧不厭喧。", "如潮無振鷺，似峽欠啼猿。", "孤店經商少，雄司漕運繁。", "人家無釣具，鳥道有䉡痕。", "喪膽尋遺跡，傷心弔溺魂。", "坼城唐記列，砥柱祖名存。", "況復詩書載，狂題愧雅言。"]'),
('67c42803-4765-430f-82c5-c196573bedd2','寄俞太中山人','魏野','宋','宋诗','song-poetry','','[]','相訪住三年，初終道一般。',48,'全唐诗/poet.song.4000.json','["相訪住三年，初終道一般。", "知心於我異，屈指似君難。", "有物皆同詠，無書不共看。", "草堂今獨處，寧免動長嘆。"]'),
('a841311c-0624-4cab-8f7a-d0ad23314558','登龍門縣樓與知宰劉大著將話別因有題紀','魏野','宋','宋诗','song-poetry','','[]','名士爲官處，登樓景好題。',48,'全唐诗/poet.song.4000.json','["名士爲官處，登樓景好題。", "縣城蠶市鬧，村墅鵲巢低。", "日暖園蔬嫩，煙晴壠麥齊。", "長宜同此望，那忍話分携。"]'),
('24aaf9b8-dd92-4874-bb0d-c0df46f21ab7','夏日懷寄西川峽路淮南薛臧王三運使','魏野','宋','宋诗','song-poetry','','[]','運使幽人酷暑時，江邊林下兩何爲。',64,'全唐诗/poet.song.4000.json','["運使幽人酷暑時，江邊林下兩何爲。", "信旗君逐舟車動，懶架吾隨枕簟移。", "繡袂幾經梅雨灑，葛衣一任竹風吹。", "蜀山淮甸棠郊外，早晚相逢豁所思。"]'),
('251191ee-7bca-4ac1-806b-737726bfcb0d','贈王氏神童昆季','魏野','宋','宋诗','song-poetry','','[]','先後登科出玉京，滿朝詩送更光榮。',32,'全唐诗/poet.song.4000.json','["先後登科出玉京，滿朝詩送更光榮。", "豈唯皇宋終難繼，自古神童少弟兄。"]'),
('9ef772e6-bbc6-4605-8c93-03b32a9239dd','送俞太中山人歸終南','魏野','宋','宋诗','song-poetry','','[]','俞貫之辭魏仲先，終南歸去落花天。',32,'全唐诗/poet.song.4000.json','["俞貫之辭魏仲先，終南歸去落花天。", "如何相見還相別，早晚溪雲一處眠。"]'),
('40d31573-ddf5-466c-8eed-a05eb75ba9ef','題鄠縣楊氏書樓','魏野','宋','宋诗','song-poetry','','[]','竹多千畝餘，賣竹濟貧儒。',48,'全唐诗/poet.song.4000.json','["竹多千畝餘，賣竹濟貧儒。", "門掩圭峰影，樓添鄠縣圖。", "蝸涎緣棟有，鶴跡入泉無。", "終約重來此，相鄰卜養愚。"]'),
('03cc4ea1-eb59-47d3-970b-0737b8794e32','送任秉南歸','魏野','宋','宋诗','song-poetry','','[]','歸覲江山遠，如何敘別離。',48,'全唐诗/poet.song.4000.json','["歸覲江山遠，如何敘別離。", "數盃村店酒，一首野人詩。", "趁渡憐舟穩，貪程恨馬羸。", "遥思到家日，已過落花時。"]'),
('695724ab-b84d-4ab0-ab2c-c62e99454411','偶作呈諤閏二上人','魏野','宋','宋诗','song-poetry','','[]','老雖無悶向茅堂，忽忽還因物感傷。',64,'全唐诗/poet.song.4000.json','["老雖無悶向茅堂，忽忽還因物感傷。", "積霧易迷平地水，孤雲難護滿天霜。", "祥麟可向清時見，驚鶴那於黑處藏。", "信意偶然成此詠，祇堪閑寫與支郎。"]'),
('62f210e2-b87f-402a-a650-3d7ac0fb475e','和人見詠新鶴','魏野','宋','宋诗','song-poetry','','[]','雪霜毛羽瘦形儀，養處人家覺道肥。',64,'全唐诗/poet.song.4000.json','["雪霜毛羽瘦形儀，養處人家覺道肥。", "龜有壽齡方可近，鷺無仙分莫相依。", "千年松上疑孤立，五色雲中好並飛。", "不競巢栖爭飲啄，也應難免衆禽非。"]'),
('572acf92-378b-4ed2-935c-467e1089b18f','出戶','魏野','宋','宋诗','song-poetry','','[]','出戶下莎庭，徘徊當踏青。',48,'全唐诗/poet.song.4000.json','["出戶下莎庭，徘徊當踏青。", "靜嫌鶑鬭舌，閑愛鶴梳翎。", "雲好昂頭望，松宜側耳聽。", "便堪爲導列，誰信可延齡。"]'),
('80e59bbb-c3dd-4f67-8db3-9736d6aa91e3','次韻和薛端公歸故里之什二首  其一','魏野','宋','宋诗','song-poetry','','[]','茜旗影裏椹袍身，迎入蒲津免問津。',64,'全唐诗/poet.song.4000.json','["茜旗影裏椹袍身，迎入蒲津免問津。", "策蹇去時爲舉子，乘驄歸日是功臣。", "豈同化鶴千餘歲，纔過登龍十數春。", "開宴仍聞傾錫賜，酣歌喜殺故鄉人。"]'),
('5140b94c-0934-46fa-9520-1fa3a109e23b','次韻和薛端公歸故里之什二首  其二','魏野','宋','宋诗','song-poetry','','[]','尚輟通儒外計籌，堂堂身豈等閑酬。',64,'全唐诗/poet.song.4000.json','["尚輟通儒外計籌，堂堂身豈等閑酬。", "綺羅笑別文翁郡，錦繡榮歸舜帝州。", "貰酒村穿紅樹過，讀書寺入翠嵐遊。", "逍遥樓對家山逈，得意詩銷此處留。"]'),
('e6b5d64b-0c03-492f-a04b-40d331dbb1fe','聞雷宣徽薨背敕葬歸鄉','魏野','宋','宋诗','song-poetry','','[]','聖代賢臣喪，何人不慘顔。',48,'全唐诗/poet.song.4000.json','["聖代賢臣喪，何人不慘顔。", "新祠民祭祀，舊債帝填還。", "鹵簿塵侵暗，銘旌淚灑斑。", "功名誰復繼，敕葬向家山。"]'),
('921790e6-1a77-485b-9418-2fc4dad8db84','和馮亞寄進士孫磻','魏野','宋','宋诗','song-poetry','','[]','閑思生白髮，懶更把菱花。',48,'全唐诗/poet.song.4000.json','["閑思生白髮，懶更把菱花。", "久別何州住，相尋恐路差。", "獨飛傷塞鴈，會宿羨林鴉。", "猶得君爲友，時過老母家。"]'),
('f119f751-c233-4082-acd1-bc8b44ea1661','送唐肅察院赴闕兼呈府尹孫大諫','魏野','宋','宋诗','song-poetry','','[]','東郊祖帳慘西風，愁聽陽關曲調終。',64,'全唐诗/poet.song.4000.json','["東郊祖帳慘西風，愁聽陽關曲調終。", "赤子泣皆牽繡袂，白馿鳴亦戀花驄。", "觸邪暫立龍墀下，儤直將歸鳳閣中。", "大尹相逢憑仗說，官高不敢寄詩筒。"]'),
('62be4f2e-ed06-49db-b9c6-aceb973d54b8','和酬益州劉大著同運使薛端公見寄之什','魏野','宋','宋诗','song-poetry','','[]','遥思錦水會荀陳，共指棠郊憶卧雲。',64,'全唐诗/poet.song.4000.json','["遥思錦水會荀陳，共指棠郊憶卧雲。", "青眼雖然蒙望我，丹心不覺恨輸君。", "離情杳杳三千里，老病厭厭八九分。", "唯待急徵同赴闕，一時得見向溪濆。"]'),
('599d93b8-d2e4-4e37-9847-fb1ecc168748','遊藍田王順山晤真寺','魏野','宋','宋诗','song-poetry','','[]','藍田王順昇仙處，白傅曾題似更稀。',64,'全唐诗/poet.song.4000.json','["藍田王順昇仙處，白傅曾題似更稀。", "野客暫遊期欲住，山禽何事叫思歸。", "稱心不獨煙霞媚，適口仍逢筍蕨肥。", "兩日正當寒食日，家園忘却有芳菲。"]'),
('1d23af1d-83c6-40d3-aa61-574d2b9ee49f','留題仙遊寺','魏野','宋','宋诗','song-poetry','','[]','將從三峽泛扁舟，先向仙遊寺裏遊。',32,'全唐诗/poet.song.4000.json','["將從三峽泛扁舟，先向仙遊寺裏遊。", "水石却驚偏怪異，江山狂興一時休。"]'),
('ce9a8405-f6ed-44b3-b309-6741f6c6d8e1','清明日離藍田白鹿原寄王太博','魏野','宋','宋诗','song-poetry','','[]','白鹿原東曉色中，人家新火翠煙濃。',32,'全唐诗/poet.song.4000.json','["白鹿原東曉色中，人家新火翠煙濃。", "豈惟心友難爲別，馿上迴頭戀玉峰。"]'),
('ce5baaa8-9a95-432f-81e4-b7e91ca5ff3a','寄淮南制置使薛戶部','魏野','宋','宋诗','song-poetry','','[]','西自荆巫徹海涯，南從吳越接京華。',224,'全唐诗/poet.song.4000.json','["西自荆巫徹海涯，南從吳越接京華。", "半天下管權何重，兩地間遊路不賒。", "山澤利均資我國，江湖境盡屬君家。", "帝心已簡身寧愧，使額雖雄性不奢。", "數道轉輸歸檢察，滿朝才子動吟誇。", "搜尋奸詐窮毫髮，舉薦廉能在齒牙。", "彩旆雙飄爲從物，畫船一簇是行衙。", "已聞村落添農器，漸見汀洲減釣車。", "不使菰蒲侵黍稷，將令橘柚變桑麻。", "台州頂自尋仙藥，建水湄親採御茶。", "器量寬如波浩渺，風謠多似櫓嘔鴉。", "閑尋僧話穿雲葉，靜聽漁歌隔浪花。", "野客唱酬容散拙，郡侯迎送厭喧譁。", "携筇未遂攀陪去，溪士時時動嘆嗟。"]'),
('57e0c439-932e-4b87-992a-538b4a969581','懷宗人仲容','魏野','宋','宋诗','song-poetry','','[]','尋常念朋友，況復是宗人。',48,'全唐诗/poet.song.4000.json','["尋常念朋友，況復是宗人。", "久別彈琴少，相思擲卦頻。", "旅遊湘水遠，家寄華山貧。", "早晚重來此，園林又過春。"]'),
('64a9b77b-e885-4dd8-843a-31c3b0711740','和何學士見詠新得鶴','魏野','宋','宋诗','song-poetry','','[]','喜得華亭鶴，看承過所宜。',48,'全唐诗/poet.song.4000.json','["喜得華亭鶴，看承過所宜。", "防饑先種稻，憂病預鑽龜。", "易愜眠雲意，難酬卧錦詩。", "不緣過郡謝，步步在相隨。"]'),
('e0140a63-c55c-4543-96a2-d907c22a33d3','夏日雨中題諤師房','魏野','宋','宋诗','song-poetry','','[]','夏雨下如繩，虛廊減鬰蒸。',48,'全唐诗/poet.song.4000.json','["夏雨下如繩，虛廊減鬰蒸。", "濺琴移榻避，添硯就簷承。", "暗喜同田父，閑聽共野僧。", "苦吟題壁上，欲改更慵能。"]'),
('05df7088-7ea0-4fc6-9411-090196aec539','送外甥李渭進士赴舉','魏野','宋','宋诗','song-poetry','','[]','棠樹掄材過禮闈，孤寒得解更光輝。',64,'全唐诗/poet.song.4000.json','["棠樹掄材過禮闈，孤寒得解更光輝。", "進身喜逐賢侯表，裹足愁分老母衣。", "千里冬殘傷獨去，一家春盡待榮歸。", "頭方念爾還如我，到闕何人許扣扉。"]'),
('a39bf4a9-f1b7-4a6b-add3-0eb1fbaf501e','和酬入內趙供奉見贈','魏野','宋','宋诗','song-poetry','','[]','出入宮闈侍從官，再過林下信溫顔。',64,'全唐诗/poet.song.4000.json','["出入宮闈侍從官，再過林下信溫顔。", "朝天駐足因臨水，馳馹迴頭入望山。", "捧詔正當趨桂殿，寄詩那忽到松關。", "老來詩思尤枯竭，莫怪陽春不旋還。"]'),
('c971e64d-427d-4a75-b7d4-4540ed476199','和薛察院同龍門知縣劉大著洎數公禹廟留題','魏野','宋','宋诗','song-poetry','','[]','七人廟下立徘徊，相顧閑心幾欲摧。',32,'全唐诗/poet.song.4000.json','["七人廟下立徘徊，相顧閑心幾欲摧。", "落日堪傷四散去，再來難得一齊來。"]'),
('91fb0f5b-38f5-4aae-8d4c-7efbb398efbb','三峰王耿殿丞將移陝下通理先已同袁刑部以唱和詩見寄因次前韻和酬二首  其一','魏野','宋','宋诗','song-poetry','','[]','君移棠樹民皆喜，我住東郊却懶誇。',64,'全唐诗/poet.song.4000.json','["君移棠樹民皆喜，我住東郊却懶誇。", "拙性怕逢詩債主，病身愁見酒讎家。", "郢詞溫潤如絲雨，蜀紙鮮明似綺霞。", "況是已經仙手和，點頭空使角冠斜。"]'),
('aa925ccd-77a8-4507-a5b6-d6224a9358c9','三峰王耿殿丞將移陝下通理先已同袁刑部以唱和詩見寄因次前韻和酬二首  其二','魏野','宋','宋诗','song-poetry','','[]','蜀出多才信不虛，淹翔猶未佩銀符。',64,'全唐诗/poet.song.4000.json','["蜀出多才信不虛，淹翔猶未佩銀符。", "民間惠愛應長有，馬上歌詩豈暫無。", "休話卜鄰來草澤，即看得路去蓬壺。", "申湖公暇閑遊地，賀監何須說鑑湖。"]'),
('8aa8f1d3-8120-4cf2-8aec-9a449174ec32','百舌鳥','魏野','宋','宋诗','song-poetry','','[]','長截鄰雞叫五更，數般名字百般聲。',32,'全唐诗/poet.song.4000.json','["長截鄰雞叫五更，數般名字百般聲。", "饒伊饒舌爭先曉，也待青天明即鳴。"]'),
('69077928-1c8b-4a0b-a8a3-2036a5a933d4','送吳石赴舉','魏野','宋','宋诗','song-poetry','','[]','吳生重赴舉，輕別重傷心。',48,'全唐诗/poet.song.4000.json','["吳生重赴舉，輕別重傷心。", "貧友欲沽酒，豪家不典琴。", "溪僧來會送，國士到爭尋。", "預想登科後，無因訪竹林。"]'),
('04c8fc52-fa7d-418a-8afe-bbcbc5130b48','暮秋閑望','魏野','宋','宋诗','song-poetry','','[]','水閣閑登望，郊原欲刈禾。',48,'全唐诗/poet.song.4000.json','["水閣閑登望，郊原欲刈禾。", "壞簷巢燕少，積雨病蟬多。", "砧隔寒溪搗，鐘隨晚吹過。", "扁舟何日去，江上負煙簑。"]'),
('1cff47c7-f9c1-4d04-b13b-9b5897caf1fb','懷寄眉山知縣王闢寺丞','魏野','宋','宋诗','song-poetry','','[]','仲先別仲通，長憶又長慵。',48,'全唐诗/poet.song.4000.json','["仲先別仲通，長憶又長慵。", "有夢應相信，無書想見容。", "塵埃五十驛，山水幾千重。", "老去難尋訪，何時得再逢。"]'),
('7934ddec-b686-484f-b4b4-adb4b9766f34','送王太博抽赴闕','魏野','宋','宋诗','song-poetry','','[]','憲府吾皇注意偏，君今應詔合居先。',64,'全唐诗/poet.song.4000.json','["憲府吾皇注意偏，君今應詔合居先。", "蛾眉班綴千官上，廌角威揚萬乘前。", "貴戚望風從此日，貧交披霧是何年。", "難忘枉駕相辭處，草屋門開雪滿天。"]'),
('25816193-37f2-4041-9322-4fc219507eec','薛端公寄示嘉川道中作次韻和酬','魏野','宋','宋诗','song-poetry','','[]','繡衣不間薜蘿衣，春暮嘉川入詠思。',64,'全唐诗/poet.song.4000.json','["繡衣不間薜蘿衣，春暮嘉川入詠思。", "憶我茅廬欹枕處，當君驄馬著鞭時。", "展眉喜近龍頭境，回首傷遥鶴髮期。", "從此親題山館裏，多情頓掩浪仙詩。"]'),
('b216a863-f483-4482-878f-d474ee5d9d81','送劉燁大著移任龍門知縣','魏野','宋','宋诗','song-poetry','','[]','天上書先夢裏傳，到施仁政減春寒。',64,'全唐诗/poet.song.4000.json','["天上書先夢裏傳，到施仁政減春寒。", "尚虛鼇嶺神仙任，暫作龍門父母官。", "愁悶豈惟增假寐，笑談直恐絕真歡。", "不緣潦倒長相逐，免得離情有萬端。"]'),
('6dfc6361-e819-44bf-9cc5-3ae3e9d12185','送壽師新加命服後歸蜀','魏野','宋','宋诗','song-poetry','','[]','日照孤雲作彩霞，帝鄉風送去天涯。',32,'全唐诗/poet.song.4000.json','["日照孤雲作彩霞，帝鄉風送去天涯。", "野人遥望歸何處，萬里峨嵋便是家。"]'),
('c3393a5c-0832-4711-8529-f0a49326541e','寄陳越學士','魏野','宋','宋诗','song-poetry','','[]','損之不見數年餘，萬種相思一事無。',32,'全唐诗/poet.song.4000.json','["損之不見數年餘，萬種相思一事無。", "唯有近來茅屋夢，爲君時復到皇都。"]'),
('29980bb0-b111-4273-a0d7-d4d729545194','書閏師白蓮堂','魏野','宋','宋诗','song-poetry','','[]','野人禪客合相陪，漸老詩心亦共灰。',64,'全唐诗/poet.song.4000.json','["野人禪客合相陪，漸老詩心亦共灰。", "朱草階前容不去，白蓮堂上喜頻來。", "地形各占幽深境，天産俱爲散逸材。", "猶恨東郊西寺遠，閑門難並水邊開。"]'),
('5c879187-418a-403f-915c-438e101e3208','寄陳越學士託附魏仲容','魏野','宋','宋诗','song-poetry','','[]','取次昇沈論等差，雲霄獨不忘泥沙。',64,'全唐诗/poet.song.4000.json','["取次昇沈論等差，雲霄獨不忘泥沙。", "常流對面如千里，密友終身似一家。", "魂夢因君遊輦轂，書題爲我寄煙霞。", "仲容到日還應說，半紀相思兩鬢華。"]'),
('30a7c411-2dad-4cad-80ac-ba4514667cbc','送王專王衢之許下自維揚謁孫學士王舍人','魏野','宋','宋诗','song-poetry','','[]','蹇馿並跨引羸僮，兩地迢迢謁至公。',64,'全唐诗/poet.song.4000.json','["蹇馿並跨引羸僮，兩地迢迢謁至公。", "才力互相鸚鵡敵，交情深與鶺鴒同。", "薛能詩在僧樓上，張祜名題酒肆中。", "到日知君尋賞處，醉吟還可繼遺風。"]'),
('5dbe8179-8c69-47d5-ad28-92cb1aa3554b','送錢國博知坊州','魏野','宋','宋诗','song-poetry','','[]','遥爲坊民賀一方，壽星偏去照光芒。',64,'全唐诗/poet.song.4000.json','["遥爲坊民賀一方，壽星偏去照光芒。", "解携朋友龍三處，隨侍兒孫鴈兩行。", "芳草路中車突兀，落花風裏旆悠颺。", "眠雲客恨難陪從，空遣吟魂倍慘傷。"]'),
('9337fcb5-231c-42a3-95d3-890a02500062','上知府李殿院十韻','魏野','宋','宋诗','song-poetry','','[]','詔選來棠樹，花驄擁旆乘。',120,'全唐诗/poet.song.4000.json','["詔選來棠樹，花驄擁旆乘。", "饑民期再活，寒士賀中興。", "廌角誰傷觸，狼心自戰兢。", "只求天子信，寧避世家憎。", "竊聽無餘論，唯愁有急徵。", "每因公宴樂，方遣妓祗承。", "才薄終難紀，情深豈易勝。", "相親容似鶴，不拜許如僧。", "郡閣招看雪，溪亭訪躡冰。", "轉愁詩老退，何以答褒稱。"]'),
('3ca000ae-5662-4e56-b286-784b8cda4fad','新井','魏野','宋','宋诗','song-poetry','','[]','林間鑿井新，里巷汲來頻。',48,'全唐诗/poet.song.4000.json','["林間鑿井新，里巷汲來頻。", "及見贏瓶者，翻思抱甕人。", "乍嘗牙覺冷，試煮茗尤珍。", "從此前溪水，潛輕似不仁。"]'),
('72387911-fffc-4d8a-9ecf-73bc93e2cff8','書黄池谷王山長屋壁','魏野','宋','宋诗','song-poetry','','[]','仲先曾到仲淹家，書院穿雲一徑斜。',32,'全唐诗/poet.song.4000.json','["仲先曾到仲淹家，書院穿雲一徑斜。", "勸酒莫言無樂送，音聲鳥語在山花。"]'),
('38d89568-91b8-436e-986e-1b9634b66ab6','送楊侍禁赴闕時有甄先生相隨','魏野','宋','宋诗','song-poetry','','[]','一種皇華覲紫宸，文資換必異常倫。',64,'全唐诗/poet.song.4000.json','["一種皇華覲紫宸，文資換必異常倫。", "隨軒已有三茅客，下榻寧無兩制人。", "清洛聽應移足懶，碧嵩看想轉頭頻。", "他時乞得休官後，莫負前言作善鄰。"]'),
('00d87fe8-b683-454a-8b37-545ca8329669','和蹇藏用暮秋郊居言懷二首  其一','魏野','宋','宋诗','song-poetry','','[]','村落秋窮興莫窮，黄花紅葉照衰容。',64,'全唐诗/poet.song.4000.json','["村落秋窮興莫窮，黄花紅葉照衰容。", "時平轉稱千般巧，年長仍添一倍慵。", "林下携筇聞遠水，洞中欹枕見前峰。", "與君鄰里何相似，來往人多是老農。"]'),
('e5ca3e7e-b083-4b35-b302-087c4169502b','和蹇藏用暮秋郊居言懷二首  其二','魏野','宋','宋诗','song-poetry','','[]','敢學宣尼歎道窮，閑心何處不相容。',64,'全唐诗/poet.song.4000.json','["敢學宣尼歎道窮，閑心何處不相容。", "交朋盡笑龜蒙散，鄰里偏諳叔夜慵。", "晚吹清泠彫萬木，殘霞紅澹映三峰。", "爲憐今歲於中稔，欲遣兒孫亦務農。"]'),
('83ec931a-9643-4485-ae95-0c08e2459007','謝劉小諫寄惠雙鶴','魏野','宋','宋诗','song-poetry','','[]','令威兄弟涉煙波，諫署人教到薜蘿。',64,'全唐诗/poet.song.4000.json','["令威兄弟涉煙波，諫署人教到薜蘿。", "毛比君情猶恐少，格如我性不爭多。", "相呼似說沖霄意，對舞初聞擊壤歌。", "仙術無能騎謝去，青雲未免阻閑過。"]'),
('d1038fc6-2bf1-413e-ae5d-fa2ffb1fd723','次韻和同理王耿殿丞見贈','魏野','宋','宋诗','song-poetry','','[]','年來暫屈佐元戎，富貴真宜在蕊宮。',64,'全唐诗/poet.song.4000.json','["年來暫屈佐元戎，富貴真宜在蕊宮。", "性潔恥分錢子母，時清懶話劍雌雄。", "公心似水逢形鑑，和氣如春觸物融。", "莫道州民俱受賜，好詩徧得有誰同。"]'),
('f4080942-ddb8-45f5-8c6f-5e253f819d46','送唐殿院罷蜀中提刑赴詔兼呈孫大諫','魏野','宋','宋诗','song-poetry','','[]','花驄出蜀瘦行難，急詔乘軺定峻遷。',64,'全唐诗/poet.song.4000.json','["花驄出蜀瘦行難，急詔乘軺定峻遷。", "清雪人如辭父母，白雲客似別神仙。", "堪曉望晴霞爛熳，伴宵征暑月團圓。", "寄語集賢孫大諫，莫嫌未和舊詩篇。"]'),
('f3fe662f-e390-430e-8230-190df8844615','雪中書事上李階殿院','魏野','宋','宋诗','song-poetry','','[]','草堂高逈樂郊東，西望搘筇景莫窮。',64,'全唐诗/poet.song.4000.json','["草堂高逈樂郊東，西望搘筇景莫窮。", "山水城池雲葉裏，管絃樓閣雪花中。", "須知應瑞因仁政，不獨呈祥自帝功。", "太守多才又多暇，唱酬翻怯見詩筒。"]'),
('46b87235-7674-4fd2-b574-929d487bfc3d','獨酌吟','魏野','宋','宋诗','song-poetry','','[]','獨酌獨吟誰與共，天爲知己月爲朋。',32,'全唐诗/poet.song.4000.json','["獨酌獨吟誰與共，天爲知己月爲朋。", "水邊醉卧無人見，席有煙莎枕有肱。"]'),
('cdbd537e-52d1-4870-a3b5-e5ab9263272c','謝薛省判寄惠鶴','魏野','宋','宋诗','song-poetry','','[]','早輟仙禽寄逸民，年來亦似厭家貧。',32,'全唐诗/poet.song.4000.json','["早輟仙禽寄逸民，年來亦似厭家貧。", "時時東望長鳴處，應憶朱門舊主人。"]'),
('8c11fffb-43a0-449b-b767-5f0ee5fbbea8','送蕭咨下第西歸','魏野','宋','宋诗','song-poetry','','[]','馿瘦懶加鞭，遲遲念獨還。',48,'全唐诗/poet.song.4000.json','["馿瘦懶加鞭，遲遲念獨還。", "聽雞行曉月，歎雉過春山。", "渭入黄河濁，雲歸紫閣閑。", "明年公道在，莫便掩松關。"]'),
('5d6e39e7-76ca-42a8-8e9d-df4f09ae54c4','謝張中允見訪','魏野','宋','宋诗','song-poetry','','[]','園林花未發，豈是爲遊春。',48,'全唐诗/poet.song.4000.json','["園林花未發，豈是爲遊春。", "深愧青宮客，先尋白屋人。", "兒童驚茜綬，僕隸笑紗巾。", "踏雪携詩謝，朱門必許親。"]'),
('cead301c-3ffd-4277-adec-b211ac2382bf','送魏莊赴舉','魏野','宋','宋诗','song-poetry','','[]','再戰去何如，羸僮逐蹇馿。',48,'全唐诗/poet.song.4000.json','["再戰去何如，羸僮逐蹇馿。", "路貧多捧刺，學富少擔書。", "已念離家晚，仍憂取事疏。", "西風酒旗下，欲別更躊躇。"]'),
('e9e8d8e3-4e91-4285-b2dd-a049cb043021','酬和知府李殿院見訪之什往來不休因成四首  其一','魏野','宋','宋诗','song-poetry','','[]','暫擁紅旌到郡新，相知情似舊交親。',64,'全唐诗/poet.song.4000.json','["暫擁紅旌到郡新，相知情似舊交親。", "盡驚慷慨山河主，忽訪支離草澤人。", "蘇徑讓慚揚繡袂，溪橋迎喜整紗巾。", "留詩中貴仍揮翰，雙美應難繼後塵。"]'),
('8c5cc91c-e1f6-4e8c-bee0-0a67a9ea1cf1','酬和知府李殿院見訪之什往來不休因成四首  其二','魏野','宋','宋诗','song-poetry','','[]','玉韻重聽倍爽神，銀鈎忽睹更躬親。',64,'全唐诗/poet.song.4000.json','["玉韻重聽倍爽神，銀鈎忽睹更躬親。", "郡侯喜是風騷主，野客慚爲唱和人。", "積霧曾侵紅繡旆，異香猶惹白綸巾。", "兩篇篋裏貞珉上，頻拂看寧有蠹塵。"]'),
('3c1c8e93-db7b-47f6-8c2b-13b3f0a4f6d1','酬和知府李殿院見訪之什往來不休因成四首  其三','魏野','宋','宋诗','song-poetry','','[]','使君悞訪樂郊民，顧我何由得暫親。',64,'全唐诗/poet.song.4000.json','["使君悞訪樂郊民，顧我何由得暫親。", "茜旆動驅千百騎，茅亭纔著兩三人。", "旋燒陸羽烹茶鼎，忙換陶潛漉酒巾。", "可愛水邊松竹上，數朝猶自有香塵。"]'),
('011561ae-2942-4f69-858a-f5d5b0294ae5','酬和知府李殿院見訪之什往來不休因成四首  其四','魏野','宋','宋诗','song-poetry','','[]','雖喜乘驄到水村，却愁詩敵勢難親。',64,'全唐诗/poet.song.4000.json','["雖喜乘驄到水村，却愁詩敵勢難親。", "平生未豎降旗客，臨老將爲棄甲人。", "豸角勇無心害物，雞皮怯有汗沾巾。", "數篇勉和情枯竭，潦倒詞鋒息戰塵。"]'),
('ff653569-a8ba-483b-a716-013cf6678363','送王太博知建昌軍','魏野','宋','宋诗','song-poetry','','[]','莫歎三山隔五雲，建昌境好說紛紛。',64,'全唐诗/poet.song.4000.json','["莫歎三山隔五雲，建昌境好說紛紛。", "雖然尚作貧才子，猶免潛呼老使君。", "遠逐朱輪輸鴈陣，閑親畫舸羨鷗羣。", "棠郊獨恨分携後，高論何時得再聞。"]'),
('f0d60d24-b03e-46ef-aef7-c9021bb8cbb0','暮春雨中作','魏野','宋','宋诗','song-poetry','','[]','獨院信寥寥，蠶生穀未苗。',48,'全唐诗/poet.song.4000.json','["獨院信寥寥，蠶生穀未苗。", "殘春無數日，積雨復連宵。", "不恨流光速，唯傷去聖遥。", "那堪當此景，時見落花飄。"]'),
('84a665ef-6382-4062-8897-ca7f90c2dcb3','送蹇藏用之平陽','魏野','宋','宋诗','song-poetry','','[]','蜀客貧遊晉，山川木落空。',48,'全唐诗/poet.song.4000.json','["蜀客貧遊晉，山川木落空。", "軍閑無虜寇，俗儉有堯風。", "鴈急長天外，馿遲落照中。", "聖君方選士，莫便歎途窮。"]'),
('c65b2195-d3bb-442b-88af-3f0a61012c4a','和絳臺王都官見寄春日書事之什','魏野','宋','宋诗','song-poetry','','[]','絳郡政閑聞，人家可閉門。',48,'全唐诗/poet.song.4000.json','["絳郡政閑聞，人家可閉門。", "馬嘶花下路，犬睡月中村。", "吏亦擎書卷，民皆挈酒樽。", "行春思隠逸，多謝動吟魂。"]'),
('b0257792-47e2-4176-b9c7-588ad5ac621b','送袁景宗之荆渚寧覲','魏野','宋','宋诗','song-poetry','','[]','荆渚北堂寧聖善，棠陰東閣別嚴君。',32,'全唐诗/poet.song.4000.json','["荆渚北堂寧聖善，棠陰東閣別嚴君。", "雪村山館思親夢，二十餘宵兩處分。"]'),
('548d9406-ff52-40b5-9a73-9efe9f2a0ceb','寄龐房','魏野','宋','宋诗','song-poetry','','[]','愛於瘦馬上吟詩，孟浩然真更似誰。',32,'全唐诗/poet.song.4000.json','["愛於瘦馬上吟詩，孟浩然真更似誰。", "雅稱自將圖畫看，況君小筆勝王維。"]'),
('e4657ba6-3dc8-48f6-891e-62eccc544ffe','和酬李殿院見訪之什','魏野','宋','宋诗','song-poetry','','[]','清嫌水有不清泠，閑擁朱輪扣掩扃。',64,'全唐诗/poet.song.4000.json','["清嫌水有不清泠，閑擁朱輪扣掩扃。", "樂廣喜披溪上霧，戴逵慚認月邊星。", "高情稱就雲爲幕，雅詠宜鎸石作屏。", "竹裏小亭從此後，因君堪號降賢亭。"]'),
('ff88b8e5-bce4-4ceb-b03a-64d5815cf224','寄題閿鄉李氏茅亭','魏野','宋','宋诗','song-poetry','','[]','閿鄉右邑有吾親，河上茅亭結構新。',64,'全唐诗/poet.song.4000.json','["閿鄉右邑有吾親，河上茅亭結構新。", "五老分明爲北里，三峰咫尺是西鄰。", "兒孫不厭閑遊客，鷗鷺偏諳醉主人。", "彼此眠雲相隠夢，從今應更往還頻。"]'),
('718a7728-b9f6-43e0-bb1c-5722b2a91f98','和酬李殿院以野將遊吳蜀二首  其一','魏野','宋','宋诗','song-poetry','','[]','將從兩蜀下三湘，清世那憂道路長。',64,'全唐诗/poet.song.4000.json','["將從兩蜀下三湘，清世那憂道路長。", "杖屨雖然遊自在，旌旗寧免別淒凉。", "召公化實宜歌詠，謝傅詩尤愧發揚。", "願得德星歸未動，光芒依舊照毫芒。"]'),
('64e0db6c-9f17-4203-9f5c-de63d417eeca','和酬李殿院以野將遊吳蜀二首  其二','魏野','宋','宋诗','song-poetry','','[]','携得筇枝背得琴，欲浮蜀浪陟吳岑。',64,'全唐诗/poet.song.4000.json','["携得筇枝背得琴，欲浮蜀浪陟吳岑。", "本期勝境酬雙眼，却恨虛名阻片心。", "出似蓬飄寧免醉，住如匏繫不妨吟。", "重酬雅詠重思想，太守相留意最深。"]'),
('4c5af505-f559-4a0e-8add-9bd3297c4a89','上知府大同王太尉六首  其一','魏野','宋','宋诗','song-poetry','','[]','兩地曾辭最重權，功如溫樹懶能言。',32,'全唐诗/poet.song.4000.json','["兩地曾辭最重權，功如溫樹懶能言。", "從來富貴知何限，少有元戎是狀元。"]'),
('0558669c-1e0f-416b-88b8-4077507a65fe','上知府大同王太尉六首  其二','魏野','宋','宋诗','song-poetry','','[]','暫輟居留從洛邑，坐棠亦恐不多時。',32,'全唐诗/poet.song.4000.json','["暫輟居留從洛邑，坐棠亦恐不多時。", "皇儲新策聞求輔，位冠春宮更是誰。"]'),
('5da0b275-21d8-4453-aafb-c30115746913','上知府大同王太尉六首  其三','魏野','宋','宋诗','song-poetry','','[]','五等諸侯稀五福，三朝官只欠三台。',32,'全唐诗/poet.song.4000.json','["五等諸侯稀五福，三朝官只欠三台。", "下車一變熙熙景，賓閤多開印少開。"]'),
('f8844368-7d52-4173-8eb8-7eb25dad4b3e','上知府大同王太尉六首  其四','魏野','宋','宋诗','song-poetry','','[]','健擁旌幢七十餘，苦吟還似在山居。',32,'全唐诗/poet.song.4000.json','["健擁旌幢七十餘，苦吟還似在山居。", "腹中萬卷猶嫌少，更待鄰州借僻書。"]'),
('94e31d49-bd27-4078-9154-7f706841a1b7','上知府大同王太尉六首  其五','魏野','宋','宋诗','song-poetry','','[]','薦士滿朝稱弟姪，教民到處過兒孫。',32,'全唐诗/poet.song.4000.json','["薦士滿朝稱弟姪，教民到處過兒孫。", "就中治陝偏清凈，不似侯門似道門。"]'),
('3655b5a5-1e5b-4b43-83c1-9bd1ff6ff428','上知府大同王太尉六首  其六','魏野','宋','宋诗','song-poetry','','[]','子細曾看九老圖，科名官職盡難如。',32,'全唐诗/poet.song.4000.json','["子細曾看九老圖，科名官職盡難如。", "更思呂望同君歲，猶自磻溪坐釣魚。"]'),
('cb318797-4f3e-4b31-afa2-5b14e87fd09d','吾友山陽蹇子韞嘗遊潁上言彼之居人有許氏者富不因貪學非求進于郡之西手植衆木鬰然成林林下搆亭壯而不麗郡倅黄公宗旦皇宋有名之士也常造焉上闕歌詩以旌其美故俾予請詩於子吾以子韞之請詩於予八十言以寄題','魏野','宋','宋诗','song-poetry','','[]','道勝富如貧，亭臨潁水濱。',96,'全唐诗/poet.song.4000.json','["道勝富如貧，亭臨潁水濱。", "一瓢思祖德，三徑與僧鄰。", "虛白雖同性，丹青不似身。", "趨庭知有子，下榻豈無人。", "紉珮蘭多老，成蹊李盡珍。", "開筵迴雪少，聯句聚星頻。", "家譜書難備，州圖畫不真。", "遥題應未的，莫把刻貞珉。"]'),
('9b62155c-2d49-4db6-8fad-25e13f1da1a6','上知府大同王太尉','魏野','宋','宋诗','song-poetry','','[]','履歷三朝五十春，坐棠難見輟元臣。',64,'全唐诗/poet.song.4000.json','["履歷三朝五十春，坐棠難見輟元臣。", "分茅已是無雙將，折桂兼爲第一人。", "郡邑暫時勞撫恤，華夷尅日望陶鈞。", "下車未暇求民瘼，先向東郊訪隠淪。"]'),
('6c4d036c-839e-4bf5-b7b4-4f59b57a571e','酬贈絳臺錢太尉見寄','魏野','宋','宋诗','song-poetry','','[]','分符不獨得民誇，玉署清華有棣華。',64,'全唐诗/poet.song.4000.json','["分符不獨得民誇，玉署清華有棣華。", "重耳山河初作主，闔閭宮闕舊爲家。", "風飄樓閣高低樂，日照池塘上下花。", "多謝到州農未勸，雙金先沐寄煙霞。"]'),
('0b6fb9cc-6b8b-4a5c-bd6b-9acbeda83475','和酬張井見贈','魏野','宋','宋诗','song-poetry','','[]','溪上閑居四十春，春溪蘭珮蕙爲紳。',64,'全唐诗/poet.song.4000.json','["溪上閑居四十春，春溪蘭珮蕙爲紳。", "自知吟詠非經濟，誰道機謀學渭濱。", "三尺焦桐勝面友，數家老叟是比鄰。", "少年多謝携詩什，來訪疏慵潦倒人。"]'),
('639c0ed2-a99d-4265-a8a9-cdaba09e0aca','啄木鳥二首  其一','魏野','宋','宋诗','song-poetry','','[]','爪利嘴還剛，殘陽啄更忙。',48,'全唐诗/poet.song.4000.json','["爪利嘴還剛，殘陽啄更忙。", "千林蠹如盡，一腹餒何妨。", "形小過槐陌，聲高近草堂。", "豈同閑燕雀，唯解占雕梁。"]'),
('085234d3-d885-48bb-a0e4-33abec50b433','啄木鳥二首  其二','魏野','宋','宋诗','song-poetry','','[]','亂遶園林啄，終朝意若何。',48,'全唐诗/poet.song.4000.json','["亂遶園林啄，終朝意若何。", "莫因饑不足，翻愛蠹偏多。", "渴映鄰溪下，驚從別樹過。", "辛懃詠還囑，無損好枝柯。"]'),
('205b042a-6dd7-4dfb-9c1b-e44952e17687','送張先寧覲','魏野','宋','宋诗','song-poetry','','[]','千里寧親去，青春勝老萊。',48,'全唐诗/poet.song.4000.json','["千里寧親去，青春勝老萊。", "苦辭留不住，堪送到方回。", "行色秋仍慘，離聲晚更哀。", "前程如有信，新鴈好憑來。"]'),
('44e701e6-43c6-4724-a0ab-749eb44d84f1','送黨宣員外赴闕兼呈劉小諫','魏野','宋','宋诗','song-poetry','','[]','行裝堪入畫何如，馬更羸於到任初。',64,'全唐诗/poet.song.4000.json','["行裝堪入畫何如，馬更羸於到任初。", "棠樹喜拋州部籍，蘭臺宜掌國圖書。", "草芽綠未侵官道，柳眼青先近帝居。", "願共耀卿來舊地，飄纓擁旆過吾廬。"]'),
('95e6a40e-580b-4c12-a7d6-ea7e5588675a','次韻和李殿院詠雪','魏野','宋','宋诗','song-poetry','','[]','瑞雪祥雲見盛時，功輕苦雨謾霏霏。',64,'全唐诗/poet.song.4000.json','["瑞雪祥雲見盛時，功輕苦雨謾霏霏。", "墜來雖作天花瘦，消去偏滋壠麥肥。", "太守登樓飄繡袂，幽人出戶混麻衣。", "鄰封願得還如此，免說秦饑與晉饑。"]'),
('25d460db-1aed-46ae-89f7-5c15a4ed57d5','送李殿院移鎮淮陽','魏野','宋','宋诗','song-poetry','','[]','花驄秋健繡旗開，漸遠棠郊近帝臺。',64,'全唐诗/poet.song.4000.json','["花驄秋健繡旗開，漸遠棠郊近帝臺。", "耳目緊官終拜去，股肱雄鎮暫迎來。", "兩州將相爲交代，三徑漁樵阻接陪。", "猶頼雅章留刻石，時時閑看拂塵埃。"]'),
('1cf0f8ca-6747-4294-9948-25128eba7931','送武屯田赴峽路均輸兼簡臧殿院','魏野','宋','宋诗','song-poetry','','[]','旌旗如火馬如風，十二峰前去少同。',64,'全唐诗/poet.song.4000.json','["旌旗如火馬如風，十二峰前去少同。", "錦帳選掄爲漕使，繡衣交代是家翁。", "蠻兒亦在提封內，神女猶居畏愛中。", "好繼金陵丁太尉，留題盡著碧紗籠。"]'),
('1c0c8cf6-6747-4b09-adc7-363f20507726','燈花','魏野','宋','宋诗','song-poetry','','[]','豈假栽培力，自然殊衆芳。',72,'全唐诗/poet.song.4000.json','["豈假栽培力，自然殊衆芳。", "開非因雨露，落不爲風霜。", "雞似殘鶑囀，蛾如宿蝶狂。", "丹心塵豈染，明焰霧難藏。", "墮睫客看懶，畫眉人翦忙。", "杏園遊宴者，曾借我餘光。"]'),
('83f04cbe-69ea-447c-a398-7937a7b2d210','次韻和酬知開封縣錢易學士見寄三首  其一','魏野','宋','宋诗','song-poetry','','[]','赤縣滯清才，家曾有國來。',48,'全唐诗/poet.song.4000.json','["赤縣滯清才，家曾有國來。", "埋金寧變土，燒玉豈爲灰。", "敏手知誰敵，冥心懶自媒。", "雅章蒙寄惠，味勝沃醇盃。"]'),
('e3c013af-6272-4887-a6d7-0bf4a318e81b','次韻和酬知開封縣錢易學士見寄三首  其二','魏野','宋','宋诗','song-poetry','','[]','遠勞仙館客，相勉寄詩來。',48,'全唐诗/poet.song.4000.json','["遠勞仙館客，相勉寄詩來。", "豈有口更嘆，兼無心可灰。", "貧資閑壽命，吟助道梯媒。", "信拙過朝暮，除能泥酒盃。"]'),
('9e7dbed7-975a-4aa0-892b-8aa209bfec95','次韻和酬知開封縣錢易學士見寄三首  其三','魏野','宋','宋诗','song-poetry','','[]','珠落銀鈎向玉牋，不還合浦到溪邊。',32,'全唐诗/poet.song.4000.json','["珠落銀鈎向玉牋，不還合浦到溪邊。", "無雙雙美真堪愛，似聽湘娥鼓舜絃。"]'),
('c9c3f054-1e81-4c0c-848c-acec9ad239d2','送王太尉赴詔二首  其一','魏野','宋','宋诗','song-poetry','','[]','功名不獨世推降，五福天鍾更少雙。',64,'全唐诗/poet.song.4000.json','["功名不獨世推降，五福天鍾更少雙。", "倚注即看宣几杖，休閑唯待讓旌幢。", "家園到想傾金篋，御宴迎應倒玉缸。", "重過嵩山定回首，白雲深鎖舊吟窗。"]'),
('7bcfd1a5-d865-4e98-b8c0-edaae28dd565','送王太尉赴詔二首  其二','魏野','宋','宋诗','song-poetry','','[]','三朝元老狀元稀，乞赴彤庭詔便依。',64,'全唐诗/poet.song.4000.json','["三朝元老狀元稀，乞赴彤庭詔便依。", "金鼎位高將正拜，璧田家近恐妨歸。", "殊恩每過莓苔徑，別淚偏霑薜荔衣。", "從此征車東去後，甘棠風物減光輝。"]'),
('89f44125-2bd5-46a9-8557-cdf4a716d435','謝王太博惠書','魏野','宋','宋诗','song-poetry','','[]','貴不忘貧賤，華緘到弊廬。',48,'全唐诗/poet.song.4000.json','["貴不忘貧賤，華緘到弊廬。", "分明如國史，子細似家書。", "情有千重在，詞無一字虛。", "未諧親謝去，東望但躊躕。"]'),
('3d21e521-566a-43df-ba3a-c9d33c452002','送蹇藏用省兄','魏野','宋','宋诗','song-poetry','','[]','迢遞西南路，山多水莫窮。',48,'全唐诗/poet.song.4000.json','["迢遞西南路，山多水莫窮。", "波濤千里遠，風雪一船空。", "海獸形難識，蠻僧語不通。", "此行忘險阻，義與在原同。"]'),
('00890bb1-0d75-4262-82ca-ff4b6ee6e06b','新栽竹','魏野','宋','宋诗','song-poetry','','[]','蒼翠兩三枝，親和凍塊移。',48,'全唐诗/poet.song.4000.json','["蒼翠兩三枝，親和凍塊移。", "旋吟酬得處，就刻記栽時。", "已任雪頻灑，未禁風苦吹。", "幽人心自足，千畝復堪嗤。"]'),
('0b8be58d-035c-4838-8835-5e3229863d9a','和酬何泳推官見贈','魏野','宋','宋诗','song-poetry','','[]','杜牧科名李賀曹，初官花幙莫辭勞。',64,'全唐诗/poet.song.4000.json','["杜牧科名李賀曹，初官花幙莫辭勞。", "年顔不似詩情老，公器還如酒戶高。", "我稱卧遊藍碧嶂，君宜立近赭黄袍。", "雅章酬晚慚慵拙，吟社何人與破逃。"]'),
('660dd3af-f6a3-4bac-8b57-876b78efa041','送孫推官之闕下','魏野','宋','宋诗','song-poetry','','[]','此去知君免嘆嗟，薦章先已到京華。',64,'全唐诗/poet.song.4000.json','["此去知君免嘆嗟，薦章先已到京華。", "賓筵沉滯才雖久，仙省遨遊路不賒。", "綠映酒旗村店柳，紅迎詩筆御園花。", "幾多祖席棠郊外，馬上回看日已斜。"]'),
('22769898-9535-4ff5-af9c-74bec7b8d7f0','留題華山陳先生舊隠','魏野','宋','宋诗','song-poetry','','[]','先生亡不朽，太華合爲碑。',48,'全唐诗/poet.song.4000.json','["先生亡不朽，太華合爲碑。", "至道雖無跡，玄言尚有詩。", "亂飛雲似覓，不食鶴應悲。", "獨遶空壇下，山風動紫芝。"]'),
('e9df1539-0c9f-411e-8637-e8cb6fe83c4e','和馮亞見贈','魏野','宋','宋诗','song-poetry','','[]','一生無一事，兀兀復騰騰。',48,'全唐诗/poet.song.4000.json','["一生無一事，兀兀復騰騰。", "信脚雖過寺，齋心不請僧。", "松篁爲活計，琴酒是良朋。", "除却君酬唱，他人亦懶能。"]'),
('be945241-f48e-4a52-a48a-0e937fde7dd5','送王專李安赴舉','魏野','宋','宋诗','song-poetry','','[]','同解約同歧，情懷獨若爲。',48,'全唐诗/poet.song.4000.json','["同解約同歧，情懷獨若爲。", "問愁離郡早，留恐到京遲。", "歲晚催行計，時豐省舉資。", "前春渾化去，莫忘野人詩。"]'),
('4f7c8083-0ff1-4c96-813d-7c6b4887547a','送陝尉邵國華南歸','魏野','宋','宋诗','song-poetry','','[]','召棠陰裏邵梅仙，守選南歸路七千。',64,'全唐诗/poet.song.4000.json','["召棠陰裏邵梅仙，守選南歸路七千。", "辛苦已傷過嶺外，別離那忍向花前。", "到京店舍逢新火，度越封疆入瘴煙。", "相顧與君頭盡白，不知後會是何年。"]'),
('e689f869-878d-4e86-936f-43f877f08d73','和王衢見寄兼呈董行父','魏野','宋','宋诗','song-poetry','','[]','棄繻東入武牢關，帝里經年豈是閑。',64,'全唐诗/poet.song.4000.json','["棄繻東入武牢關，帝里經年豈是閑。", "鶂退暫知淹鳳藻，鵬殘即看上鼇山。", "討論想慰門人意，談笑應開翰長顔。", "唯我塊然誰共處，終朝門掩竹林間。"]'),
('03985fdb-8990-4da3-80a0-505ff2664319','渭上秋夕閑望','魏野','宋','宋诗','song-poetry','','[]','秋夕滿秦川，登臨渭水邊。',48,'全唐诗/poet.song.4000.json','["秋夕滿秦川，登臨渭水邊。", "殘陽初過雨，何樹不鳴蟬。", "極浦涵新月，孤帆沒遠煙。", "漁人空老盡，誰似太公賢。"]'),
('bc4787da-3b39-4057-a7ef-114a13f30ffa','過古戰場','魏野','宋','宋诗','song-poetry','','[]','戰死掩無墳，生降恥負君。',48,'全唐诗/poet.song.4000.json','["戰死掩無墳，生降恥負君。", "古今魂易弔，貴賤骨難分。", "狐兔迷莎徑，烏鳶噪隴雲。", "誰家有征婦，曾此待回軍。"]'),
('b2348174-25cf-4abb-a881-8e3a11488095','長安春日書事','魏野','宋','宋诗','song-poetry','','[]','長安春色自依依，大命移應地不知。',64,'全唐诗/poet.song.4000.json','["長安春色自依依，大命移應地不知。", "蔓草已迷雙鳳闕，千花猶照九龍池。", "豈無東閤開今日，尚有南山似舊時。", "一月悠悠遊不足，青門欲出步遲遲。"]'),
('8c12ae01-db9a-48e4-865f-594ee72f8a66','哭錢觀察','魏野','宋','宋诗','song-poetry','','[]','操麾授鉞器縱橫，盡說長城指顧成。',64,'全唐诗/poet.song.4000.json','["操麾授鉞器縱橫，盡說長城指顧成。", "嶽既孕靈偏有意，天何促壽太無情。", "明堂欲建棟梁折，巨海將浮舟楫傾。", "未得四旬餘四載，龍旌不覺變銘旌。"]'),
('addcc38e-75c6-4375-91c0-e0ef1681f1ea','將遊蜀中恨有所滯至情難蓄發爲拙詩寄錦川峽路薛田臧奎二運使提刑楊及','魏野','宋','宋诗','song-poetry','','[]','却爲虛名動嘆嗟，難如雲鶴轉天涯。',64,'全唐诗/poet.song.4000.json','["却爲虛名動嘆嗟，難如雲鶴轉天涯。", "兩川尚阻尋三友，四海空傳是一家。", "白髮無多殘歲月，青城何限好煙霞。", "此生不遂閑遊去，蜀魄巴猿恨莫誇。"]'),
('4d435dfe-9427-4b10-b3b9-d72d9de80e92','疑山石泉','魏野','宋','宋诗','song-poetry','','[]','閑翫正嚴凝，神和澹鏡澄。',120,'全唐诗/poet.song.4000.json','["閑翫正嚴凝，神和澹鏡澄。", "至清無隠物，微暖不生冰。", "派想河難雜，源疑濟是朋。", "窺魚光照鶴，洗鉢影摇僧。", "逗石聲偏響，烹茶味更增。", "四溟終必到，八封內先稱。", "氣逐巖雲起，紋隨竹吹興。", "戲遊鱗未化，呼飲鳥相應。", "靜樂慚非智，成章愧不能。", "終朝臨處處，雖淺亦兢兢。"]'),
('9567ef49-1f3f-4bc5-8eec-391c7884a597','送端上人南歸','魏野','宋','宋诗','song-poetry','','[]','相尋如有事，獨去似無依。',48,'全唐诗/poet.song.4000.json','["相尋如有事，獨去似無依。", "海內山遊徧，江邊寺始歸。", "題詩當路少，乞食入城稀。", "肯學尋常輩，忙忙爲紫衣。"]'),
('dcd9f730-a2ce-44a1-b5e7-068f3f996f88','題陝府同判衙吏隠亭','魏野','宋','宋诗','song-poetry','','[]','小亭高岸上，危絕復何言。',48,'全唐诗/poet.song.4000.json','["小亭高岸上，危絕復何言。", "墨跡唐丞相，詩牌宋狀元。", "山形連二華，河勢瀉三門。", "吏隠真宜此，無窮景滿軒。"]'),
('1d516fd4-877e-4ad5-8a28-e38507203062','聞李安下第因有所感','魏野','宋','宋诗','song-poetry','','[]','客携春榜至，開處倚柴荆。',48,'全唐诗/poet.song.4000.json','["客携春榜至，開處倚柴荆。", "未看御題目，先尋君姓名。", "本期鄰狀首，敢歎滯文明。", "不會玄穹意，默然空愴情。"]'),
('040e9598-ed08-4188-99be-821af57995ef','次韻和鄴都趙尚書見寄','魏野','宋','宋诗','song-poetry','','[]','將鉞截瓊瑶，親題寄山野。',48,'全唐诗/poet.song.4000.json','["將鉞截瓊瑶，親題寄山野。", "喜若再和羹，味如重啖炙。", "身在蝸廬中，心懸雀臺下。", "龍門許復登，奔馳寧俟駕。"]'),
('0d04785e-c94a-4f86-af98-d2d24b6e1ec9','送王衢之任德之推官','魏野','宋','宋诗','song-poetry','','[]','從軍重疊繼家聲，雅稱風流舊信靈。',64,'全唐诗/poet.song.4000.json','["從軍重疊繼家聲，雅稱風流舊信靈。", "功業即看輝聖日，科名先已應台星。", "絲蠶地說連河朔，戎馬塵聞近虜庭。", "正是窮秋雨多際，不堪迴首向郊坰。"]'),
('00e7b6a4-6965-457f-a85e-b7adbb361ace','別雲臺觀同宿饒益寺與薛田聯句','魏野','宋','宋诗','song-poetry','','[]','自古人人足歎嗟，閑遊得侶復堪誇。',32,'全唐诗/poet.song.4000.json','["自古人人足歎嗟，閑遊得侶復堪誇。", "可憐十宿無喧雜，不在僧家即道家。"]'),
('e45682d1-df6e-48c2-9618-b721ab2892d1','經溫泉','魏野','宋','宋诗','song-poetry','','[]','堯水不墊民，溫泉溺唐祚。',36,'全唐诗/poet.song.4000.json','["堯水不墊民，溫泉溺唐祚。", "兵處洗不得，翻爲天下汙。", "山鳥徒咬咬，翠華無問處。"]'),
('d9d2c00e-adb9-4e26-afcf-7b0b0b989869','寓興七首  其一','魏野','宋','宋诗','song-poetry','','[]','天地無他功，其妙在自然。',48,'全唐诗/poet.song.4000.json','["天地無他功，其妙在自然。", "堯舜無他聖，其要在知賢。", "知賢無他術，觀其出處焉。", "堯苟不知舜，徒云能則天。"]'),
('a5438e10-be0b-4a42-abce-be787ecb7edc','寓興七首  其二','魏野','宋','宋诗','song-poetry','','[]','每念李斯首，不及嚴光足。',48,'全唐诗/poet.song.4000.json','["每念李斯首，不及嚴光足。", "斯首不自保，光足舒帝腹。", "我心異老聃，驚寵不驚辱。", "豈敢示他人，吟之將自勗。"]'),
('e2bdf8e2-4cf4-4107-9ff0-42a5cadefda6','寓興七首  其三','魏野','宋','宋诗','song-poetry','','[]','秦鑑雖至明，不能自照燭。',60,'全唐诗/poet.song.4000.json','["秦鑑雖至明，不能自照燭。", "楚劍徒云利，翻將自殺戮。", "有國苟失賢，若跣瞽雙目。", "况履艱險途，舉步成顛覆。", "秦楚昧於斯，寶器徒收畜。"]'),
('33497501-5205-495b-844c-8b5d4e070009','寓興七首  其四','魏野','宋','宋诗','song-poetry','','[]','伯夷非好餓，展禽非好黜。',60,'全唐诗/poet.song.4000.json','["伯夷非好餓，展禽非好黜。", "聖人不私己，動爲萬世則。", "夷齊苟就祿，賊亂何由窒。", "展禽苟便去，何人肯佐國。", "其跡則有殊，其道萬爲一。"]'),
('1a20f764-0362-483f-9833-2f84fe91a21e','寓興七首  其五','魏野','宋','宋诗','song-poetry','','[]','聖人不避嫌，小人不避恥。',36,'全唐诗/poet.song.4000.json','["聖人不避嫌，小人不避恥。", "伊尹放太甲，董賢居高位。", "嗟嗟若此人，堪愛復堪鄙。"]'),
('93f03d28-04cd-4bcc-af16-1469bed934af','寓興七首  其六','魏野','宋','宋诗','song-poetry','','[]','天地勞覆載，日月勞往還。',60,'全唐诗/poet.song.4000.json','["天地勞覆載，日月勞往還。", "此尚不能息，何况在其間。", "鳥獸飲食外，悠悠無貪慳。", "如何人異此，晝夜機相關。", "顧我道何如，心足身長閑。"]'),
('5364dea7-33a3-43d5-ac11-007678a4bdf5','寓興七首  其七','魏野','宋','宋诗','song-poetry','','[]','勿謂患至大，君聖民有頼。',40,'全唐诗/poet.song.4000.json','["勿謂患至大，君聖民有頼。", "勿謂事至小，父荒子無告。", "因思唐堯九年水，少於驪姬數滴淚。"]'),
('f81b6f4a-4eeb-4590-96f9-9901cc16e747','寄河中王專推官兼呈知府孫學士','魏野','宋','宋诗','song-poetry','','[]','風流官職稱紅蓮，花發多同太守筵。',64,'全唐诗/poet.song.4000.json','["風流官職稱紅蓮，花發多同太守筵。", "綠醑十分傾玉斝，清商一部列金鈿。", "池塘閑詠陪靈運，樓閣時登異仲宣。", "更想清明倚公暇，棲巖萬固到應偏。"]'),
('a871b8ad-ba1e-49e3-9bb1-9682081c7345','寄贈桃林尉史溫','魏野','宋','宋诗','song-poetry','','[]','知韞才能負壯心，莫嗟作尉尚湮沉。',64,'全唐诗/poet.song.4000.json','["知韞才能負壯心，莫嗟作尉尚湮沉。", "幽求起去登台席，居易徵來入翰林。", "望氣臺邊桑柘密，棄繻關畔水雲深。", "憐君况是徵君後，閑擬秋凉策杖尋。"]'),
('1c305f9a-4492-4680-8996-6c59d1f4c14c','贈陝縣薛偕主簿','魏野','宋','宋诗','song-poetry','','[]','少年來作簿，英俊復誰如。',72,'全唐诗/poet.song.4000.json','["少年來作簿，英俊復誰如。", "好事雖聞舊，能官不覺初。", "耽憂因稼穡，廢寢爲詩書。", "客戀門前住，民欣部內居。", "親科公舍竹，教種職田蔬。", "異日廳應鎖，清才本有餘。"]'),
('57facbfe-15bc-477a-a2c9-584468b684e6','次韻和王希知縣見贈','魏野','宋','宋诗','song-poetry','','[]','從前宰字絕文詞，喜遇今來併有詩。',64,'全唐诗/poet.song.4000.json','["從前宰字絕文詞，喜遇今來併有詩。", "封禪榜偏推鳳藻，陶鎔筆肯轉稽遲。", "訟庭任靜猶忘寐，文會雖忙不後期。", "莫怪林間强酬和，一般民最受深知。"]'),
('0b559e16-4b19-49fa-9cc4-6092c0bbcfe0','送錢中舍移任洋州興道縣兼呈知郡李屯田','魏野','宋','宋诗','song-poetry','','[]','鴛鴻出宰去如何，莫爲辭親發浩歌。',64,'全唐诗/poet.song.4000.json','["鴛鴻出宰去如何，莫爲辭親發浩歌。", "淹抑暫因民製錦，騫翔終預帝搜羅。", "樽前老淚流雖盡，林下離腸斷已多。", "却羨使君爲舊友，公餘開宴日相過。"]'),
('0dd08a78-6b6d-4e28-bd8f-f503ad7080b3','贈孫何狀元','魏野','宋','宋诗','song-poetry','','[]','天非道莫尊，道非賢莫存。',252,'全唐诗/poet.song.4000.json','["天非道莫尊，道非賢莫存。", "始知賢人生，與道爲輪轅。", "明庭親選士，慮彼賢愚渾。", "天子至文明，擢公爲狀元。", "一榜三百人，默默誰復言。", "有如鳳在林，衆鳥不敢喧。", "威稜廌有角，度量海無垠。", "直入仲尼室，不顧孟軻門。", "文得古中新，陳熟甚已冤。", "一字如一星，光芒不見痕。", "首官來理陝，棠樹換枯根。", "淑氣春風和，美化冬日暄。", "至誠物莫欺，至明物莫昏。", "平思治地陝，清欲變河源。", "我生三十年，未嘗離丘園。", "朴性昧巧習，惟知道可敦。", "貧巷無富車，閑地唯雲屯。", "我願爲松竹，生在君子軒。", "早夜接清風，節高陰更繁。", "何當親教授，如渴飲衢樽。", "斯言拙且直，堪將鬼神論。"]'),
('8a990aa7-0567-4c8c-aee9-f02632721342','寄友人臧奎','魏野','宋','宋诗','song-poetry','','[]','知己念不見，塊然何爲生。',48,'全唐诗/poet.song.4000.json','["知己念不見，塊然何爲生。", "慈母無醜子，澹父有妍情。", "凍雲少舒泰，獨鶴多哀鳴。", "茲懷若爲寫，援琴不成聲。"]'),
('459ee262-7af9-4b2c-832e-7402a9de15da','別同州陳太保','魏野','宋','宋诗','song-poetry','','[]','至道不在言，至言不在舌。',96,'全唐诗/poet.song.4000.json','["至道不在言，至言不在舌。", "在琴復在詩，諒唯君子別。", "侯門戟森森，中有野人謁。", "非趨勢利場，慕彼仁義轍。", "此去幾遲留，忽焉還歲月。", "孤心傷欲摧，凍足澀如折。", "離聲無歌鍾，行色有霜雪。", "去矣當復來，琴絃未欲絕。"]'),
('c6ff9b78-8649-48a7-9d33-71632afc0ab9','宿晦上人房','魏野','宋','宋诗','song-poetry','','[]','野客訪琴僧，夜午月又午。',24,'全唐诗/poet.song.4000.json','["野客訪琴僧，夜午月又午。", "爲我彈薰風，似聽重華語。"]'),
('cc7f0599-a180-4c4d-9b1d-69f5d3f7dddf','夏夜與臧奎陳越會宿河亭聯句三十韻','魏野','宋','宋诗','song-poetry','','[]','雨破畏日沉，月出酷暑歇。',288,'全唐诗/poet.song.4000.json','["雨破畏日沉，月出酷暑歇。", "衙中河亭上，靜與山不別。", "良朋俱遠來，文會一何悅。", "箕踞巾舄閑，玩好琴樽列。", "繁禮厭拘攣，陳言誓擺脫。", "揮塵影參差，飯果香馥烈。", "酒令時解嚴，談鋒久不缺。", "樂天無荒淫，飽德異饕餮。", "高談聞謔浪，正義排詭譎。", "抗俗絕依違，評文無詆詰。", "輿論鄙譸張，奴學賤剽竊。", "徵引角競出，聯唱更相發。", "較善合權衡，馳義同軌轍。", "萬物情難逃，千古疑皆决。", "聖道約扶持，淫辭謀劓刖。", "風鑒定妍媸，天機藏巧拙。", "是物有廢興，唯道無本末。", "義路自坦夷，世途終兀臬。", "烈士死光輝，常徒生汨沒。", "逸氣小風雲，直筆輕斧鉞。", "孟軻心不動，陶潛腰恥折。", "疲倦僕屢更，輝映燭頻跋。", "浩歌不成調，狂舞寧赴節。", "氣候隨斗占，分野爲星別。"]'),
('8eb97f2a-3daf-40b7-a3ed-8be7c027d4bc','解城條山','魏野','宋','宋诗','song-poetry','','[]','萬仞雲根泉，清泠濯我足。',120,'全唐诗/poet.song.4000.json','["萬仞雲根泉，清泠濯我足。", "森森滄爪甲，凜凜寒肌肉。", "來初自試探，坐久頻舒縮。", "觸開浪花白，踏破苔衣綠。", "肺腑亦清泠，形影相照燭。", "忽罷避遊魚，未歸妨渴鹿。", "懼濁遠泥沙，就陰憐草木。", "浸潤易調暢，狎翫難羈束。", "欲伐我未能，先起人何速。", "此會高且閑，願繼漁父躅。"]'),
('c441f15f-b2a5-42aa-ace6-9c3e7df6faa2','宿王闢宅與王專洎用晦上人因成聯句','魏野','宋','宋诗','song-poetry','','[]','夜淺月未生，春寒雪猶在。',48,'全唐诗/poet.song.4000.json','["夜淺月未生，春寒雪猶在。", "吳僧携古琴，來與山人會。", "詩心有是非，禪話無慷慨。", "高鴻自冥冥，弋者復何害。"]'),
('97c56352-6c08-4366-9433-c25259461374','淳化五年秋八月二十四日鉅鹿魏野江東僧用晦趙郡李識登解城瑯琊王衢命聯句詩一章凡六十四句請題於是','魏野','宋','宋诗','song-poetry','','[]','危城閑登臨，秋色際空碧。',288,'全唐诗/poet.song.4000.json','["危城閑登臨，秋色際空碧。", "四顧廓且平，萬慮忽然釋。", "精誠日月暗，曠達天地窄。", "壯節但孤聳，憤氣欲四射。", "鹽穴狂風號，峭壁濃嵐滴。", "膽氣高虛空，眼目無疆域。", "幽耳如洗濯，剛腸若刳剔。", "高譚俗不聞，嘉句景來索。", "四時歸牢籠，萬象在咫尺。", "山勢出嵩華，地界連虞虢。", "意脫喧卑場，神入清虛宅。", "千峰如聚拳，萬木同森戟。", "白雲閑不動，飛鳥忽相逆。", "平莎類裀褥，遠籟當琴瑟。", "定交心欲剖，言利口難擘。", "不作蔽日雲，願爲補天石。", "道在樂詩書，時平偃金革。", "笑傲得良朋，狂散絕勍敵。", "筆功壓班輸，酒腸欺烏獲。", "逸思驟雨傾，歡情湍水激。", "玄門匪防禦，學海詎沉溺。", "實果間酒巡，鄰谷和歌拍。", "頭鄙鍾儀冠，足愛謝公屐。", "靜勝貫兵法，默論通禪寂。"]'),
('9fd9669a-3720-40f0-9cc6-00ef6dafff7f','贈妓張八','魏野','宋','宋诗','song-poetry','','[]','君爲北道生張八，我是西州熟魏三。',32,'全唐诗/poet.song.4000.json','["君爲北道生張八，我是西州熟魏三。", "莫惜樽前無笑語，半生半熟未相諳。"]'),
('7e4aab40-f2ed-4bfc-be4c-45795c6eaddf','薔薇','魏野','宋','宋诗','song-poetry','','[]','碎剪紅綃間綠叢，風流疑在列仙宮。',32,'全唐诗/poet.song.4000.json','["碎剪紅綃間綠叢，風流疑在列仙宮。", "朝真更欲熏香去，爭擲霓衣上寶籠。"]'),
('751f3eac-c304-4852-bd58-8e1fc2f2030e','曉','魏野','宋','宋诗','song-poetry','','[]','露侵短褐曉寒輕，星斗闌干野外明。',32,'全唐诗/poet.song.4000.json','["露侵短褐曉寒輕，星斗闌干野外明。", "寂寞小橋和夢過，豆花深處草蟲鳴。"]'),
('d87a7fab-ef5c-4925-a005-0cdd1aa20ea1','題僧寺','魏野','宋','宋诗','song-poetry','','[]','世情冷暖由分別，何必區區較異同。',32,'全唐诗/poet.song.4000.json','["世情冷暖由分別，何必區區較異同。", "但得常將紅袖拂，也應勝似碧紗籠。"]'),
('1be8cada-b102-40ad-8ae6-1f066fd54c8a','尋隠者不遇','魏野','宋','宋诗','song-poetry','','[]','尋真誤入蓬萊島，香風不動松花老。',32,'全唐诗/poet.song.4000.json','["尋真誤入蓬萊島，香風不動松花老。", "採芝何處未歸來，白雲滿地無人掃。"]'),
('1f4c511f-6782-472b-b579-0467334bea08','挽王平甫','魏野','宋','宋诗','song-poetry','','[]','今日臨風淚，瀟瀟似綆縻。',48,'全唐诗/poet.song.4000.json','["今日臨風淚，瀟瀟似綆縻。", "空懷徐稚絮，誰立鄭玄碑。", "無力酬推轂，平時憤抵巇。", "何人知枉狀，路粹豈能爲。"]'),
('851bab92-753a-4cd8-bfcb-77b1a66745bf','白頭公','魏野','宋','宋诗','song-poetry','','[]','有何辛苦有何愁，個個林間盡白頭。',64,'全唐诗/poet.song.4000.json','["有何辛苦有何愁，個個林間盡白頭。", "細葉累巢花影暖，微蟲共食竹陰秋。", "清音豈許黄鶑伏，素羽曾教白鷺羞。", "唯爾鬢毛應似我，相逢不用話因由。"]'),
('fa5364d6-ba75-4866-ab6c-38dd293473fd','劉燁大著忽惠雅章喜懼交集輒增二詠聊以謝酬','魏野','宋','宋诗','song-poetry','','[]','東觀劉郎一古儒，等閑簡帖類經書。',64,'全唐诗/poet.song.4000.json','["東觀劉郎一古儒，等閑簡帖類經書。", "論交不棄如雲客，並馬常容似雪馿。", "蝴蝶夢魂知有據，鳳凰詔命想無虛。", "翻愁旦暮西垣去，難伴王維宿直廬。"]'),
('50ac41a0-3ee9-4bd7-8160-7169c4dae29e','送薛階迎覲察院','魏野','宋','宋诗','song-poetry','','[]','知心人去野人孤，猶頼時時見鳳雛。',32,'全唐诗/poet.song.4000.json','["知心人去野人孤，猶頼時時見鳳雛。", "病裏鳳雛辭又去，老身縱健不如無。"]'),
('c6a8ce2a-a298-4809-889c-d40abad1c880','又次前韻兼乞鶴','魏野','宋','宋诗','song-poetry','','[]','君去華亭鶴又殂，眼前空見衆禽雛。',32,'全唐诗/poet.song.4000.json','["君去華亭鶴又殂，眼前空見衆禽雛。", "欲憑轉乞爲閒伴，許史多情許我無。"]'),
('80f93b3b-aede-4e7b-b3f2-fe207a059bca','詩一首','魏野','宋','宋诗','song-poetry','','[]','誰人把我狂詩句，寫向添蘇繡戶中。',32,'全唐诗/poet.song.4000.json','["誰人把我狂詩句，寫向添蘇繡戶中。", "閑暇若將紅袖拂，還應勝得碧紗籠。"]'),
('83262014-2b75-4325-a313-7530487a807c','詩一首','魏野','宋','宋诗','song-poetry','','[]','城裏爭看城外花，獨來城裏訪僧家。',32,'全唐诗/poet.song.4000.json','["城裏爭看城外花，獨來城裏訪僧家。", "辛勤旋覓新鑽火，爲我親烹嶽麓茶。"]'),
('e4b7d2ef-545a-459d-8b73-e0d8c6b43c60','句  其一','魏野','宋','宋诗','song-poetry','','[]','通體全無力，酡顔不自持。',12,'全唐诗/poet.song.4000.json','["通體全無力，酡顔不自持。"]'),
('d6fb9519-2f08-4bf1-a028-47a223545218','句  其二','魏野','宋','宋诗','song-poetry','','[]','放人少處先登第，舉族貧時已受官。',16,'全唐诗/poet.song.4000.json','["放人少處先登第，舉族貧時已受官。"]'),
('90f7cbec-bed7-4f84-abdd-3fa5a34b4f44','存目  其一','魏野','宋','宋诗','song-poetry','','[]','詩題：清明首句：無花無酒過清明。',16,'全唐诗/poet.song.4000.json','["詩題：清明首句：無花無酒過清明。"]'),
