('338870dd-ab43-49dc-9c9a-3698e481eb59','解城條山聯句淳化五年秋八月二十四日鉅鹿魏野江東僧用晦趙郡李識登解城瑯琊王衢命聯句詩一章凡六十四句請題於是','李識','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.4000.json','["無正文。"]'),
('bc325407-ce03-424d-9887-4632e2df6d01','送崇教大師歸天台謹吟七言四韻','范貽孫','宋','宋诗','song-poetry','','[]','名僧高隠盡修行，人說吾師最出羣。',64,'全唐诗/poet.song.4000.json','["名僧高隠盡修行，人說吾師最出羣。", "新向天台承帝澤，便朝梁院謝明君。", "幾程烟水趨丹闕，一院杉松鎖白雲。", "却泛輕杯舊山去，石橋秋月會聲聞。"]'),
('33f5e232-9e6f-4e28-b445-96a20fc6a0ae','禁林讌會之什','錢若水','宋','宋诗','song-poetry','','[]','一夜春風滿帝都，禁林清曉宴簪裾。',96,'全唐诗/poet.song.4000.json','["一夜春風滿帝都，禁林清曉宴簪裾。", "玉堂乍到驚凡目，金鎖徐開見御書。", "四字驪龍爭夭矯，兩篇瓊樹鬭扶疏。", "詞臣此會人應羨，聖主多才古不如。", "日上花磚簾捲後，柳遮鈴索雨晴初。", "閣前吟罷先沈醉，忘却西垣有直廬。"]'),
('6456a73b-b1fb-471a-b2d3-2f154267ba3d','送楊大年知處州二首  其一','錢若水','宋','宋诗','song-poetry','','[]','夫子厭承明，還求領郡行。',48,'全唐诗/poet.song.4000.json','["夫子厭承明，還求領郡行。", "兩章干負扆，數刻對延英。", "豈獨綵衣樂，兼爲晝錦榮。", "聖朝循吏傳，首得見君名。"]'),
('add10f55-0fb4-4ccd-83b2-98eb8bad8e3f','送楊大年知處州二首  其二','錢若水','宋','宋诗','song-poetry','','[]','汗簡成惇史，分符別近班。',48,'全唐诗/poet.song.4000.json','["汗簡成惇史，分符別近班。", "仍聞括蒼郡，酷似武夷山。", "捲箔煙霞麗，登樓水石閑。", "二年棄官去，惟我獨何顔。"]'),
('e889f27a-11bd-4aa5-9f4c-c1f1fb4648c2','濟源縣裴公亭','錢若水','宋','宋诗','song-poetry','','[]','裴相亭成未退身，空煩舞袖與歌塵。',32,'全唐诗/poet.song.4000.json','["裴相亭成未退身，空煩舞袖與歌塵。", "至今亭下蕭蕭竹，似對秋風怨主人。"]'),
('0528a270-3216-48f0-8e80-720db1cfe467','詠華林書院','錢若水','宋','宋诗','song-poetry','','[]','居近華林對白雲，義風深可羨人倫。',96,'全唐诗/poet.song.4000.json','["居近華林對白雲，義風深可羨人倫。", "兒孫盡得詩書力，門巷偏多車馬塵。", "樓上落霞粘筆硯，池邊怪石間松筠。", "鄉閭豈獨民遷善，階砌無關鳥亦馴。", "朱實垂庭紅橘熟，清香襲坐藥畦春。", "他年好卜爲鄰住，悔葺吾廬洛水濱。"]'),
('b82a851e-6553-46ce-91c4-d3836ba392b8','句  其一','錢若水','宋','宋诗','song-poetry','','[]','三陪藻燕簪裾上，五對龍顔日月邊。',16,'全唐诗/poet.song.4000.json','["三陪藻燕簪裾上，五對龍顔日月邊。"]'),
('2c3579e8-f8c3-49a5-9db1-735b1944a1da','句  其二','錢若水','宋','宋诗','song-poetry','','[]','黼座勸觴鈞樂逸，雲章屬韻待貂傳。',16,'全唐诗/poet.song.4000.json','["黼座勸觴鈞樂逸，雲章屬韻待貂傳。"]'),
('1774cafa-4863-48a0-a66b-b7f304c7caaf','上法智大師','釋遇昌','宋','宋诗','song-poetry','','[]','雨霽遥空木落時，危亭南望倍依依。',64,'全唐诗/poet.song.4000.json','["雨霽遥空木落時，危亭南望倍依依。", "白蓮舊社人離久，丹闕經年信去稀。", "入觀夜堂江月滿，揮松秋殿晝燈微。", "林中自有吾廬在，請益終期海上歸。"]'),
('623af466-fb53-4c2c-a12d-6e51050b382b','題義門胡氏華林書院','馮起','宋','宋诗','song-poetry','','[]','華林仙野近南昌，聞說幽奇景異常。',64,'全唐诗/poet.song.4000.json','["華林仙野近南昌，聞說幽奇景異常。", "竹翠松寒籠藥圃，水清山秀繞書堂。", "詞登科第名尤振，恩表門閭道愈光。", "我恨方爲簪組累，莫同吟嘯白雲房。"]'),
('6fc75137-9983-451d-9700-09050553515c','睢陽五老會詩','馮平','宋','宋诗','song-poetry','','[]','詔恩分務許優閑，肯借留都獬豸冠。',64,'全唐诗/poet.song.4000.json','["詔恩分務許優閑，肯借留都獬豸冠。", "名宦儻來空擾攘，丘園歸去好盤桓。", "醉遊春圃煙霞暖，吟聽秋潭水石寒。", "退傅況兼爲隠伴，紅塵那復舉頭看。"]'),
('2f28b3bc-8e52-46d2-93a0-34dfd70246dc','送張無夢歸天台','張復','宋','宋诗','song-poetry','','[]','學道探玄務谷神，薜衣疏野見明君。',64,'全唐诗/poet.song.4000.json','["學道探玄務谷神，薜衣疏野見明君。", "暫來北闕利名地，歸去舊山鸞鶴羣。", "洞壑深藏塵外士，冠裳不繫嶺頭雲。", "赤城千仞幽居處，夜籟秋猿枕上聞。"]'),
('a45bc363-5c00-4cb1-92e3-4813e10f4873','正旦病中','孫何','宋','宋诗','song-poetry','','[]','千官簪笏儼成行，春逐鑾輿出建章。',64,'全唐诗/poet.song.4000.json','["千官簪笏儼成行，春逐鑾輿出建章。", "丹鳳案明分曙色，絳紗袍暖起天香。", "旌旗影裏陳方物，金石聲中舉壽觴。", "可惜龍墀立班處，劉生獨自卧清漳。"]'),
('6ff13bf2-4f2d-408b-8cf8-6851c3d2c57d','僧','孫何','宋','宋诗','song-poetry','','[]','去路餘千里，行行雪灑衣。',48,'全唐诗/poet.song.4000.json','["去路餘千里，行行雪灑衣。", "諸峰何日別，一錫犯寒歸。", "夜宿誰聞磬，晨齋自採薇。", "遥知到禪宇，猿鳥共開扉。"]'),
('be31a8cd-db92-4dbd-a569-412060ebff08','杏','孫何','宋','宋诗','song-poetry','','[]','殷紅鄙桃艷，淡白笑梨花。',48,'全唐诗/poet.song.4000.json','["殷紅鄙桃艷，淡白笑梨花。", "落處飄微霰，繁時疊碎霞。", "苑宜開帝里，壇稱在儒家。", "麗日明珠箔，清香襲絳紗。"]'),
('37561c4f-368d-48fc-9bbf-3829fe59f5f5','題石橋','孫何','宋','宋诗','song-poetry','','[]','六月巖崖似九秋，興公辭賦好淹留。',64,'全唐诗/poet.song.4000.json','["六月巖崖似九秋，興公辭賦好淹留。", "杉松迤邐連華頂，鐘磬依稀近沃洲。", "枕水古碑卿相撰，拂雲新剎帝王修。", "高僧盡解飛金錫，誰是當年白道猷。"]'),
('c1915322-1ffc-47bb-9b09-f268eb9425e2','送弟侑','孫何','宋','宋诗','song-poetry','','[]','武昌古名地，英秀森琳琅。',24,'全唐诗/poet.song.4000.json','["武昌古名地，英秀森琳琅。", "既號詩書窟，復稱雲水鄉。"]'),
('4e1a89d4-43c7-4ed2-afb4-e6c78c0102e2','侍宴御樓','孫何','宋','宋诗','song-poetry','','[]','突兀毬場錦繡峰，遊人士女擁千重。',32,'全唐诗/poet.song.4000.json','["突兀毬場錦繡峰，遊人士女擁千重。", "月離雲海飛金鏡，燈射冰簾掣火龍。"]'),
('f067ee11-af35-4b05-8099-1ca9e57b220c','上元雨','孫何','宋','宋诗','song-poetry','','[]','淡月微雲外，街泥小雨餘。',24,'全唐诗/poet.song.4000.json','["淡月微雲外，街泥小雨餘。", "人如墟市散，燈似曉星疏。"]'),
('a15ff21c-26ec-4c54-862f-269d93cdb475','桐柏觀','孫何','宋','宋诗','song-poetry','','[]','玉壇三級接秋空，此是仙家第幾重。',64,'全唐诗/poet.song.4000.json','["玉壇三級接秋空，此是仙家第幾重。", "羽客有時來駕鶴，王人無歲不投龍。", "微吟海月生巖桂，長嘯天風起澗松。", "司馬先生何處去，篆碑猶有白雲封。"]'),
('b36880fd-62ed-4cb5-8422-ec74cf1d1138','吳江','孫何','宋','宋诗','song-poetry','','["\u592a\u6e56"]','晚灘如雪起沙鷗，咫尺姑蘇亦勝遊。',64,'全唐诗/poet.song.4000.json','["晚灘如雪起沙鷗，咫尺姑蘇亦勝遊。", "逸勢瀉歸滄海遠，冷聲分作太湖秋。", "葑田幾處連僧寺，橘岸誰家對驛樓。", "魯望不存無可語，片帆中夜渡清流。"]'),
('c907c215-ca37-44ff-857d-ea1862e6cad8','詠華林書院','孫何','宋','宋诗','song-poetry','','[]','六闕旌門事若何，諸生常不絕弦歌。',128,'全唐诗/poet.song.4000.json','["六闕旌門事若何，諸生常不絕弦歌。", "鯉庭共稟詩書訓，隠巷齊登俊造科。", "宗族有光傳孝弟，鄉閭無訟化淳和。", "芝蘭子弟相薰習，金石交朋互切磋。", "遥望楚江波迥急，却分廬阜影偏多。", "題名石鼓圍松桂，講易高堂繞芰荷。", "採藥路從洪井出，買書船自孺亭過。", "我慚已在瀛洲直，不得西山隠薜蘿。"]'),
('c3a41137-7c05-41e7-acab-19cdc49bbe90','詩一首','孫何','宋','宋诗','song-poetry','','[]','張樂魚龍侵岸聽，賦詩賈客倚船看。',32,'全唐诗/poet.song.4000.json','["張樂魚龍侵岸聽，賦詩賈客倚船看。", "他年得第彤庭直，拜疏終求鄂渚官。"]'),
('5b87ad9e-a0dd-471d-a213-ebb55d51be7e','詩三首  其一','孫何','宋','宋诗','song-poetry','','[]','貝闕琳宮紫霧深，鳳凰仙樂尚愔愔。',64,'全唐诗/poet.song.4000.json','["貝闕琳宮紫霧深，鳳凰仙樂尚愔愔。", "鼎湖往事三千載，石筍青春一萬尋。", "挺立不教凡草長，削成應免俗塵侵。", "霓旌絳節知何處，空有蓮花送好音。"]'),
('8c4092f3-e1be-4629-a51e-538179fce29c','詩三首  其二','孫何','宋','宋诗','song-poetry','','[]','薜荔無因掛一毫，化工鎸削亦應勞。',64,'全唐诗/poet.song.4000.json','["薜荔無因掛一毫，化工鎸削亦應勞。", "圭形直指明河落，桂影遥分漲海濤。", "發地五千何足貴，去天三百未足高。", "軒轅轍跡今猶在，斗上丹枕著羽袍。"]'),
('cfd806ea-28c0-44d7-9f03-c41bf8a85f0a','詩三首  其三','孫何','宋','宋诗','song-poetry','','[]','黄帝昇天去不還，空留片石在人間。',48,'全唐诗/poet.song.4000.json','["黄帝昇天去不還，空留片石在人間。", "千尋杳杳撐紅日，倚雲喬木羽林閒。", "時人不信飛昇路，轍跡龍髯竟可攀。"]'),
('ffed725d-9fc8-41f5-b6bc-e78708dbaf9a','句  其一','孫何','宋','宋诗','song-poetry','','[]','誰如張璪工松石，擬裂鮫綃畫作圖。',16,'全唐诗/poet.song.4000.json','["誰如張璪工松石，擬裂鮫綃畫作圖。"]'),
('5c862a0a-17ba-47ab-9954-7e41359f2ce2','句  其二','孫何','宋','宋诗','song-poetry','','[]','早晚無塵事。',6,'全唐诗/poet.song.4000.json','["早晚無塵事。"]'),
('6b6a27ed-6c52-4160-af18-87305126f067','句  其三','孫何','宋','宋诗','song-poetry','','[]','美人與月正同色，客子折梅空斷腸。',16,'全唐诗/poet.song.4000.json','["美人與月正同色，客子折梅空斷腸。"]'),
('353c7229-b0c1-445f-aa01-777f03b141b2','句  其四','孫何','宋','宋诗','song-poetry','','[]','飛泉落翠巘，爽籟生寒空。',12,'全唐诗/poet.song.4000.json','["飛泉落翠巘，爽籟生寒空。"]'),
('ce530e93-006f-4da7-ac8b-de42823fe2bb','句  其五','孫何','宋','宋诗','song-poetry','','[]','欲謁元戎無介紹，薛能詩版在鵰堂。',16,'全唐诗/poet.song.4000.json','["欲謁元戎無介紹，薛能詩版在鵰堂。"]'),
('1bac80c5-5b49-4600-82bb-3ed2cb3f640c','贈英公大師','王承衎','宋','宋诗','song-poetry','','[]','文章篆籀久傳芳，灰志禪門道愈光。',64,'全唐诗/poet.song.4000.json','["文章篆籀久傳芳，灰志禪門道愈光。", "豐鎬有心營寶剎，瀟湘無意卧雲房。", "陶情早著詩千首，混俗何妨酒百觴。", "若許宗雷重結社，願持香火學空王。"]'),
('b3cb1a27-57ba-41e5-aaf5-3ac7a2e8951d','句  其一','劉師道','宋','宋诗','song-poetry','','[]','南浦未傷春草碧，北山仍媿曉猿驚。',16,'全唐诗/poet.song.4000.json','["南浦未傷春草碧，北山仍媿曉猿驚。"]'),
('39c6bc4f-62d6-49e6-ba7d-b9ef3daee517','句  其二','劉師道','宋','宋诗','song-poetry','','[]','久師金馬客，勍敵玉溪生。',12,'全唐诗/poet.song.4000.json','["久師金馬客，勍敵玉溪生。"]'),
('20569354-066a-4502-b2a8-46dd6a8411a1','句  其三','劉師道','宋','宋诗','song-poetry','','[]','有路期奔月，無媒與嫁春。',12,'全唐诗/poet.song.4000.json','["有路期奔月，無媒與嫁春。"]'),
('5830b200-209e-4849-99cf-28e59c4c74a4','句  其四','劉師道','宋','宋诗','song-poetry','','[]','金谷路塵埋國艷，武陵溪水泛天香。',16,'全唐诗/poet.song.4000.json','["金谷路塵埋國艷，武陵溪水泛天香。"]'),
('93d32dd2-b722-4249-ace3-6085e8cc12f8','句  其五','劉師道','宋','宋诗','song-poetry','','[]','晨瞻北斗天何遠，夢斷南柯日未沉。',16,'全唐诗/poet.song.4000.json','["晨瞻北斗天何遠，夢斷南柯日未沉。"]'),
('90079493-6896-44f3-89ad-a759e1fc3a94','句  其六','劉師道','宋','宋诗','song-poetry','','[]','野馬飛窗日，醯雞舞甕天。',12,'全唐诗/poet.song.4000.json','["野馬飛窗日，醯雞舞甕天。"]'),
('262017f2-26cf-4ad5-a602-c2d60b5c73be','句  其七','劉師道','宋','宋诗','song-poetry','','[]','青帝翠華沈物外，素娥孀影弔雲端。',16,'全唐诗/poet.song.4000.json','["青帝翠華沈物外，素娥孀影弔雲端。"]'),
('b9618cc0-a6b1-4845-8bab-ec34984f11f8','句  其八','劉師道','宋','宋诗','song-poetry','','[]','三千世界銀成色，十二樓臺玉作層。',16,'全唐诗/poet.song.4000.json','["三千世界銀成色，十二樓臺玉作層。"]'),
('60e2e807-1647-4cca-8b59-d20e9dc9fd7a','句  其九','劉師道','宋','宋诗','song-poetry','','[]','逝波帝子魂何在，芳草王孫怨未歸。',16,'全唐诗/poet.song.4000.json','["逝波帝子魂何在，芳草王孫怨未歸。"]'),
('12443f75-c725-43d2-99f5-5d71f09b63e7','送張無夢歸天台','陳堯叟','宋','宋诗','song-poetry','','[]','山人之所隠，臨海赤城閒。',140,'全唐诗/poet.song.4000.json','["山人之所隠，臨海赤城閒。", "天台峰峨峨，剡水聲潺潺。", "絕頂一室非塵寰，忘形終日同雲閒。", "仙軿每戾止，人迹絕躋攀。", "沆瀣挹朝味，冰雪留童顔。", "手持百首還元詩，詩成自謂人不知。", "世人得之蹈，希夷自此遊。", "朝市皆爭識形儀，承禎以道遇明主。", "子訓賣藥歸會稽，張君今能盡繼之。", "冥冥孤鴻東南飛，邈然不負煙霞期。"]'),
('2587ae5e-60ee-4bd3-9568-bde45b21c7a4','送崇教大師南歸','陳堯叟','宋','宋诗','song-poetry','','[]','能名浄行達理闈，振錫携瓶出翠微。',64,'全唐诗/poet.song.4000.json','["能名浄行達理闈，振錫携瓶出翠微。", "恩重冕旒曾召對，情高雲鶴却同歸。", "會思蓮社寰中結，杯泛潮風海上飛。", "不是清時未陳力，便堪隨去掃巖扉。"]'),
('879d01a8-2155-499d-9bb0-50ce7971b592','果實','陳堯叟','宋','宋诗','song-poetry','','[]','甜於糖蜜軟於酥，閬苑山頭擁萬株。',32,'全唐诗/poet.song.4000.json','["甜於糖蜜軟於酥，閬苑山頭擁萬株。", "葉底深藏紅玳瑁，枝邊低綴碧珊瑚。"]'),
('b01d10f5-0496-450e-90c3-e0d02257d26d','洞霄宮','陳堯叟','宋','宋诗','song-poetry','','[]','迴合煙光疊翠屏，東南山水此爲靈。',96,'全唐诗/poet.song.4000.json','["迴合煙光疊翠屏，東南山水此爲靈。", "鶑花春學蓬瀛境，樓閣夜干牛斗星。", "古檜森羅燒藥竈，彩雲飄灑聚仙亭。", "遼天俯近歸期鶴，澥谷旁連駭巨溟。", "紫陌紅塵無一點，綠毛仙骨有千齡。", "當時聽法談玄者，環佩鏘鏘拱上清。"]'),
('61a872a0-e812-463e-a0b5-1e24582f4cf6','披雲亭','陳堯叟','宋','宋诗','song-poetry','','[]','秦關百二山河固，陝服城闉控此中。',64,'全唐诗/poet.song.4000.json','["秦關百二山河固，陝服城闉控此中。", "別構棟梁成爽塏，俯觀竹樹立青蔥。", "虛簷豁敞迎朝日，曲檻縈回带晚風。", "登眺自欣襟带地，萬方轍迹坦然同。"]'),
('32e0631e-1c6a-467c-8e0b-d2dcde29f42d','妙智洞','陳堯叟','宋','宋诗','song-poetry','','[]','追憶經行三十年，漫山桃李競爭妍。',32,'全唐诗/poet.song.4000.json','["追憶經行三十年，漫山桃李競爭妍。", "于今棠棣花成萼，我已童顔射酒舡。"]'),
('08521032-7935-4a52-852b-e9ac6d47e08a','題義門胡氏華林書院','陳堯叟','宋','宋诗','song-poetry','','[]','旌闕書亭煥水鄉，四時煙景似滄浪。',64,'全唐诗/poet.song.4000.json','["旌闕書亭煥水鄉，四時煙景似滄浪。", "玉漿寒色連莎砌，金障秋陰覆草堂。", "田里從來應遜畔，兒孫遊戲亦成行。", "吾君孝理風天下，誰識謳歌綴樂章。"]'),
('8ef4ec06-b27c-4d7b-8b2e-f072ecc9d221','賡上賜病歸韻','陳堯叟','宋','宋诗','song-poetry','','[]','寅會丁昌運，訏謨愧瑣才。',72,'全唐诗/poet.song.4000.json','["寅會丁昌運，訏謨愧瑣才。", "微功酬帝造，邁級處公臺。", "辭位囊封上，逾涯寵數來。", "維藩分聖寄，涕泗遠丹臺。", "旌仰宸章降，隆彌睿眷回。", "載賡誠寡和，望闕幾徘徊。"]'),
('4efca674-1c1c-46cb-bf1c-7148285dbc02','詩一首','陳堯叟','宋','宋诗','song-poetry','','[]','一榻琴書雙門寺，片心泉石兩林山。',32,'全唐诗/poet.song.4000.json','["一榻琴書雙門寺，片心泉石兩林山。", "江樓把酒雲供望，秋院支筇鶴對閒。"]'),
('b580c13f-77dc-49a2-9880-8dd87d64fd19','休沐端居有懷希聖','李維','宋','宋诗','song-poetry','','[]','銀闕琳房視草餘，龍門岑寂斷軒車。',64,'全唐诗/poet.song.4000.json','["銀闕琳房視草餘，龍門岑寂斷軒車。", "彩毫閑試金壺墨，青案時看玉字書。", "王令風流希謝傅，子雲詞賦敵相如。", "瓊枝不見蕭齋晚，蕙草烟微度綺疏。"]'),
('5ebbf847-bb00-4964-af77-caf58066e37f','王左丞新菊','李維','宋','宋诗','song-poetry','','[]','青規前席暇，歸沐興何長。',96,'全唐诗/poet.song.4000.json','["青規前席暇，歸沐興何長。", "北第秋將晚，東籬菊正芳。", "幽叢霏薄霧，桂色艷輕霜。", "已近黄金印，兼臨白玉堂。", "甘疑掩萍實，秀肯讓芝房。", "有佞還應指，無憂可要忘。", "蘂浮丞相酒，氣馥令君香。", "好固松椿壽，仙經識秘方。"]'),
('dcbecc31-a12e-4504-83f9-7d513c53ab58','霜月','李維','宋','宋诗','song-poetry','','[]','銀牀葉暗飄，霜月夜迢迢。',48,'全唐诗/poet.song.4000.json','["銀牀葉暗飄，霜月夜迢迢。", "寒極犀難辟，憂多酒漫消。", "荀爐殘更換，湘瑟罷仍調。", "誰道河流淺，盈盈萬里遥。"]'),
('f69dca30-425d-42af-8650-5c9a3b1cf5b5','送張無夢歸天台','李維','宋','宋诗','song-poetry','','[]','金骨一何輕，瞳方鬢復青。',48,'全唐诗/poet.song.4000.json','["金骨一何輕，瞳方鬢復青。", "樓居隠巖桂，飈馭別階蓂。", "玉宇藏丹訣，琱觴泛綠醹。", "霞城中夕夢，懸想在彤庭。"]'),
('3a820087-113e-4f49-bd83-4c9adaa0d9df','送僧歸護國寺','李維','宋','宋诗','song-poetry','','[]','香剎隠霞標，齋房見落潮。',48,'全唐诗/poet.song.4000.json','["香剎隠霞標，齋房見落潮。", "歸思海衆繞，來應輔臣招。", "倚策吟雲合，乘杯咒浪銷。", "曹溪久得法，遊戲自逍遥。"]'),
('7d22ab4f-46b0-40c5-a8cb-7745eb381d4a','送舒殿丞','李維','宋','宋诗','song-poetry','','[]','讀碑經峴首，貰酒過宜城。',24,'全唐诗/poet.song.4000.json','["讀碑經峴首，貰酒過宜城。", "莫問依劉事，休傷吊屈情。"]'),
('04fecd5e-6eec-49a6-8085-750d2b801ebf','句  其一','李維','宋','宋诗','song-poetry','','[]','清朝納祿猶强健，白首還家正太平。',16,'全唐诗/poet.song.4000.json','["清朝納祿猶强健，白首還家正太平。"]'),
('454fd899-e6bc-4373-9a62-1f727a96279e','句  其二','李維','宋','宋诗','song-poetry','','[]','故宮芳草在，往事暮江流。',12,'全唐诗/poet.song.4000.json','["故宮芳草在，往事暮江流。"]'),
