('9060d689-a19c-4ea4-8cbe-f8b723cd2c3d','存目  其六','李維','宋','宋诗','song-poetry','','[]','詩題：郊居寄朝中知己首句：年來流水壞平田。',21,'全唐诗/poet.song.4000.json','["詩題：郊居寄朝中知己首句：年來流水壞平田。"]'),
('e01c174d-9446-4e93-90e6-102872265152','題黄休復茅亭','任玠','宋','宋诗','song-poetry','','[]','聚散榮枯一夢中，西歸親友半成空。',32,'全唐诗/poet.song.4000.json','["聚散榮枯一夢中，西歸親友半成空。", "唯餘大隠茅亭客，垂白論交有古風。"]'),
('94b64df7-ce8b-48fa-9c91-824f3b55fb98','句','任玠','宋','宋诗','song-poetry','','[]','春風天遠望不盡。',8,'全唐诗/poet.song.4000.json','["春風天遠望不盡。"]'),
('0a14184b-a381-447c-b802-dde926a5230a','僻居','燕肅','宋','宋诗','song-poetry','','[]','茅茨城市遠，草徑接魚村。',48,'全唐诗/poet.song.4000.json','["茅茨城市遠，草徑接魚村。", "白日偶無客，青山長對門。", "藥鑪留火暖，花塢带煙昏。", "靜坐搜新句，冥心傍酒樽。"]'),
('618d68f5-fc5d-46d2-9d81-a719a40a483a','劍閣','燕肅','宋','宋诗','song-poetry','','[]','劍聳秋峰積靄昏，關城遥向望中分。',48,'全唐诗/poet.song.4000.json','["劍聳秋峰積靄昏，關城遥向望中分。", "觸新百堵連青嶂，依舊千家住白雲。", "松檜影隨巖寺出，管絃聲雜澗聲聞。"]'),
('ab3c1549-448d-45dc-a5dc-fca99c5d2e5a','贈惠山慶上人','燕肅','宋','宋诗','song-poetry','','[]','陸羽泉邊倚瘦筇，參差臺殿映疏松。',64,'全唐诗/poet.song.4000.json','["陸羽泉邊倚瘦筇，參差臺殿映疏松。", "五天講去春騎虎，一鉢擎來晝伏龍。", "像閣磬敲清有韻，蘇庭雲過靜無蹤。", "相逢多說遊方話，知老靈山第幾峰。"]'),
('fc6da5be-24ed-4665-b713-6e0a8ec8d5b8','句  其一','燕肅','宋','宋诗','song-poetry','','[]','鬢邊今日白，腰下幾時黄。',12,'全唐诗/poet.song.4000.json','["鬢邊今日白，腰下幾時黄。"]'),
('1e1c1890-99b2-4779-a012-41cc39a6572e','句  其二','燕肅','宋','宋诗','song-poetry','','[]','南昌襦袴歌將洽，西掖絲綸演未遲。',16,'全唐诗/poet.song.4000.json','["南昌襦袴歌將洽，西掖絲綸演未遲。"]'),
('3e6a7ef5-6b67-40a9-8be5-4c851a5dcc60','句  其三','燕肅','宋','宋诗','song-poetry','','[]','王宣古樓閣，習郁舊池塘。',12,'全唐诗/poet.song.4000.json','["王宣古樓閣，習郁舊池塘。"]'),
('937a8ef2-c69a-465c-94c1-04f50bd0c2fd','奉和御製中秋翫月歌','寇準','宋','宋诗','song-poetry','','[]','戒井銅龍漏水平，玉輪初滿物華清。',126,'全唐诗/poet.song.4000.json','["戒井銅龍漏水平，玉輪初滿物華清。", "光連南極星輝正，影泛中天帝宇明。", "風來蘋末披輕霧，香濕蘭叢浥零露。", "絳河橫度燦雲章，靈鵲羣飛遶宮樹。", "法久照兮慶昌時，樂芳宴兮忘疲。", "敷睿文兮玩澄景，當嚴更兮漸永。", "九門秘邃敞堯宸，靄靄金波矚目頻。", "進牘豈能抽鄙思，賡歌深媿預朝倫。"]'),
('c2c650eb-a40d-4bcf-a60f-0147edcf8678','奉聖旨賦牡丹花','寇準','宋','宋诗','song-poetry','','[]','栽培終得近天家，獨有芳名出衆花。',64,'全唐诗/poet.song.4000.json','["栽培終得近天家，獨有芳名出衆花。", "香遞暖風飄御座，葉籠輕靄襯明霞。", "縱吟宜把紅牋襞，留賞惟張翠幄遮。", "深覺侍臣千載幸，許隨仙仗看穠華。"]'),
('27a7b62e-e9b8-4bae-97ac-16e610d97929','奉和御製南郊禮成','寇準','宋','宋诗','song-poetry','','[]','薦降靈符昭瑞命，交修盛則薦清衷。',128,'全唐诗/poet.song.4000.json','["薦降靈符昭瑞命，交修盛則薦清衷。", "朝真曲里揚丕烈，類帝圓壇報昊穹。", "述職萬邦咸執玉，來庭異域協占風。", "禹功高大天無極，堯德明如日正中。", "福浸含生臻富壽，澤流綿宇霈龐鴻。", "粢盛豐潔神皆饗，金石和平政本通。", "鬰鬰雲煙當晝麗，熙熙景物共春融。", "羣臣抃蹈瞻宸扆，願比南山祝壽躬。"]'),
('6e9700e0-23e8-473a-a178-25858f1b3bec','奉和御製真游殿上梁','寇準','宋','宋诗','song-poetry','','[]','敦崇妙本膺丕貺，濬發鴻源示永年。',160,'全唐诗/poet.song.4000.json','["敦崇妙本膺丕貺，濬發鴻源示永年。", "吉語密傳當乙夜，粹儀祗覿擁祥煙。", "皇心翼翼精齋至，祖德綿綿道誨宣。", "誕集純禧彰錫羨，交修茂典表欽先。", "爰稽大壯新瓊宇，仰法殊庭設綺筵。", "山積瓌材咸備矣，神扶華棟見巍然。", "元龜獻兆良辰協，哲匠施勤庶藝全。", "四柱如翬循寶勢，觚稜削玉燦珠躔。", "黼帷夙設宸居麗，翠葆躬臨聖志虔。", "昭答明靈陳盛會，睿詞敷暢煥雲牋。"]'),
('458e0982-eeea-4643-a00d-bf0c9e4b5735','奉和御製郊外觀稼','寇準','宋','宋诗','song-poetry','','[]','天苑清塵宿雨收，翠華觀稼慶盈疇。',64,'全唐诗/poet.song.4000.json','["天苑清塵宿雨收，翠華觀稼慶盈疇。", "氣和玉燭成豐歲，露冷金莖凜素秋。", "日麗鮮原平杳杳，煙含嘉穀鬰油油。", "共知省歛敦農事，信史騰芳紀聖遊。"]'),
('f58437c6-d332-4c06-b35a-f90602ea79e6','瑞慶園觀稼奉聖旨次韻','寇準','宋','宋诗','song-poetry','','[]','善苗棲畝昭靈貺，禁苑鳴鑾值素秋。',64,'全唐诗/poet.song.4000.json','["善苗棲畝昭靈貺，禁苑鳴鑾值素秋。", "歛籍神倉符禮本，采詩良耜慶農收。", "宴開雲幄皇慈洽，日駐天衢睿賞留。", "千載逢辰增嶽抃，清塵叨從屬車遊。"]'),
('c0f0d88c-0ed3-4120-a751-c8d5fd7257da','應制賞花','寇準','宋','宋诗','song-poetry','','[]','上苑經春雨，宸遊屬盛時。',48,'全唐诗/poet.song.4000.json','["上苑經春雨，宸遊屬盛時。", "花光籠寶檻，柳色暗龍池。", "瀲灧雕觴滿，融和暖日遲。", "共歌成至樂，千載播聲詩。"]'),
('481eb6f5-faf5-4605-b36f-b6f57cd4979d','應制太清樓觀書','寇準','宋','宋诗','song-poetry','','[]','仙禁開書府，神毫紀格言。',48,'全唐诗/poet.song.4000.json','["仙禁開書府，神毫紀格言。", "簡編包舜禹，圍範總乾坤。", "稽古崇邦教，斯文闢聖門。", "從遊觀奧秘，何以報宸恩。"]'),
('41c88e02-c888-4cf4-8079-b3323431dd69','御製乃眷儲闈方崇學術錫羣書於冊府勵至業於承華日命近班同觀盛事七言十韻詩一首奉聖旨次韻','寇準','宋','宋诗','song-poetry','','[]','景命昭彰佑德基，元儲敦裕協祥期。',160,'全唐诗/poet.song.4000.json','["景命昭彰佑德基，元儲敦裕協祥期。", "寢門劭至嘗無怠，學肆多聞詎有疑。", "金玉騰音鏘睿律，簡編申錫振良規。", "河圖奧秘言誠訓，藝圃優柔善益資。", "玉宇風清傳密詔，蓬山雲委錫芳蕤。", "天顔不遠回宸眷，肉味都忘聽寶辭。", "燕翼詒謀欣教盛，上庠隆道慶才奇。", "叨逢華旦居黄閣，久侍宣遊近赤墀。", "恩厚薦承三晝接，力微寧致百工熙。", "東闈疏問英猷遠，聖慮乾乾更念茲。"]'),
('320dc1ec-0167-483c-b934-23818e2b9ef5','御製慶先后升祔禮成七言六韻奉和','寇準','宋','宋诗','song-poetry','','[]','天錫靈符興寶祚，澤流綿宇福含生。',96,'全唐诗/poet.song.4000.json','["天錫靈符興寶祚，澤流綿宇福含生。", "蒸蒸至孝咸歸厚，翼翼精衷尚執盈。", "順考漢儀彰道廣，欽崇周典闡文明。", "豆籩合饗豐盛備，管磬同和雅奏成。", "愛景融輝昭善應，非煙絢采協殊禎。", "尊升茂典光惇史，稽古鴻猷振帝紘。"]'),
('07788644-9016-40e7-85ae-be496b67f5ad','應制賞花釣魚','寇準','宋','宋诗','song-poetry','','[]','龍禁含佳氣，鑾輿下建章。',48,'全唐诗/poet.song.4000.json','["龍禁含佳氣，鑾輿下建章。", "碧波微蕩漾，紅萼竟芬芳。", "玉斝春醪滿，金波晝漏長。", "逢時空竊抃，萬宇正歡康。"]'),
('fd27c92f-64fe-4b77-ab25-4df00d87c836','和御製降聖節內中道場睹瑞鶴神雀歌','寇準','宋','宋诗','song-poetry','','[]','秋殿霜凝當永夕，靈場齋潔方無斁。',88,'全唐诗/poet.song.4000.json','["秋殿霜凝當永夕，靈場齋潔方無斁。", "高真諄誨昔親聞，上帝休禎今再覿。", "鬰葱兮卿雲，仙鶴兮不羣。", "肅清兮采席，神雀兮振翼。", "香飄華燭焰亭亭，風度翠簾聲歷歷。", "嘉應紛綸寶運昌，聖人功與天無極。"]'),
('d95044fc-9040-45b0-9140-6a2ad6295a5b','奉和御製奉祀述懷歌','寇準','宋','宋诗','song-poetry','','[]','巍巍至德充綿宇，翼翼宸心臨兆庶。',304,'全唐诗/poet.song.4000.json','["巍巍至德充綿宇，翼翼宸心臨兆庶。", "覆育懷生動法天，講求茂典皆師古。", "協和神化踵唐堯，彬蔚頌聲踰吉甫。", "赫奕皇威振八荒，清夷王度綏中土。", "豐年朝野正歡康，溢牒充圖福紀祥。", "睿聖繼明恢大業，禎符錫祚降穹蒼。", "省方展寀宣邦職，登岱銘功舉國章。", "睢上埋牲專事地，漢唐故實存聞記。", "精靈昭感果潛通，瑞應昭臻知所自。", "飆羽光臨神告彰，洪源肇啟僊游暨。", "瀨鄉舊壤闢珍詞，款謁齋莊敦睿意。", "譙都奏牘達彤庭，耆耋雲趨共瀝誠。", "順考皇儀尊妙道，再修盛節徇輿情。", "聲明文物當興運，申命羣儒究禮經。", "秩秩德音咸布惠，穰穰景福必求成。", "恭虔毖祠爲齋久，企仰真風志克勤。", "肅奉蕭薌嘉薦備，廣覃慶賜湛恩頻。", "式揚丕烈心彌潔，祗上鴻名道益伸。", "將睹虞巡陪法從，幸同鳬藻樂昌辰。"]'),
('2ea8356a-971d-4313-96ea-4c44cbc242e3','天安殿致齋','寇準','宋','宋诗','song-poetry','','[]','國陽崇大報，王宇藻多儀。',96,'全唐诗/poet.song.4000.json','["國陽崇大報，王宇藻多儀。", "散致尊王度，懷柔祝帝禧。", "儲精通合漠，玩志協徵夷。", "律正風來迥，宵長月上遲。", "漏筒聲淅瀝，陛戟影流離。", "夙戒羣倫序，交懽百慮怡。", "星繁陳法仗，雲密蔭平逵。", "傳曉鳴梢動，威容聲率祗。"]'),
('f39d677a-b257-4a76-b6c9-5cf5cbcaac88','天安殿酌獻天書','寇準','宋','宋诗','song-poetry','','[]','聖運昭惟永，高真協降祥。',120,'全唐诗/poet.song.4000.json','["聖運昭惟永，高真協降祥。", "方嚴泰壇祀，先薦釜山章。", "典禮官無曠，涓辰筮有常。", "中天華闕秘，象衮睟容莊。", "宵迥星河燦，風微羽衛揚。", "獻酬靈契接，陟降寶儀彰。", "顧諟欽元命，寅恭達上蒼。", "彌文輝竹帛，備物儼蕭薌。", "尊道宸心至，登春雅俗康。", "猶將奉齋潔，禔福俟穰穰。"]'),
('3f4ef54c-9327-4fcf-82cb-a01a24fb5978','西垣致齋日因成一章呈二相公','寇準','宋','宋诗','song-poetry','','[]','攝事修雩祀，齋居近紫庭。',72,'全唐诗/poet.song.4000.json','["攝事修雩祀，齋居近紫庭。", "千門夏雨歇，高樹夕陽生。", "更散掖垣靜，風來鐘漏清。", "巖廊慚舊德，書殿愧羣英。", "白髮將何補，丹心忽自驚。", "敢言陪邴魏，三接奉休明。"]'),
('d17bf70a-e50c-4298-abf1-2dc3ffcf9968','瓊林苑應制','寇準','宋','宋诗','song-poetry','','[]','鳳蹕出重城，宸遊順物情。',48,'全唐诗/poet.song.4000.json','["鳳蹕出重城，宸遊順物情。", "檻花紅蕊盛，苑樹綠陰成。", "雨過池塘靜，風來殿閣清。", "樂和堯酒滿，千載樂昇平。"]'),
('f0151d77-57c4-4750-b717-c1c3f0e84efb','和御製祀后土','寇準','宋','宋诗','song-poetry','','[]','臨晉迎清蹕，靈壇備克禋。',144,'全唐诗/poet.song.4000.json','["臨晉迎清蹕，靈壇備克禋。", "薦誠祠后土，求福爲蒸民。", "展義王猷遠，推恩慶賜均。", "千官陪漢祀，萬國奉虞巡。", "仗衛明初日，郊原麗上春。", "花飛函谷路，柳暗大陽津。", "宿麥深藏雉，柔桑遠映人。", "河流迴二陝，山勢壯三秦。", "簫鼓聞睢上，旌旗過渭濱。", "天聲驚遠野，兵氣懾邊鄰。", "在鎬皇歡洽，橫汾睿藻新。", "周南慚滯迹，空想屬車塵。"]'),
('c56ee096-4c55-418e-b85b-af2c7761ca33','述懷','寇準','宋','宋诗','song-poetry','','[]','吾家嗣儒業，奕世盛冠裳。',192,'全唐诗/poet.song.4000.json','["吾家嗣儒業，奕世盛冠裳。", "桂籍冠倫輩，天下知聲光。", "有才無其命，不得步玉堂。", "余亦好古者，詩禮承餘芳。", "赴義忘白刃，奮節凌秋霜。", "垂衣遇聖主，射策遭時昌。", "十九中高第，弱冠司國章。", "棘寺陪法吏，奉使安殊方。", "薄才難變俗，賤節惟勤王。", "務簡忽興念，不覺心徬徨。", "慈親違萬里，瘴雨悲南荒。", "端居增浩歎，離恨銷剛腸。", "木落多異感，蟬鳴非故鄉。", "長思千萬乘，奉職昇周行。", "步武親玉陛，獻納肩忠良。", "功成自高退，散髮遊滄浪。"]'),
('d1ce4779-a1fb-4cac-b5a7-1d7b1f5ff2ad','古別意','寇準','宋','宋诗','song-poetry','','[]','水螢光淡曉色寒，庭除索寞星河殘。',64,'全唐诗/poet.song.4000.json','["水螢光淡曉色寒，庭除索寞星河殘。", "清樽酒盡艷歌闋，離人欲去肝腸絕。", "露荷香散西風驚，征車漸遠聞鷄鳴。", "深閨從此泣秋扇，夢魂長在遼陽城。"]'),
('d8eaede9-4c94-4b7f-b9dc-c8d059424316','江南春','寇準','宋','宋诗','song-poetry','','["\u6000\u4eba", "\u5b8b\u8bcd\u7cbe\u9009", "\u5199\u666f", "\u5973\u5b50"]','波渺渺，柳依依。',36,'全唐诗/poet.song.4000.json','["波渺渺，柳依依。", "孤村芳草遠，斜日杏花飛。", "江南春盡離腸斷，蘋滿汀洲人未歸。"]'),
('7f33133a-4053-4c80-a299-334aa9cfdfa8','追思柳惲汀洲之詠尚有遺妍因書一絕','寇準','宋','宋诗','song-poetry','','[]','杳杳煙波隔千里，白蘋香散東風起。',32,'全唐诗/poet.song.4000.json','["杳杳煙波隔千里，白蘋香散東風起。", "日落汀洲一望時，愁情不斷如春水。"]'),
('3919cdc7-4e56-4625-a6d3-a8102c179bfb','遠恨','寇準','宋','宋诗','song-poetry','','[]','敗葉亂如雨，暮蟬聲似哭。',84,'全唐诗/poet.song.4000.json','["敗葉亂如雨，暮蟬聲似哭。", "感物悲昔心，佳期悵難續。", "雲山雖阻歎，韶華若在目。", "深情染綵牋，密密空盈幅。", "溫瘴雁不來，游魚隠深谷。", "羽鱗孰可憑，音書安可復。", "焚灰寄長風，字滅魂亦逐。"]'),
('542e28cb-454f-41c6-9d97-df4d61a55545','雜言','寇準','宋','宋诗','song-poetry','','[]','我徒曠達由胸臆，耻學鯫生事文墨。',96,'全唐诗/poet.song.4000.json','["我徒曠達由胸臆，耻學鯫生事文墨。", "蛟龍長欲趁風雷，騏驥焉能制啣勒。", "鏘金佩玉良有時，丐色諛言盡虛飾。", "功名富貴非偶然，楊子草玄徒默默。", "楚蘭罷秀足蓬蒿，青松委幹多荆棘。", "爭如一醉度流年，免使悲歡蕩情域。"]'),
('72148ea7-1828-4a87-b4fc-7435b4f57bc1','秋興呈裴李二同年  其一','寇準','宋','宋诗','song-poetry','','[]','秋興逐凉吹，颯然驅煩襟。',48,'全唐诗/poet.song.4000.json','["秋興逐凉吹，颯然驅煩襟。", "人悲故鄉遠，葉落空山深。", "楚俗傷去恨，秦城稀來音。", "何當返煙渭，自樂于園林。"]'),
('a47fedc6-8ca1-4567-a55d-f56beb9183fb','秋興呈裴李二同年  其二','寇準','宋','宋诗','song-poetry','','[]','歲晚亂山外，野望誰能同。',48,'全唐诗/poet.song.4000.json','["歲晚亂山外，野望誰能同。", "寒沙明夕照，敗葉驚西風。", "孤煙暝汀樹，霜氣高秋空。", "徘徊念前事，旅恨良難窮。"]'),
('7c65ff71-5d2f-4404-aebb-a5b1bb1bc362','暇日遊建平三閭故里廟貌荒凉慘動耳目噫賢者之祀世不絕享郡無正人遺棄若是感事傷俗因留斯句','寇準','宋','宋诗','song-poetry','','[]','人生苦遠遊，多是悲登眺。',120,'全唐诗/poet.song.4000.json','["人生苦遠遊，多是悲登眺。", "況復念三閭，遺蹤良可弔。", "道直出章華，才高逐邊徼。", "冤聲噴夜江，愁色迷煙嶠。", "斷碑沒敗莎，古木吟荒廟。", "祠正少來奠，岸峻稀停棹。", "神容漬老苔，壞壁通殘照。", "舊徑失朱門，空庭起寒燒。", "餘基雖索寞，清問長光耀。", "旌賢誰再興，勿使過者誚。"]'),
('242b7f77-c093-4c2b-9a89-160f339f3ae6','水閣晨起','寇準','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','板閣常晏眠，偶獨起清旦。',48,'全唐诗/poet.song.4000.json','["板閣常晏眠，偶獨起清旦。", "月落簷鳥語，煙開客船散。", "長江色自澄，汀樹聲空亂。", "羣動又復然，勞勞可長歎。"]'),
('098e68d3-639d-4eb3-b9d2-59855302dacb','晚望有感','寇準','宋','宋诗','song-poetry','','[]','出門望寒野，四顧惟椒坡。',48,'全唐诗/poet.song.4000.json','["出門望寒野，四顧惟椒坡。", "憶昔楚大夫，還此情如何。", "殘陽半明雨，水落西風多。", "因同下蔡恨，不覺增悲歌。"]'),
('cb89cfa4-3a4d-4ffa-b29a-9617d9a730c3','庚辰歲將命至巴東時已秋序霜荷索然偶賦是章用遣幽恨','寇準','宋','宋诗','song-poetry','','[]','秉軺偶將命，撫俗煙江湄。',84,'全唐诗/poet.song.4000.json','["秉軺偶將命，撫俗煙江湄。", "地僻接窮峽，務簡稀公期。", "秋信任無趣，野懷良自宜。", "月白夜蟬響，池暗風荷衰。", "溪雲入破牖，山菊開疏籬。", "貰酒不能醉，鄉園空結悲。", "徘徊獨凝望，目極長天涯。"]'),
('f4e869c2-0564-4b69-82a4-7d24803d1236','成安感秋','寇準','宋','宋诗','song-poetry','','[]','蟬噪木葉下，遠客忽驚秋。',96,'全唐诗/poet.song.4000.json','["蟬噪木葉下，遠客忽驚秋。", "凝恨悲晚候，萬緒皆如抽。", "芳時同夢幻，急景如奔流。", "念我何爲者，年來生百憂。", "貧居負勝事，壯歲傷羈遊。", "臨民慚墨綬，垂釣思滄洲。", "達則濟天下，窮當守一丘。", "胡能效時輩，靦冒隨沉浮。"]'),
('98fd6313-f2ff-4ad1-8502-276b5456a210','感興','寇準','宋','宋诗','song-poetry','','[]','憶昔金門初射策，一日聲華喧九陌。',96,'全唐诗/poet.song.4000.json','["憶昔金門初射策，一日聲華喧九陌。", "少年得意出風塵，自爲青雲無所隔。", "主上掄才登桂堂，神京進秩奔殊方。", "墨綬銅章竟何用，巴雲瘴雨徒荒凉。", "有時扼腕生憂端，儒書讀盡猶饑寒。", "丈夫意氣到如此，搔首空歌行路難。"]'),
('9b2fa5ae-975d-4ea9-826d-2db64117d2da','暇日  其一','寇準','宋','宋诗','song-poetry','','[]','江樓晝靜春陰變，日午簾空飛乳燕。',32,'全唐诗/poet.song.4000.json','["江樓晝靜春陰變，日午簾空飛乳燕。", "帆稀客散野岸空，隠隠遥峰望中見。"]'),
('30ee321e-4365-4926-9208-f4fa00f47f6e','暇日  其二','寇準','宋','宋诗','song-poetry','','[]','郵亭落日多飛絮，琵琶音重江春暮。',32,'全唐诗/poet.song.4000.json','["郵亭落日多飛絮，琵琶音重江春暮。", "坐久凝眸欲斷腸，梅雨如煙暝村樹。"]'),
('ab836dd8-5a08-4992-a56f-2173c7873c97','南浦','寇準','宋','宋诗','song-poetry','','[]','春色入垂楊，煙波漲南浦。',24,'全唐诗/poet.song.4000.json','["春色入垂楊，煙波漲南浦。", "落日動離魂，江花泣微雨。"]'),
('a6d831b8-6313-4934-8fb0-578b04b29a84','長郊雨餘遠樹減翠新蟬忽鳴激耳嘹唳久客孤坐情如何哉形之于文聊以自遣','寇準','宋','宋诗','song-poetry','','[]','遥山夏雨歇，遠樹凉風至。',72,'全唐诗/poet.song.4000.json','["遥山夏雨歇，遠樹凉風至。", "憑欄偶開襟，新蟬動秋思。", "沙溪潔細流，庭木驚疏翠。", "節候又復然，幽憂斯所萃。", "芳歲若奔流，羲光不停轡。", "感物悼前期，誰知此時意。"]'),
('9fba2954-19dc-46a7-8988-1f5a7e3920d4','雪霽池上','寇準','宋','宋诗','song-poetry','','[]','雪霽池上亭，晴光照泉石。',48,'全唐诗/poet.song.4000.json','["雪霽池上亭，晴光照泉石。", "暖覺岸冰銷，靜聞簷溜滴。", "務簡身暫閑，景幽心自適。", "極目望南山，圭峰露微碧。"]'),
('a4e38132-1ddb-435c-8248-7dc6a33356b7','有寄','寇準','宋','宋诗','song-poetry','','[]','金陵煙草綠，玉塞霜天白。',24,'全唐诗/poet.song.4000.json','["金陵煙草綠，玉塞霜天白。", "萬里隔關山，年來斷消息。"]'),
('06128e6a-a8e9-4836-8178-9e6a69413f49','春日登樓懷歸','寇準','宋','宋诗','song-poetry','','["\u767b\u9ad8", "\u601d\u4e61", "\u671b\u8fdc"]','高樓聊引望，杳杳一川平。',48,'全唐诗/poet.song.4000.json','["高樓聊引望，杳杳一川平。", "遠水無人渡，孤舟盡日橫。", "荒村生斷靄，深樹語流鶑。", "舊業遥清渭，沉思忽自驚。"]'),
('ac10f2dd-c786-4f5e-aecb-446f4e5e7b46','秋思','寇準','宋','宋诗','song-poetry','','[]','秋氣動天地，恍然情未窮。',48,'全唐诗/poet.song.4000.json','["秋氣動天地，恍然情未窮。", "故園應墜葉，昨夜又西風。", "白草侵危堞，寒濤接遠空。", "搘頤當此景，無語夕陽中。"]'),
('d2b210cc-26fc-46eb-8e6d-aa1499452545','再歸秦川','寇準','宋','宋诗','song-poetry','','[]','阮路何方盡，西歸興未勞。',48,'全唐诗/poet.song.4000.json','["阮路何方盡，西歸興未勞。", "河流經陝狹，山色入秦高。", "返照明秋壘，孤村接暮濤。", "還如丁令至，故里滿蓬蒿。"]'),
('f234f019-7b6a-4dc5-8d25-27cd1cef27b0','秋夜獨書勉詩友','寇準','宋','宋诗','song-poetry','','[]','西風驚萬木，危坐思悠哉。',48,'全唐诗/poet.song.4000.json','["西風驚萬木，危坐思悠哉。", "故國經年別，秋鴻半夜來。", "人應多棄善，天豈不憐才。", "休學嚴夫子，荒凉老釣臺。"]'),
('559f9def-0456-4a02-b69c-2424ea3b8ced','長安書事','寇準','宋','宋诗','song-poetry','','[]','一從洛邑移秦甸，三見東郊綻早梅。',64,'全唐诗/poet.song.4000.json','["一從洛邑移秦甸，三見東郊綻早梅。", "蓮府晝閑鈴閤閉，柳營春暖射堂開。", "齋壇首冠慚諸將，相印兼營接上台。", "何事燕公輕仗鉞，却言分閫是麤才。"]'),
('efdb1b3a-fa82-4446-b91d-af1054f58eb5','重陽登高偶作','寇準','宋','宋诗','song-poetry','','[]','務閑留上客，佳節值重陽。',48,'全唐诗/poet.song.4000.json','["務閑留上客，佳節值重陽。", "旨酒浮仙菊，清歌遶畫梁。", "高城明落日，疏樹覺微霜。", "且盡登臨興，餘歡尚未忘。"]'),
('1b57733a-5879-45d3-a719-b64a5c2fdc51','塞上','寇準','宋','宋诗','song-poetry','','[]','春風千里動，榆塞雪方休。',48,'全唐诗/poet.song.4000.json','["春風千里動，榆塞雪方休。", "晚角數聲起，交河冰未流。", "征人臨迥磧，歸雁別滄洲。", "我欲思投筆，期封定遠侯。"]'),
('b7bf2867-d7a2-4dc9-bb14-2e3fdbb6c997','寓居有懷','寇準','宋','宋诗','song-poetry','','[]','疏林頻落葉，孤僻繼離騷。',48,'全唐诗/poet.song.4000.json','["疏林頻落葉，孤僻繼離騷。", "獨坐聞鴻遠，閑吟見月高。", "夢回更自永，思苦夜何勞。", "寂寂西郊內，披衣聽海濤。"]'),
('8a6822e5-39a5-41bb-a110-068a0ca5be27','重到進公院','寇準','宋','宋诗','song-poetry','','[]','伍年重到支公院，物態人情盡不同。',32,'全唐诗/poet.song.4000.json','["伍年重到支公院，物態人情盡不同。", "唯有寒檉暗秋色，依然蟬噪夕陽中。"]'),
('aa258415-b26e-40d8-bd13-86df1d2a1adc','野步','寇準','宋','宋诗','song-poetry','','[]','幽景恣追尋，遲遲傍柳陰。',96,'全唐诗/poet.song.4000.json','["幽景恣追尋，遲遲傍柳陰。", "靜思非世務，孤立是閑心。", "村迥遥峰出，溪明返照侵。", "片沙招野步，白鷺伴高吟。", "積雨迴塘漲，微晴疊翠深。", "春鳩鳴古寺，煙草入平林。", "迸笋行無定，飛花勢不禁。", "凝然客亭上，鄉思獨沉沉。"]'),
('3d5df395-c09f-4b7d-b456-77cc6c1de93d','秋日原上','寇準','宋','宋诗','song-poetry','','[]','蕭蕭古原上，景物感離腸。',48,'全唐诗/poet.song.4000.json','["蕭蕭古原上，景物感離腸。", "遠嶠收殘雨，寒林带夕陽。", "溪聲迷竹韻，野色混秋光。", "吟罷還西望，平沙起雁行。"]'),
('6b617225-ff7f-4e53-849b-46c47c63ecd4','江上晚望懷所知','寇準','宋','宋诗','song-poetry','','[]','遲遲迷遠信，閑立大江隅。',48,'全唐诗/poet.song.4000.json','["遲遲迷遠信，閑立大江隅。", "遊子在何處，秋風吹五湖。", "潮迴沙鳥聚，岸闊釣船孤。", "歸去還堪歎，田園半已蕪。"]'),
('5280c6c9-6930-4417-9209-d3c53fa56434','秦中感懷寄江外知己','寇準','宋','宋诗','song-poetry','','[]','念子隔江海，浩然時已秋。',48,'全唐诗/poet.song.4000.json','["念子隔江海，浩然時已秋。", "蟬鳴關外樹，人在水邊樓。", "髮白猶搜句，時清尚旅遊。", "遥思當永夜，不寐向孤舟。"]'),
('af5f170e-9cbd-40b2-a6a8-d9e296bd8a0d','水村即事','寇準','宋','宋诗','song-poetry','','[]','虛齋臨遠水，吟釣度朝晡。',48,'全唐诗/poet.song.4000.json','["虛齋臨遠水，吟釣度朝晡。", "葦岸秋聲合，莎亭鶴影孤。", "片雲藏疊巘，野燒起寒蕪。", "獨步時吟望，離人隔五湖。"]'),
('a479cbc8-5711-46d7-8f4c-2de208edf853','暮秋感興','寇準','宋','宋诗','song-poetry','','[]','苒苒前期遠，窮途一可傷。',48,'全唐诗/poet.song.4000.json','["苒苒前期遠，窮途一可傷。", "有時聞落葉，不語立殘陽。", "塞草秋先白，溪沙晚更光。", "那堪望天末，燕雁又成行。"]'),
('d84fcbc3-4f09-4b4a-a93f-fd6f6ae902d6','秋夜感興寄吳順之','寇準','宋','宋诗','song-poetry','','[]','耿耿不成寐，楚鄉經暮秋。',48,'全唐诗/poet.song.4000.json','["耿耿不成寐，楚鄉經暮秋。", "故人遥海嶠，寒月滿江樓。", "閉戶生蒼蘚，安閑到白頭。", "如何太平日，獨不出汀洲。"]'),
('4846a61b-630b-4592-8cca-ed59d50e63a6','夜坐有懷寄張士遜','寇準','宋','宋诗','song-poetry','','[]','清秋吟更僻，況復古亭間。',48,'全唐诗/poet.song.4000.json','["清秋吟更僻，況復古亭間。", "少夢蟲聲碎，無風樹影閑。", "月華澄曲沼，霜氣滿空山。", "不見張夫子，誰人共往還。"]'),
('6faa58c0-ae07-4ec7-b73f-8035a208f9bb','送人下第歸吳','寇準','宋','宋诗','song-poetry','','[]','鶑老計還失，負書歸故鄉。',48,'全唐诗/poet.song.4000.json','["鶑老計還失，負書歸故鄉。", "杏園無近路，澤國有高堂。", "白鳥迷幽浦，寒猿叫夕陽。", "離懷休墮淚，春草正茫茫。"]'),
('c20737fa-4eba-4620-a34f-3f73ea29e0df','秋訪江上友生所居','寇準','宋','宋诗','song-poetry','','[]','苔石半寥落，坐來生遠愁。',48,'全唐诗/poet.song.4000.json','["苔石半寥落，坐來生遠愁。", "故人應罷釣，寒葉自驚秋。", "村隔平沙暝，江和暮靄流。", "徘徊不能去，此處有扁舟。"]'),
('9ae82f1e-ccb3-483f-8da3-487c1afd2af9','冬夜旅思','寇準','宋','宋诗','song-poetry','','[]','年少嗟羈旅，煙宵進未能。',48,'全唐诗/poet.song.4000.json','["年少嗟羈旅，煙宵進未能。", "江樓千里月，雪屋一龕燈。", "遠信憑邊雁，孤吟寄嶽僧。", "爐灰愁擁坐，硯水半成冰。"]'),
('9539b059-fe32-4e38-9032-7005f779bab8','貽趙少府','寇準','宋','宋诗','song-poetry','','[]','夫君何感命，拾載困風塵。',48,'全唐诗/poet.song.4000.json','["夫君何感命，拾載困風塵。", "薄宦須流落，孤吟更苦辛。", "山寒泉易凍，邊近草難春。", "珍重常招隠，慚非孟子鄰。"]'),
('b882ac4d-0f3f-4bd8-a009-87c53885e457','春日懷張曙','寇準','宋','宋诗','song-poetry','','[]','不見張夫子，巖花幾度新。',48,'全唐诗/poet.song.4000.json','["不見張夫子，巖花幾度新。", "久閑空賦命，遠別更傷春。", "雨艇愁天末，煙蓑隠渭濱。", "應嗟年未冠，已作異鄉人。"]'),
('544defa0-e810-4059-b88f-dce613f1b861','初夏雨中','寇準','宋','宋诗','song-poetry','','[]','綠樹新陰暗井桐，雜英當砌墜疏紅。',32,'全唐诗/poet.song.4000.json','["綠樹新陰暗井桐，雜英當砌墜疏紅。", "重門寂寂經初夏，盡日垂簾細雨中。"]'),
('2dffaebe-6358-41cd-91e1-20ba2b3bd87e','感興寄蓮嶽一二詩禪友','寇準','宋','宋诗','song-poetry','','[]','西風傷遠別，前計競成非。',48,'全唐诗/poet.song.4000.json','["西風傷遠別，前計競成非。", "芳草此時暮，故山何日歸。", "禪應同雅道，貧合長天機。", "翻憶雲溪伴，無憀對落暉。"]'),
('b433a33f-a567-412e-bf95-4278df067628','贈隠士','寇準','宋','宋诗','song-poetry','','[]','夫子才名重，貧居志未勞。',48,'全唐诗/poet.song.4000.json','["夫子才名重，貧居志未勞。", "吟當寒夜苦，閑到白頭高。", "心地通禪寂，田園近海濤。", "不知千載後，誰更續離騷。"]'),
('284b819f-14b4-4268-9cfb-93f85b7da8a0','湖上作','寇準','宋','宋诗','song-poetry','','[]','極目望南浦，望中生遠思。',48,'全唐诗/poet.song.4000.json','["極目望南浦，望中生遠思。", "雁沉芳草渡，燒斷夕陽陂。", "歲月寒萍梗，江山念別離。", "猶餘清夜夢，暫與白雲期。"]'),
('88ea1cbb-58ef-4e61-bdce-8d2da3739246','有懷','寇準','宋','宋诗','song-poetry','','[]','秦川春婉晚，漢水路迢遥。',24,'全唐诗/poet.song.4000.json','["秦川春婉晚，漢水路迢遥。", "不待凭危檻，離魂已暗銷。"]'),
('3925960c-fbb5-4f08-87e6-98490998432c','送李生歸秦中','寇準','宋','宋诗','song-poetry','','[]','酒闌還執手，之子擬歸秦。',48,'全唐诗/poet.song.4000.json','["酒闌還執手，之子擬歸秦。", "風雪過殘歲，山川近早春。", "久遊詩思苦，遠別柳條新。", "後會知何日，空餘淚滿巾。"]'),
('5dce0e65-07a2-413d-b49f-9fd445763a9e','書懷寄韋山人','寇準','宋','宋诗','song-poetry','','[]','萬事不關慮，孤吟役此生。',48,'全唐诗/poet.song.4000.json','["萬事不關慮，孤吟役此生。", "風騷中旨趣，山水裏心情。", "衆木彫寒色，空江噴暮聲。", "終期謁君子，同遶綠苔行。"]'),
('b2ae2116-6e4d-48a6-8f60-a27bdec3524d','閑夜圍棋作','寇準','宋','宋诗','song-poetry','','[]','歸山終未遂，折桂復何時。',24,'全唐诗/poet.song.4000.json','["歸山終未遂，折桂復何時。", "且共江人約，松軒雪夜棋。"]'),
('eea9e223-8bb8-4489-b5a8-0e958e5ff388','紙鳶','寇準','宋','宋诗','song-poetry','','[]','碧落秋方靜，騰空力尚微。',24,'全唐诗/poet.song.4000.json','["碧落秋方靜，騰空力尚微。", "清風如可託，終共白雲飛。"]'),
('10385d44-7f2b-410c-8d8f-3a663d95a083','春雨','寇準','宋','宋诗','song-poetry','','[]','散亂縈花塢，空濛暗柳堤。',24,'全唐诗/poet.song.4000.json','["散亂縈花塢，空濛暗柳堤。", "望迴腸已斷，何處更鶑啼。"]'),
('cbbe1ae0-7003-4e76-9b99-8ca77ffb99a4','夜坐懷故友','寇準','宋','宋诗','song-poetry','','[]','西風起窮巷，衆木又彫零。',48,'全唐诗/poet.song.4000.json','["西風起窮巷，衆木又彫零。", "蕙浦月華白，竹窗燈影青。", "故人難重見，鄰笛不堪聽。", "行傍秋池上，孤吟對遠星。"]'),
('45bdb4c3-e9eb-4b56-b23e-ebed8c470a4d','南陽帝上各賦玉蝴蝶花一絕','寇準','宋','宋诗','song-poetry','','[]','堪賞東君造化奇，裝成蝴蝶滿纖枝。',32,'全唐诗/poet.song.4000.json','["堪賞東君造化奇，裝成蝴蝶滿纖枝。", "粉融輕翅攢花蕊，疑是尋芳未去時。"]'),
('d7184581-f5dc-4a69-b9ec-3bff012bdd7e','鄴北旅中懷友人','寇準','宋','宋诗','song-poetry','','[]','浮世多塵事，悠悠難定期。',48,'全唐诗/poet.song.4000.json','["浮世多塵事，悠悠難定期。", "夢闌懷遠夜，秋盡望鄉時。", "道在應無悶，風澆自業詩。", "何當歸釣渚，搘肘一沉思。"]'),
('afdef7c1-dc5d-4bca-b4e1-025be90eb729','弔任瓘處士','寇準','宋','宋诗','song-poetry','','[]','一生長抱恨，終亦是貧居。',48,'全唐诗/poet.song.4000.json','["一生長抱恨，終亦是貧居。", "遺信留孤鶴，營墳賣古書。", "竹齋無俗物，秋圃有寒蔬。", "福善何言昧，悠然望太虛。"]'),
('20506b55-c1c2-4839-b050-d1d11d0488b0','秋懷','寇準','宋','宋诗','song-poetry','','[]','落日留不住，默然空淚零。',48,'全唐诗/poet.song.4000.json','["落日留不住，默然空淚零。", "敗莎侵陋巷，疏葉滿閑庭。", "有趣窮風雅，無機敵杳冥。", "浮榮安足戀，歸去亂山青。"]'),
('797ff501-4e28-4814-ad09-0f2592970c7f','送友生下第南歸','寇準','宋','宋诗','song-poetry','','[]','頻頻退禮闈，此去欲忘機。',48,'全唐诗/poet.song.4000.json','["頻頻退禮闈，此去欲忘機。", "霄漢貧難達，江湖老獨歸。", "程遥秋浪疊，村暝夜燈微。", "應使爲儒者，翻悲苦業非。"]'),
('5bd62c1f-5cb0-4692-a289-e79682a446b7','邊城春望','寇準','宋','宋诗','song-poetry','','[]','獨望原西路，離襟倍黯然。',48,'全唐诗/poet.song.4000.json','["獨望原西路，離襟倍黯然。", "青山遮故國，絕塞度新年。", "風聚沙迷岸，煙開燒滿川。", "歸心正無際，驃騎莫留連。"]'),
('b895ed04-c48c-4157-93e3-a0ab70609c14','草','寇準','宋','宋诗','song-poetry','','[]','獨步高原上，依依動所思。',48,'全唐诗/poet.song.4000.json','["獨步高原上，依依動所思。", "無人尋蕙徑，落日滿江湄。", "楚澤晴芳處，秦川晚翠時。", "此中興廢事，千古復誰知。"]'),
('580c8eeb-a0af-4cf8-a6fe-075efef45770','送左眉州之任','寇準','宋','宋诗','song-poetry','','[]','分官離法署，承命守眉州。',48,'全唐诗/poet.song.4000.json','["分官離法署，承命守眉州。", "山館鄰孤寺，春城過亂流。", "江雲長映日，蜀魄似悲秋。", "到郡揚清政，遺黎病必瘳。"]'),
('890a42ac-5be5-4024-9dca-4fb0d65c2453','楚江夜懷','寇準','宋','宋诗','song-poetry','','[]','西風生遠水，蕭颯度吟臺。',48,'全唐诗/poet.song.4000.json','["西風生遠水，蕭颯度吟臺。", "明日夜還滿，故人秋未來。", "寒蛩啼暗壁，敗葉下蒼苔。", "誰念空江外，年年首重迴。"]'),
('edefdea7-89e9-435c-b8f1-fc6747974106','春日書懷','寇準','宋','宋诗','song-poetry','','[]','曾讀前書笑古今，耻隨流俗信浮沉。',64,'全唐诗/poet.song.4000.json','["曾讀前書笑古今，耻隨流俗信浮沉。", "終期直道扶元化，敢爲虛名役片心。", "默坐野禽啼晝景，閉門官柳長春陰。", "世間事了須先退，不待霜毛漸滿簪。"]'),
('b4525236-261c-4db5-b364-74f2495e6b66','離京日作','寇準','宋','宋诗','song-poetry','','[]','離歌豈忍罇前聽，別恨無由醉裏消。',32,'全唐诗/poet.song.4000.json','["離歌豈忍罇前聽，別恨無由醉裏消。", "惟有夢魂歸北闕，不知京洛路迢遥。"]'),
('853f4f93-3892-469e-98b8-36ef290d8542','夜泊江上','寇準','宋','宋诗','song-poetry','','[]','歲暮峽中村，維舟古樹根。',48,'全唐诗/poet.song.4000.json','["歲暮峽中村，維舟古樹根。", "羣峰初落日，夜後獨聞猿。", "流水自無盡，客愁那可論。", "平明離楚岸，迢遞指吳門。"]'),
('7523a54e-5fae-4d69-bd88-bcfcb7fbf7d1','新蟬','寇準','宋','宋诗','song-poetry','','[]','寂寂宮槐雨乍晴，高枝微带夕陽明。',32,'全唐诗/poet.song.4000.json','["寂寂宮槐雨乍晴，高枝微带夕陽明。", "臨風忽起悲秋思，獨聽新蟬第一聲。"]'),
('0101268d-24e6-4edf-9c40-f93dee0500ae','寄獻廣南許虞部','寇準','宋','宋诗','song-poetry','','[]','南國江山五十州，星郎從此播芳猷。',64,'全唐诗/poet.song.4000.json','["南國江山五十州，星郎從此播芳猷。", "詩窮雅道皆清唱，官重名曹未白頭。", "望斷蠻村煙樹遠，吟殘嶺月海風秋。", "三年政滿迎丹詔，諫署重膺仄席求。"]'),
('47c91419-cc65-4da7-adb2-7a6ba572992e','送吉上人','寇準','宋','宋诗','song-poetry','','[]','新鴻并落葉，正逐朔風飛。',48,'全唐诗/poet.song.4000.json','["新鴻并落葉，正逐朔風飛。", "此地仍分首，何山是所歸。", "問程雲棧遠，宿館雨燈微。", "莫恨天涯別，重尋志未違。"]'),
('21ad318b-3b52-49a2-8ecb-8757dc867a6a','秋夕書懷','寇準','宋','宋诗','song-poetry','','[]','官路時風漸識情，一悲前計遠愁生。',64,'全唐诗/poet.song.4000.json','["官路時風漸識情，一悲前計遠愁生。", "深秋寒氣侵燈影，半夜疏林起雨聲。", "縣印終年拘吏役，煙蓑何日避浮名。", "窮通休問巢蓮骨，大抵無徒是至清。"]'),
('c03ea903-7c71-401e-8618-ca10a6d8422a','春郊閑望','寇準','宋','宋诗','song-poetry','','[]','風騷高處謝知音，公退何妨縱野吟。',64,'全唐诗/poet.song.4000.json','["風騷高處謝知音，公退何妨縱野吟。", "弱柳不能牽別恨，片雲應念識閑心。", "沙平古岸春潮急，門掩殘陽暮草深。", "凝望江皋動幽興，數聲鐘磐出西林。"]'),
('b2803fe2-91c1-4d10-ad3a-e9f2a771a698','雨中書事','寇準','宋','宋诗','song-poetry','','[]','一雨起前浦，霏微向暮秋。',48,'全唐诗/poet.song.4000.json','["一雨起前浦，霏微向暮秋。", "誰方眠釣艇，我獨在江樓。", "山晦峰巒隠，煙凝島嶼幽。", "何當見晴旭，一得泛迴舟。"]'),
('789d0901-5ba8-40b9-b5c1-91e1161928c6','夜懷寄友生','寇準','宋','宋诗','song-poetry','','[]','遥夜獨無趣，怳然思故交。',48,'全唐诗/poet.song.4000.json','["遥夜獨無趣，怳然思故交。", "泉聲飛石壁，星影動林梢。", "志壯難低俗，情閑任獻嘲。", "秋山雖入望，猶不似衡茅。"]'),
('7bfe1011-ecf9-4361-9595-db2ac2a4492c','秋夜懷歸','寇準','宋','宋诗','song-poetry','','[]','背窗寒燭影沉沉，楚客鄉思欲不禁。',64,'全唐诗/poet.song.4000.json','["背窗寒燭影沉沉，楚客鄉思欲不禁。", "板閣漏殘人自遠，水螢光淡夜方深。", "牢愁聞雨眠疏屋，歸夢隨雲徹故林。", "憶著煙村舊風景，柿紅時節又鳴砧。"]'),
('b2c3549a-2430-46c4-ada0-b33d61063910','夏夜閑書','寇準','宋','宋诗','song-poetry','','[]','雨濛村落野梅黄，茅閣長吟水氣凉。',64,'全唐诗/poet.song.4000.json','["雨濛村落野梅黄，茅閣長吟水氣凉。", "幽鳥遠聲來獨樹，小荷疏影占前塘。", "閑心終不忘魚釣，澹水真宜習老莊。", "報國自知無世用，煙蓑何日卧清漳。"]'),
('487a9503-a747-4e93-9625-ba9accf0220c','秋興浩然追憶館殿幽致偶成長句寄徐休學士','寇準','宋','宋诗','song-poetry','','[]','軺車南去詠江天，閑憶羣賢倍黯然。',64,'全唐诗/poet.song.4000.json','["軺車南去詠江天，閑憶羣賢倍黯然。", "御水莎青孤立鷺，宮槐煙冷數聲蟬。", "石渠吏散簾風靜，鳳闕雲歸霽景鮮。", "幽致不知何日共，思君唯賦帝京篇。"]'),
('64c7a2dc-f840-415d-b3ec-8976dc0a0156','宿江西寺','寇準','宋','宋诗','song-poetry','','[]','獨宿西林夜，凝然靜擁袍。',48,'全唐诗/poet.song.4000.json','["獨宿西林夜，凝然靜擁袍。", "巫雲秋暝峽，楚月冷生濤。", "莎敗蛩猶噪，鄉遥夢亦勞。", "霜風開落葉，還欲續離騷。"]'),
('e397615d-61e4-4995-8946-b6795f05a40b','聞杜宇','寇準','宋','宋诗','song-poetry','','[]','曾爲深冤無處雪，長年江上哭青春。',32,'全唐诗/poet.song.4000.json','["曾爲深冤無處雪，長年江上哭青春。", "平林雨歇殘陽後，愁殺天涯去國人。"]'),
('065872fa-59f4-4380-8b61-c156b26b84b3','巴東寒食','寇準','宋','宋诗','song-poetry','','[]','春雨蕭蕭寒食天，遠行猶在楚江邊。',64,'全唐诗/poet.song.4000.json','["春雨蕭蕭寒食天，遠行猶在楚江邊。", "人思故國迷殘照，鳥隔深花語斷煙。", "薄宦未能酬壯節，良時空自感流年。", "因循未學陶潛興，長見孤雲倍黯然。"]'),
('4ad32967-279b-43b6-b622-d30f179337f4','春晚書事','寇準','宋','宋诗','song-poetry','','[]','春盡江天景寂寥，思鄉還共楚雲遥。',64,'全唐诗/poet.song.4000.json','["春盡江天景寂寥，思鄉還共楚雲遥。", "林花經雨香猶在，堤柳無風絮自飄。", "水國獨慚臨縣邑，煙郊爭合負漁樵。", "青梅時節遲歸計，且逐餘芳殢酒瓢。"]'),
('4cbee2eb-8752-4009-9073-907e87946175','月夜懷故人','寇準','宋','宋诗','song-poetry','','[]','清夜月初滿，蘚庭吟更幽。',48,'全唐诗/poet.song.4000.json','["清夜月初滿，蘚庭吟更幽。", "梧桐疏影老，蟋蟀亂聲秋。", "舊國情何極，空江思欲流。", "故人今底處，危坐獨凝愁。"]'),
('4fb09eb4-e11c-475c-bf50-5782ce3c0032','和趙監丞贈隠士','寇準','宋','宋诗','song-poetry','','[]','不愛簪裾陪盛列，終年深隠養天機。',64,'全唐诗/poet.song.4000.json','["不愛簪裾陪盛列，終年深隠養天機。", "靜聞風雨眠漁艇，閑稱林泉掛道衣。", "門接水村多野色，鶴當莎徑立殘暉。", "高吟幽賞無羈束，始覺趨時事事非。"]'),
('9f767c7d-df31-4587-91df-00b83b7af9d2','雨夜書事','寇準','宋','宋诗','song-poetry','','[]','離人聽積雨，滴滴動鄉心。',48,'全唐诗/poet.song.4000.json','["離人聽積雨，滴滴動鄉心。", "故國程猶遠，重門夜正深。", "氣昏濛燼燭，巢冷語棲禽。", "遥想江南岸，餘花委故林。"]'),
('b639f9a6-827c-49e3-82c6-9e89be2eb4d7','歸州留別傅君','寇準','宋','宋诗','song-poetry','','[]','楊柳如絲拂畫橋，此中留語欲魂銷。',32,'全唐诗/poet.song.4000.json','["楊柳如絲拂畫橋，此中留語欲魂銷。", "還愁別後巴東館，獨聽空江半夜潮。"]'),
('f9d617b2-ecea-41a2-88f8-ba073a90d9ef','秋晚閑書','寇準','宋','宋诗','song-poetry','','[]','吟情自覺都無趣，況復離居感物華。',64,'全唐诗/poet.song.4000.json','["吟情自覺都無趣，況復離居感物華。", "厭讀羣書尋野徑，閑收落葉煮山茶。", "燒殘寒菊花猶在，霜過香橙味轉加。", "因想前期重搔首，不堪秋思極長沙。"]'),
('c44c22cb-2d6a-4e6c-90dd-3904be6ed739','聞笛','寇準','宋','宋诗','song-poetry','','[]','平野人歸後，孤城日落時。',24,'全唐诗/poet.song.4000.json','["平野人歸後，孤城日落時。", "西風聞一笛，惆悵憶桓伊。"]'),
('fba2985d-d3f5-41be-a6c7-a25891b07ff1','縣齋春書十二韻','寇準','宋','宋诗','song-poetry','','[]','縣幽無俗事，公退只高吟。',144,'全唐诗/poet.song.4000.json','["縣幽無俗事，公退只高吟。", "江到荆門闊，山連蜀國深。", "峽雲長映日，蠻雨易成霖。", "羣雀鳴春院，饑猿叫夜岑。", "庭荒多古木，地僻見沙禽。", "印鎖殘陽後，人歸疊翠陰。", "思鄉空索寞，素分信浮沉。", "樂靜稀塵累，甘閑負壯心。", "衰容常懶櫛，病髮豈勝簪。", "寡欲慵求友，防邪每自箴。", "澆風終耻合，前事固難諶。", "望斷天涯外，離魂欲不禁。"]'),
('f83db31d-3e35-47d6-94ee-be3854c08b90','予頃從穰下移涖河陽洎出中書復領分陝惟茲二鎮俯接洛都皆山河襟带之地也每凭高極望思以詩句狀其物景久而方成四絕句書于河上亭壁  其一','寇準','宋','宋诗','song-poetry','','[]','堤草惹煙連野綠，岸花經雨壓枝紅。',32,'全唐诗/poet.song.4000.json','["堤草惹煙連野綠，岸花經雨壓枝紅。", "年來多病辜春醉，惆悵河橋酒旆風。"]'),
('1c0872ce-1fc3-44e1-a60e-3c9385011338','予頃從穰下移涖河陽洎出中書復領分陝惟茲二鎮俯接洛都皆山河襟带之地也每凭高極望思以詩句狀其物景久而方成四絕句書于河上亭壁  其二','寇準','宋','宋诗','song-poetry','','[]','蟬鳴日正樹陰濃，避暑行吟獨杖筇。',32,'全唐诗/poet.song.4000.json','["蟬鳴日正樹陰濃，避暑行吟獨杖筇。", "却愛野雲無定處，水邊容易聳奇峰。"]'),
('08b17712-290d-451c-8159-ce29f893a95f','予頃從穰下移涖河陽洎出中書復領分陝惟茲二鎮俯接洛都皆山河襟带之地也每凭高極望思以詩句狀其物景久而方成四絕句書于河上亭壁  其三','寇準','宋','宋诗','song-poetry','','["\u5199\u666f", "\u6292\u60c5", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u9ec4\u6cb3"]','岸闊檣稀浪渺茫，獨凭危檻思何長。',32,'全唐诗/poet.song.4000.json','["岸闊檣稀浪渺茫，獨凭危檻思何長。", "蕭蕭遠樹疏林外，一半秋山带夕陽。"]'),
('f2b8cc90-9327-4054-8228-876dcbf96ad7','予頃從穰下移涖河陽洎出中書復領分陝惟茲二鎮俯接洛都皆山河襟带之地也每凭高極望思以詩句狀其物景久而方成四絕句書于河上亭壁  其四','寇準','宋','宋诗','song-poetry','','[]','暮天寥落凍雲垂，一望危亭欲下遲。',32,'全唐诗/poet.song.4000.json','["暮天寥落凍雲垂，一望危亭欲下遲。", "臨水數村誰畫得，淺山寒雪未銷時。"]'),
('52880ad7-aa68-40ea-8b99-5da5be72b87e','秋夜懷洛下一上人','寇準','宋','宋诗','song-poetry','','[]','遊宦忘機久，心源亦自澄。',48,'全唐诗/poet.song.4000.json','["遊宦忘機久，心源亦自澄。", "夜聽吳苑雨，秋憶洛城僧。", "木葉驚棲鳥，寒窗暗靜燈。", "何時過竹院，一得問三乘。"]'),
('c62fcec0-4513-4be0-b514-03d831e424ba','題花','寇準','宋','宋诗','song-poetry','','[]','繁花昨夜香苞裂，露裛風吹照野時。',32,'全唐诗/poet.song.4000.json','["繁花昨夜香苞裂，露裛風吹照野時。", "能與離人添悵望，一時留與子規啼。"]'),
('76cd749b-563b-4be6-9f61-7be94548d35d','春望書事','寇準','宋','宋诗','song-poetry','','[]','因晴每日向吟臺，縱目山城景象開。',64,'全唐诗/poet.song.4000.json','["因晴每日向吟臺，縱目山城景象開。", "白鳥靜投沙浦去，落花閑逐野泉來。", "客愁已被楊煙染，春色難甘蜀魄催。", "看即流芳無處問，但將餘興殢黄醅。"]'),
('8ddb123c-c66d-4b26-a4d0-a33a855816f5','秋日懷友生','寇準','宋','宋诗','song-poetry','','[]','寂寂感離羣，前期何足云。',48,'全唐诗/poet.song.4000.json','["寂寂感離羣，前期何足云。", "人從秦嶺別，蟬向楚江聞。", "村送孤煙起，山空白日曛。", "更逢疏葉落，愁緒轉紛紛。"]'),
('c6fdc45b-2208-403e-8ba7-d1f544d98c95','春初夜書','寇準','宋','宋诗','song-poetry','','[]','水國淹留歲月空，雲山東去阻千重。',64,'全唐诗/poet.song.4000.json','["水國淹留歲月空，雲山東去阻千重。", "欲令遥夜春愁薄，須頼黄醅臘酒濃。", "南浦有潮舂柵鎖，西窗無睡怯巖鐘。", "誰家幾點畬田火，疑是殘星掛遠峰。"]'),
('a40c6860-1ef0-43ad-bb94-aabdfd4fb754','江上','寇準','宋','宋诗','song-poetry','','[]','古岸蕭蕭聞去雁，平蕪杳杳更斜暉。',32,'全唐诗/poet.song.4000.json','["古岸蕭蕭聞去雁，平蕪杳杳更斜暉。", "空江極目望不盡，楓葉半紅人未歸。"]'),
('733276b3-4a7a-47e0-8597-2cb8b0b365d6','夜望','寇準','宋','宋诗','song-poetry','','[]','南亭閑坐欲忘機，望久前村島嶼微。',32,'全唐诗/poet.song.4000.json','["南亭閑坐欲忘機，望久前村島嶼微。", "數點寒燈起煙浪，江艇應見夜漁歸。"]'),
('3b3116d3-0f6b-4dd0-8e89-cbee2b9e3297','送人','寇準','宋','宋诗','song-poetry','','[]','客亭殘照裏，歌闋獨南行。',48,'全唐诗/poet.song.4000.json','["客亭殘照裏，歌闋獨南行。", "芳草無斷色，離人多別情。", "遠塗方不極，長笛更飛聲。", "莫動鄉關念，徒令白髮生。"]'),
('e4960545-40c6-4619-a4cc-5e9e234800c6','早春','寇準','宋','宋诗','song-poetry','','[]','溪水覺暖微函碧，山杏經春半吐紅。',32,'全唐诗/poet.song.4000.json','["溪水覺暖微函碧，山杏經春半吐紅。", "不向此時拚一醉，到頭無計奈春風。"]');
